BEGIN;
UPDATE public.qt_plans SET text = E'대하26:1  유다 온 백성이 나이가 십육 세 된 웃시야를 세워 그의 아버지 아마샤를 대신하여 왕으로 삼으니\n대하26:2 아마샤 왕이 그의 열조들의 묘실에 누운 후에 웃시야가 엘롯을 건축하여 유다에 돌렸더라\n대하26:3 웃시야가 왕위에 오를 때에 나이가 십육 세라 예루살렘에서 오십이 년 간 다스리니라 그의 어머니의 이름은 여골리아요 예루살렘 사람이더라\n대하26:4 웃시야가 그의 아버지 아마샤의 모든 행위대로 여호와 보시기에 정직하게 행하며\n대하26:5 하나님의 묵시를 밝히 아는 스가랴가 사는 날에 하나님을 찾았고 그가 여호와를 찾을 동안에는 하나님이 형통하게 하셨더라\n대하26:6 웃시야가 나가서 블레셋 사람들과 싸우고 가드 성벽과 야브네 성벽과 아스돗 성벽을 헐고 아스돗 땅과 블레셋 사람들 가운데에 성읍들을 건축하매\n대하26:7 하나님이 그를 도우사 블레셋 사람들과 구르바알에 거주하는 아라비아 사람들과 마온 사람들을 치게 하신지라\n대하26:8 암몬 사람들이 웃시야에게 조공을 바치매 웃시야가 매우 강성하여 이름이 애굽 변방까지 퍼졌더라\n대하26:9 웃시야가 예루살렘에서 성 모퉁이 문과 골짜기 문과 성굽이에 망대를 세워 견고하게 하고\n대하26:10 또 광야에 망대를 세우고 물 웅덩이를 많이 파고 고원과 평지에 가축을 많이 길렀으며 또 여러 산과 좋은 밭에 농부와 포도원을 다스리는 자들을 두었으니 농사를 좋아함이었더라\n대하26:11 웃시야에게 또 싸우는 군사가 있으니 서기관 여이엘과 병영장 마아세야가 직접 조사한 수효대로 왕의 지휘관 하나냐의 휘하에 속하여 떼를 지어 나가서 싸우는 자라\n대하26:12 족장의 총수가 이천육백 명이니 모두 큰 용사요\n대하26:13 그의 휘하의 군대가 삼십만 칠천오백 명이라 건장하고 싸움에 능하여 왕을 도와 적을 치는 자이며\n대하26:14 웃시야가 그의 온 군대를 위하여 방패와 창과 투구와 갑옷과 활과 물매 돌을 준비하고\n대하26:15 또 예루살렘에서 재주 있는 사람들에게 무기를 고안하게 하여 망대와 성곽 위에 두어 화살과 큰 돌을 쏘고 던지게 하였으니 그의 이름이 멀리 퍼짐은 기이한 도우심을 얻어 강성하여짐이었더라\n대하26:16  그가 강성하여지매 그의 마음이 교만하여 악을 행하여 그의 하나님 여호와께 범죄하되 곧 여호와의 성전에 들어가서 향단에 분향하려 한지라\n대하26:17 제사장 아사랴가 여호와의 용맹한 제사장 팔십 명을 데리고 그의 뒤를 따라 들어가서\n대하26:18 웃시야 왕 곁에 서서 그에게 이르되 웃시야여 여호와께 분향하는 일은 왕이 할 바가 아니요 오직 분향하기 위하여 구별함을 받은 아론의 자손 제사장들이 할 바니 성소에서 나가소서 왕이 범죄하였으니 하나님 여호와에게서 영광을 얻지 못하리이다\n대하26:19 웃시야가 손으로 향로를 잡고 분향하려 하다가 화를 내니 그가 제사장에게 화를 낼 때에 여호와의 전 안 향단 곁 제사장들 앞에서 그의 이마에 나병이 생긴지라\n대하26:20 대제사장 아사랴와 모든 제사장이 왕의 이마에 나병이 생겼음을 보고 성전에서 급히 쫓아내고 여호와께서 치시므로 왕도 속히 나가니라\n대하26:21 웃시야 왕이 죽는 날까지 나병환자가 되었고 나병환자가 되매 여호와의 전에서 끊어져 별궁에 살았으므로 그의 아들 요담이 왕궁을 관리하며 백성을 다스렸더라\n대하26:22 웃시야의 남은 시종 행적은 아모스의 아들 선지자 이사야가 기록하였더라\n대하26:23 웃시야가 그의 조상들과 함께 누우매 그는 나병환자라 하여 왕들의 묘실에 접한 땅 곧 그의 조상들의 곁에 장사하니라 그의 아들 요담이 대신하여 왕이 되니라' WHERE date = '2027-07-06';
UPDATE public.qt_plans SET text = E'대하27:1  요담이 왕위에 오를 때에 나이가 이십오 세라 예루살렘에서 십육 년 동안 다스리니라 그의 어머니의 이름은 여루사요 사독의 딸이더라\n대하27:2 요담이 그의 아버지 웃시야의 모든 행위대로 여호와 보시기에 정직하게 행하였으나 여호와의 성전에는 들어가지 아니하였고 백성은 여전히 부패하였더라\n대하27:3 그가 여호와의 전 윗문을 건축하고 또 오벨 성벽을 많이 증축하고\n대하27:4 유다 산중에 성읍들을 건축하며 수풀 가운데에 견고한 진영들과 망대를 건축하고\n대하27:5 암몬 자손의 왕과 더불어 싸워 그들을 이겼더니 그 해에 암몬 자손이 은 백 달란트와 밀 만 고르와 보리 만 고르를 바쳤고 제이년과 제삼년에도 암몬 자손이 그와 같이 바쳤더라\n대하27:6 요담이 그의 하나님 여호와 앞에서 바른 길을 걸었으므로 점점 강하여졌더라\n대하27:7 요담의 남은 사적과 그의 모든 전쟁과 행위는 이스라엘과 유다 열왕기에 기록되니라\n대하27:8 요담이 왕위에 오를 때에 나이가 이십오 세요 예루살렘에서 다스린 지 십육 년이라\n대하27:9 그가 그의 조상들과 함께 누우매 다윗 성에 장사되고 그의 아들 아하스가 대신하여 왕이 되니라' WHERE date = '2027-07-07';
UPDATE public.qt_plans SET text = E'대하28:1  아하스가 왕위에 오를 때에 나이가 이십 세라 예루살렘에서 십육 년 동안 다스렸으나 그의 조상 다윗과 같지 아니하여 여호와 보시기에 정직하게 행하지 아니하고\n대하28:2 이스라엘 왕들의 길로 행하여 바알들의 우상을 부어 만들고\n대하28:3 또 힌놈의 아들 골짜기에서 분향하고 여호와께서 이스라엘 자손 앞에서 쫓아내신 이방 사람들의 가증한 일을 본받아 그의 자녀들을 불사르고\n대하28:4 또 산당과 작은 산 위와 모든 푸른 나무 아래에서 제사를 드리며 분향하니라\n대하28:5 그러므로 그의 하나님 여호와께서 그를 아람 왕의 손에 넘기시매 그들이 쳐서 심히 많은 무리를 사로잡아 다메섹으로 갔으며 또 이스라엘 왕의 손에 넘기시매 그가 쳐서 크게 살륙하였으니\n대하28:6 이는 그의 조상들의 하나님 여호와를 버렸음이라 르말랴의 아들 베가가 유다에서 하루 동안에 용사 십이만 명을 죽였으며\n대하28:7 에브라임의 용사 시그리는 왕의 아들 마아세야와 궁내대신 아스리감과 총리대신 엘가나를 죽였더라\n대하28:8  이스라엘 자손이 그들의 형제 중에서 그들의 아내와 자녀를 합하여 이십만 명을 사로잡고 그들의 재물을 많이 노략하여 사마리아로 가져가니\n대하28:9 그 곳에 여호와의 선지자가 있는데 이름은 오뎃이라 그가 사마리아로 돌아오는 군대를 영접하고 그들에게 이르되 너희 조상의 하나님 여호와께서 유다에게 진노하셨으므로 너희 손에 넘기셨거늘 너희의 노기가 충천하여 살륙하고\n대하28:10 이제 너희가 또 유다와 예루살렘 백성들을 압제하여 노예로 삼고자 생각하는도다 그러나 너희는 너희의 하나님 여호와께 범죄함이 없느냐\n대하28:11 그런즉 너희는 내 말을 듣고 너희의 형제들 중에서 사로잡아 온 포로를 놓아 돌아가게 하라 여호와의 진노가 너희에게 임박하였느니라 한지라\n대하28:12 에브라임 자손의 우두머리 몇 사람 곧 요하난의 아들 아사랴와 무실레못의 아들 베레갸와 살룸의 아들 여히스기야와 하들래의 아들 아마사가 일어나서 전장에서 돌아오는 자들을 막으며\n대하28:13 그들에게 이르되 너희는 이 포로를 이리로 끌어들이지 못하리라 너희가 행하는 일이 우리를 여호와께 허물이 있게 함이니 우리의 죄와 허물을 더하게 함이로다 우리의 허물이 이미 커서 진노하심이 이스라엘에게 임박하였느니라 하매\n대하28:14 이에 무기를 가진 사람들이 포로와 노략한 물건을 방백들과 온 회중 앞에 둔지라\n대하28:15 이 위에 이름이 기록된 자들이 일어나서 포로를 맞고 노략하여 온 것 중에서 옷을 가져다가 벗은 자들에게 입히며 신을 신기며 먹이고 마시게 하며 기름을 바르고 그 약한 자들은 모두 나귀에 태워 데리고 종려나무 성 여리고에 이르러 그의 형제에게 돌려준 후에 사마리아로 돌아갔더라\n대하28:16  그 때에 아하스 왕이 앗수르 왕에게 사람을 보내어 도와 주기를 구하였으니\n대하28:17 이는 에돔 사람들이 다시 와서 유다를 치고 그의 백성을 사로잡았음이며\n대하28:18 블레셋 사람들도 유다의 평지와 남방 성읍들을 침노하여 벧세메스와 아얄론과 그데롯과 소고 및 그 주변 마을들과 딤나 및 그 주변 마을들과 김소 및 그 주변 마을들을 점령하고 거기에 살았으니\n대하28:19 이는 이스라엘 왕 아하스가 유다에서 망령되이 행하여 여호와께 크게 범죄하였으므로 여호와께서 유다를 낮추심이라\n대하28:20 앗수르 왕 디글랏빌레셀이 그에게 이르렀으나 돕지 아니하고 도리어 그를 공격하였더라\n대하28:21 아하스가 여호와의 전과 왕궁과 방백들의 집에서 재물을 가져다가 앗수르 왕에게 주었으나 그에게 유익이 없었더라\n대하28:22  이 아하스 왕이 곤고할 때에 더욱 여호와께 범죄하여\n대하28:23 자기를 친 다메섹 신들에게 제사하여 이르되 아람 왕들의 신들이 그들을 도왔으니 나도 그 신에게 제사하여 나를 돕게 하리라 하였으나 그 신이 아하스와 온 이스라엘을 망하게 하였더라\n대하28:24 아하스가 하나님의 전의 기구들을 모아 하나님의 전의 기구들을 부수고 또 여호와의 전 문들을 닫고 예루살렘 구석마다 제단을 쌓고\n대하28:25 유다 각 성읍에 산당을 세워 다른 신에게 분향하여 그의 조상들의 하나님 여호와를 진노하게 하였더라\n대하28:26 아하스의 남은 시종 사적과 모든 행위는 유다와 이스라엘 열왕기에 기록되니라\n대하28:27 아하스가 그의 조상들과 함께 누우매 이스라엘 왕들의 묘실에 들이지 아니하고 예루살렘 성에 장사하였더라 그의 아들 히스기야가 대신하여 왕이 되니라' WHERE date = '2027-07-08';
UPDATE public.qt_plans SET text = E'대하29:1  히스기야가 왕위에 오를 때에 나이가 이십오 세라 예루살렘에서 이십구 년 동안 다스리니라 그의 어머니의 이름은 아비야요 스가랴의 딸이더라\n대하29:2 히스기야가 그의 조상 다윗의 모든 행실과 같이 여호와 보시기에 정직하게 행하여\n대하29:3 첫째 해 첫째 달에 여호와의 전 문들을 열고 수리하고\n대하29:4 제사장들과 레위 사람들을 동쪽 광장에 모으고\n대하29:5 그들에게 이르되 레위 사람들아 내 말을 들으라 이제 너희는 성결하게 하고 또 너희 조상들의 하나님 여호와의 전을 성결하게 하여 그 더러운 것을 성소에서 없애라\n대하29:6 우리 조상들이 범죄하여 우리 하나님 여호와 보시기에 악을 행하여 하나님을 버리고 얼굴을 돌려 여호와의 성소를 등지고\n대하29:7 또 낭실 문을 닫으며 등불을 끄고 성소에서 분향하지 아니하며 이스라엘의 하나님께 번제를 드리지 아니하므로\n대하29:8 여호와께서 유다와 예루살렘에 진노하시고 내버리사 두려움과 놀람과 비웃음거리가 되게 하신 것을 너희가 똑똑히 보는 바라\n대하29:9 이로 말미암아 우리의 조상들이 칼에 엎드러지며 우리의 자녀와 아내들이 사로잡혔느니라\n대하29:10 이제 이스라엘의 하나님 여호와와 더불어 언약을 세워 그 맹렬한 노를 우리에게서 떠나게 할 마음이 내게 있노니\n대하29:11 내 아들들아 이제는 게으르지 말라 여호와께서 이미 너희를 택하사 그 앞에 서서 수종들어 그를 섬기며 분향하게 하셨느니라\n대하29:12 이에 레위 사람들이 일어나니 곧 그핫의 자손 중 아마새의 아들 마핫과 아사랴의 아들 요엘과 므라리의 자손 중 압디의 아들 기스와 여할렐렐의 아들 아사랴와 게르손 사람 중 심마의 아들 요아와 요아의 아들 에덴과\n대하29:13 엘리사반의 자손 중 시므리와 여우엘과 아삽의 자손 중 스가랴와 맛다냐와\n대하29:14 헤만의 자손 중 여후엘과 시므이와 여두둔의 자손 중 스마야와 웃시엘이라\n대하29:15 그들이 그들의 형제들을 모아 성결하게 하고 들어가서 왕이 여호와의 말씀대로 명령한 것을 따라 여호와의 전을 깨끗하게 할새\n대하29:16 제사장들도 여호와의 전 안에 들어가서 깨끗하게 하여 여호와의 전에 있는 모든 더러운 것을 끌어내어 여호와의 전 뜰에 이르매 레위 사람들이 받아 바깥 기드론 시내로 가져갔더라\n대하29:17 첫째 달 초하루에 성결하게 하기를 시작하여 그 달 초팔일에 여호와의 낭실에 이르고 또 팔 일 동안 여호와의 전을 성결하게 하여 첫째 달 십육 일에 이르러 마치고\n대하29:18 안으로 들어가서 히스기야 왕을 보고 이르되 우리가 여호와의 온 전과 번제단과 그 모든 그릇들과 떡을 진설하는 상과 그 모든 그릇들을 깨끗하게 하였고\n대하29:19 또 아하스 왕이 왕위에 있어 범죄할 때에 버린 모든 그릇들도 우리가 정돈하고 성결하게 하여 여호와의 제단 앞에 두었나이다 하니라\n대하29:20  히스기야 왕이 일찍이 일어나 성읍의 귀인들을 모아 여호와의 전에 올라가서\n대하29:21 수송아지 일곱 마리와 숫양 일곱 마리와 어린 양 일곱 마리와 숫염소 일곱 마리를 끌어다가 나라와 성소와 유다를 위하여 속죄제물로 삼고 아론의 자손 제사장들을 명령하여 여호와의 제단에 드리게 하니\n대하29:22 이에 수소를 잡으매 제사장들이 그 피를 받아 제단에 뿌리고 또 숫양들을 잡으매 그 피를 제단에 뿌리고 또 어린 양들을 잡으매 그 피를 제단에 뿌리고\n대하29:23 이에 속죄제물로 드릴 숫염소들을 왕과 회중 앞으로 끌어오매 그들이 그 위에 안수하고\n대하29:24 제사장들이 잡아 그 피를 속죄제로 삼아 제단에 드려 온 이스라엘을 위하여 속죄하니 이는 왕이 명령하여 온 이스라엘을 위하여 번제와 속죄제를 드리게 하였음이더라\n대하29:25 왕이 레위 사람들을 여호와의 전에 두어서 다윗과 왕의 선견자 갓과 선지자 나단이 명령한 대로 제금과 비파와 수금을 잡게 하니 이는 여호와께서 그의 선지자들로 이렇게 명령하셨음이라\n대하29:26 레위 사람은 다윗의 악기를 잡고 제사장은 나팔을 잡고 서매\n대하29:27 히스기야가 명령하여 번제를 제단에 드릴새 번제 드리기를 시작하는 동시에 여호와의 시로 노래하고 나팔을 불며 이스라엘 왕 다윗의 악기를 울리고\n대하29:28 온 회중이 경배하며 노래하는 자들은 노래하고 나팔 부는 자들은 나팔을 불어 번제를 마치기까지 이르니라\n대하29:29 제사 드리기를 마치매 왕과 그와 함께 있는 자들이 다 엎드려 경배하니라\n대하29:30 히스기야 왕이 귀인들과 더불어 레위 사람을 명령하여 다윗과 선견자 아삽의 시로 여호와를 찬송하게 하매 그들이 즐거움으로 찬송하고 몸을 굽혀 예배하니라\n대하29:31 이에 히스기야가 말하여 이르되 너희가 이제 스스로 몸을 깨끗하게 하여 여호와께 드렸으니 마땅히 나아와 제물과 감사제물을 여호와의 전으로 가져오라 하니 회중이 제물과 감사제물을 가져오되 무릇 마음에 원하는 자는 또한 번제물도 가져오니\n대하29:32 회중이 가져온 번제물의 수효는 수소가 칠십 마리요 숫양이 백 마리요 어린 양이 이백 마리이니 이는 다 여호와께 번제물로 드리는 것이며\n대하29:33 또 구별하여 드린 소가 육백 마리요 양이 삼천 마리라\n대하29:34 그런데 제사장이 부족하여 그 모든 번제 짐승들의 가죽을 능히 벗기지 못하는 고로 그의 형제 레위 사람들이 그 일을 마치기까지 돕고 다른 제사장들이 성결하게 하기까지 기다렸으니 이는 레위 사람들의 성결하게 함이 제사장들보다 성심이 있었음이라\n대하29:35 번제와 화목제의 기름과 각 번제에 속한 전제들이 많더라 이와 같이 여호와의 전에서 섬기는 일이 순서대로 갖추어지니라\n대하29:36 이 일이 갑자기 되었으나 하나님께서 백성을 위하여 예비하셨으므로 히스기야가 백성과 더불어 기뻐하였더라' WHERE date = '2027-07-09';
UPDATE public.qt_plans SET text = E'대하30:1  히스기야가 온 이스라엘과 유다에 사람을 보내고 또 에브라임과 므낫세에 편지를 보내어 예루살렘 여호와의 전에 와서 이스라엘 하나님 여호와를 위하여 유월절을 지키라 하니라\n대하30:2 왕이 방백들과 예루살렘 온 회중과 더불어 의논하고 둘째 달에 유월절을 지키려 하였으니\n대하30:3 이는 성결하게 한 제사장들이 부족하고 백성도 예루살렘에 모이지 못하였으므로 그 정한 때에 지킬수 없었음이라\n대하30:4 왕과 온 회중이 이 일을 좋게 여기고\n대하30:5 드디어 왕이 명령을 내려 브엘세바에서부터 단까지 온 이스라엘에 공포하여 일제히 예루살렘으로 와서 이스라엘 하나님 여호와의 유월절을 지키라 하니 이는 기록한 규례대로 오랫동안 지키지 못하였음이더라\n대하30:6 보발꾼들이 왕과 방백들의 편지를 받아 가지고 왕의 명령을 따라 온 이스라엘과 유다에 두루 다니며 전하니 일렀으되 이스라엘 자손들아 너희는 아브라함과 이삭과 이스라엘의 하나님 여호와께로 돌아오라 그리하면 그가 너희 남은 자 곧 앗수르 왕의 손에서 벗어난 자에게로 돌아오시리라\n대하30:7 너희 조상들과 너희 형제 같이 하지 말라 그들은 그의 조상들의 하나님 여호와께 범죄하였으므로 여호와께서 멸망하도록 버려 두신 것을 너희가 똑똑히 보는 바니라\n대하30:8 그런즉 너희 조상들 같이 목을 곧게 하지 말고 여호와께 돌아와 영원히 거룩하게 하신 전에 들어가서 너희 하나님 여호와를 섬겨 그의 진노가 너희에게서 떠나게 하라\n대하30:9 너희가 만일 여호와께 돌아오면 너희 형제들과 너희 자녀가 사로잡은 자들에게서 자비를 입어 다시 이 땅으로 돌아오리라 너희 하나님 여호와는 은혜로우시고 자비하신지라 너희가 그에게로 돌아오면 그의 얼굴을 너희에게서 돌이키지 아니하시리라 하였더라\n대하30:10 보발꾼이 에브라임과 므낫세 지방 각 성읍으로 두루 다녀서 스불론까지 이르렀으나 사람들이 그들을 조롱하며 비웃었더라\n대하30:11 그러나 아셀과 므낫세와 스불론 중에서 몇 사람이 스스로 겸손한 마음으로 예루살렘에 이르렀고\n대하30:12 하나님의 손이 또한 유다 사람들을 감동시키사 그들에게 왕과 방백들이 여호와의 말씀대로 전한 명령을 한 마음으로 준행하게 하셨더라\n대하30:13  둘째 달에 백성이 무교절을 지키려 하여 예루살렘에 많이 모이니 매우 큰 모임이라\n대하30:14 무리가 일어나 예루살렘에 있는 제단과 향단들을 모두 제거하여 기드론 시내에 던지고\n대하30:15 둘째 달 열넷째 날에 유월절 양을 잡으니 제사장과 레위 사람이 부끄러워하여 성결하게 하고 번제물을 가지고 여호와의 전에 이르러\n대하30:16 규례대로 각각 자기들의 처소에 서고 하나님의 사람 모세의 율법을 따라 제사장들이 레위 사람의 손에서 피를 받아 뿌리니라\n대하30:17 회중 가운데 많은 사람이 자신들을 성결하게 하지 못하였으므로 레위 사람들이 모든 부정한 사람을 위하여 유월절 양을 잡아 그들로 여호와 앞에서 성결하게 하였으나\n대하30:18 에브라임과 므낫세와 잇사갈과 스불론의 많은 무리는 자기들을 깨끗하게 하지 아니하고 유월절 양을 먹어 기록한 규례를 어긴지라 히스기야가 그들을 위하여 기도하여 이르되 선하신 여호와여 사하옵소서\n대하30:19 결심하고 하나님 곧 그의 조상들의 하나님 여호와를 구하는 사람은 누구든지 비록 성소의 결례대로 스스로 깨끗하게 못하였을지라도 사하옵소서 하였더니\n대하30:20 여호와께서 히스기야의 기도를 들으시고 백성을 고치셨더라\n대하30:21 예루살렘에 모인 이스라엘 자손이 크게 즐거워하며 칠 일 동안 무교절을 지켰고 레위 사람들과 제사장들은 날마다 여호와를 칭송하며 큰 소리 나는 악기를 울려 여호와를 찬양하였으며\n대하30:22 히스기야는 여호와를 섬기는 일에 능숙한 모든 레위 사람들을 위로하였더라 이와 같이 절기 칠 일 동안에 무리가 먹으며 화목제를 드리고 그의 조상들의 하나님 여호와께 감사하였더라\n대하30:23  온 회중이 다시 칠 일을 지키기로 결의하고 이에 또 칠 일을 즐겁게 지켰더라\n대하30:24 유다 왕 히스기야가 수송아지 천 마리와 양 칠천 마리를 회중에게 주었고 방백들은 수송아지 천 마리와 양 만 마리를 회중에게 주었으며 자신들을 성결하게 한 제사장들도 많았더라\n대하30:25 유다 온 회중과 제사장들과 레위 사람들과 이스라엘에서 온 모든 회중과 이스라엘 땅에서 나온 나그네들과 유다에 사는 나그네들이 다 즐거워하였으므로\n대하30:26 예루살렘에 큰 기쁨이 있었으니 이스라엘 왕 다윗의 아들 솔로몬 때로부터 이러한 기쁨이 예루살렘에 없었더라\n대하30:27 그 때에 제사장들과 레위 사람들이 일어나서 백성을 위하여 축복하였으니 그 소리가 하늘에 들리고 그 기도가 여호와의 거룩한 처소 하늘에 이르렀더라' WHERE date = '2027-07-10';
UPDATE public.qt_plans SET text = E'대하31:1  이 모든 일이 끝나매 거기에 있는 이스라엘 무리가 나가서 유다 여러 성읍에 이르러 주상들을 깨뜨리며 아세라 목상들을 찍으며 유다와 베냐민과 에브라임과 므낫세 온 땅에서 산당들과 제단들을 제거하여 없애고 이스라엘 모든 자손이 각각 자기들의 본성 기업으로 돌아갔더라\n대하31:2 히스기야가 제사장들과 레위 사람들의 반열을 정하고 그들의 반열에 따라 각각 그들의 직임을 행하게 하되 곧 제사장들과 레위 사람들에게 번제와 화목제를 드리며 여호와의 휘장 문에서 섬기며 감사하며 찬송하게 하고\n대하31:3 또 왕의 재산 중에서 얼마를 정하여 여호와의 율법에 기록된 대로 번제 곧 아침과 저녁의 번제와 안식일과 초하루와 절기의 번제에 쓰게 하고\n대하31:4 또 예루살렘에 사는 백성을 명령하여 제사장들과 레위 사람들 몫의 음식을 주어 그들에게 여호와의 율법을 힘쓰게 하라 하니라\n대하31:5 왕의 명령이 내리자 곧 이스라엘 자손이 곡식과 포도주와 기름과 꿀과 밭의 모든 소산의 첫 열매들을 풍성히 드렸고 또 모든 것의 십일조를 많이 가져왔으며\n대하31:6 유다 여러 성읍에 사는 이스라엘과 유다 자손들도 소와 양의 십일조를 가져왔고 또 그들의 하나님 여호와께 구별하여 드릴 성물의 십일조를 가져왔으며 그것을 쌓아 여러 더미를 이루었는데\n대하31:7 셋째 달에 그 더미들을 쌓기 시작하여 일곱째 달에 마친지라\n대하31:8 히스기야와 방백들이 와서 쌓인 더미들을 보고 여호와를 송축하고 그의 백성 이스라엘을 위하여 축복하니라\n대하31:9 히스기야가 그 더미들에 대하여 제사장들과 레위 사람들에게 물으니\n대하31:10 사독의 족속 대제사장 아사랴가 그에게 대답하여 이르되 백성이 예물을 여호와의 전에 드리기 시작함으로부터 우리가 만족하게 먹었으나 남은 것이 많으니 이는 여호와께서 그의 백성에게 복을 주셨음이라 그 남은 것이 이렇게 많이 쌓였나이다\n대하31:11 그 때에 히스기야가 명령하여 여호와의 전 안에 방들을 준비하라 하므로 그렇게 준비하고\n대하31:12 성심으로 그 예물과 십일조와 구별한 물건들을 갖다 두고 레위 사람 고나냐가 그 일의 책임자가 되고 그의 아우 시므이는 부책임자가 되며\n대하31:13 여히엘과 아사시야와 나핫과 아사헬과 여리못과 요사밧과 엘리엘과 이스마갸와 마핫과 브나야는 고나냐와 그의 아우 시므이의 수하에서 보살피는 자가 되니 이는 히스기야 왕과 하나님의 전을 관리하는 아사랴가 명령한 바이며\n대하31:14 동문지기 레위 사람 임나의 아들 고레는 즐거이 하나님께 드리는 예물을 맡아 여호와께 드리는 것과 모든 지성물을 나눠 주며\n대하31:15 그의 수하의 에덴과 미냐민과 예수아와 스마야와 아마랴와 스가냐는 제사장들의 성읍들에 있어서 직임을 맡아 그의 형제들에게 반열대로 대소를 막론하고 나눠 주되\n대하31:16 삼 세 이상으로 족보에 기록된 남자 외에 날마다 여호와의 전에 들어가서 그 반열대로 직무에 수종드는 자들에게 다 나눠 주며\n대하31:17 또 그들의 족속대로 족보에 기록된 제사장들에게 나눠 주며 이십세 이상에서 그 반열대로 직무를 맡은 레위 사람들에게 나눠 주며\n대하31:18 또 그 족보에 기록된 온 회중의 어린 아이들 아내들 자녀들에게 나눠 주었으니 이 회중은 성결하고 충실히 그 직분을 다하는 자며\n대하31:19 각 성읍에서 등록된 사람이 있어 성읍 가까운 들에 사는 아론 자손 제사장들에게도 나눠 주되 제사장들의 모든 남자와 족보에 기록된 레위 사람들에게 나눠 주었더라\n대하31:20 히스기야가 온 유다에 이같이 행하되 그의 하나님 여호와 보시기에 선과 정의와 진실함으로 행하였으니\n대하31:21 그가 행하는 모든 일 곧 하나님의 전에 수종드는 일에나 율법에나 계명에나 그의 하나님을 찾고 한 마음으로 행하여 형통하였더라' WHERE date = '2027-07-12';
UPDATE public.qt_plans SET text = E'겔1:2 여호야긴 왕이 사로잡힌 지 오 년 그 달 초닷새라\n겔1:3 갈대아 땅 그발 강 가에서 여호와의 말씀이 부시의 아들 제사장 나 에스겔에게 특별히 임하고 여호와의 권능이 내 위에 있으니라\n겔1:4 내가 보니 북쪽에서부터 폭풍과 큰 구름이 오는데 그 속에서 불이 번쩍번쩍하여 빛이 그 사방에 비치며 그 불 가운데 단 쇠 같은 것이 나타나 보이고\n겔1:5 그 속에서 네 생물의 형상이 나타나는데 그들의 모양이 이러하니 그들에게 사람의 형상이 있더라\n겔1:6 그들에게 각각 네 얼굴과 네 날개가 있고\n겔1:7 그들의 다리는 곧은 다리요 그들의 발바닥은 송아지 발바닥 같고 광낸 구리 같이 빛나며\n겔1:8 그 사방 날개 밑에는 각각 사람의 손이 있더라 그 네 생물의 얼굴과 날개가 이러하니\n겔1:9 날개는 다 서로 연하였으며 갈 때에는 돌이키지 아니하고 일제히 앞으로 곧게 행하며\n겔1:10 그 얼굴들의 모양은 넷의 앞은 사람의 얼굴이요 넷의 오른쪽은 사자의 얼굴이요 넷의 왼쪽은 소의 얼굴이요 넷의 뒤는 독수리의 얼굴이니\n겔1:11 그 얼굴은 그러하며 그 날개는 들어 펴서 각기 둘씩 서로 연하였고 또 둘은 몸을 가렸으며\n겔1:12 영이 어떤 쪽으로 가면 그 생물들도 그대로 가되 돌이키지 아니하고 일제히 앞으로 곧게 행하며\n겔1:13 또 생물들의 모양은 타는 숯불과 횃불 모양 같은데 그 불이 그 생물 사이에서 오르락내리락 하며 그 불은 광채가 있고 그 가운데에서는 번개가 나며\n겔1:14 그 생물들은 번개 모양 같이 왕래하더라\n겔1:15 내가 그 생물들을 보니 그 생물들 곁에 있는 땅 위에는 바퀴가 있는데 그 네 얼굴을 따라 하나씩 있고\n겔1:16 그 바퀴의 모양과 그 구조는 황옥 같이 보이는데 그 넷은 똑같은 모양을 가지고 있으며 그들의 모양과 구조는 바퀴 안에 바퀴가 있는 것 같으며\n겔1:17 그들이 갈 때에는 사방으로 향한 대로 돌이키지 아니하고 가며\n겔1:18 그 둘레는 높고 무서우며 그 네 둘레로 돌아가면서 눈이 가득하며\n겔1:19 그 생물들이 갈 때에 바퀴들도 그 곁에서 가고 그 생물들이 땅에서 들릴 때에 바퀴들도 들려서\n겔1:20 영이 어떤 쪽으로 가면 생물들도 영이 가려 하는 곳으로 가고 바퀴들도 그 곁에서 들리니 이는 생물의 영이 그 바퀴들 가운데에 있음이니라\n겔1:21 그들이 가면 이들도 가고 그들이 서면 이들도 서고 그들이 땅에서 들릴 때에는 이들도 그 곁에서 들리니 이는 생물의 영이 그 바퀴들 가운데에 있음이더라\n겔1:22 그 생물의 머리 위에는 수정 같은 궁창의 형상이 있어 보기에 두려운데 그들의 머리 위에 펼쳐져 있고\n겔1:23 그 궁창 밑에 생물들의 날개가 서로 향하여 펴 있는데 이 생물은 두 날개로 몸을 가렸고 저 생물도 두 날개로 몸을 가렸더라\n겔1:24 생물들이 갈 때에 내가 그 날개 소리를 들으니 많은 물 소리와도 같으며 전능자의 음성과도 같으며 떠드는 소리 곧 군대의 소리와도 같더니 그 생물이 설 때에 그 날개를 내렸더라\n겔1:25 그 머리 위에 있는 궁창 위에서부터 음성이 나더라 그 생물이 설 때에 그 날개를 내렸더라\n겔1:26 그 머리 위에 있는 궁창 위에 보좌의 형상이 있는데 그 모양이 남보석 같고 그 보좌의 형상 위에 한 형상이 있어 사람의 모양 같더라\n겔1:27 내가 보니 그 허리 위의 모양은 단 쇠 같아서 그 속과 주위가 불 같고 내가 보니 그 허리 아래의 모양도 불 같아서 사방으로 광채가 나며\n겔1:28 그 사방 광채의 모양은 비 오는 날 구름에 있는 무지개 같으니 이는 여호와의 영광의 형상의 모양이라 내가 보고 엎드려 말씀하시는 이의 음성을 들으니라' WHERE date = '2027-07-13';
UPDATE public.qt_plans SET text = E'겔2:1  그가 내게 이르시되 인자야 네 발로 일어서라 내가 네게 말하리라 하시며\n겔2:2 그가 내게 말씀하실 때에 그 영이 내게 임하사 나를 일으켜 내 발로 세우시기로 내가 그 말씀하시는 자의 소리를 들으니\n겔2:3 내게 이르시되 인자야 내가 너를 이스라엘 자손 곧 패역한 백성, 나를 배반하는 자에게 보내노라 그들과 그 조상들이 내게 범죄하여 오늘까지 이르렀나니\n겔2:4 이 자손은 얼굴이 뻔뻔하고 마음이 굳은 자니라 내가 너를 그들에게 보내노니 너는 그들에게 이르기를 주 여호와의 말씀이 이러하시다 하라\n겔2:5 그들은 패역한 족속이라 그들이 듣든지 아니 듣든지 그들 가운데에 선지자가 있음을 알지니라\n겔2:6 인자야 너는 비록 가시와 찔레와 함께 있으며 전갈 가운데에 거주할지라도 그들을 두려워하지 말고 그들의 말을 두려워하지 말지어다 그들은 패역한 족속이라도 그 말을 두려워하지 말며 그 얼굴을 무서워하지 말지어다\n겔2:7 그들은 심히 패역한 자라 그들이 듣든지 아니 듣든지 너는 내 말로 고할지어다\n겔2:8 너 인자야 내가 네게 이르는 말을 듣고 그 패역한 족속 같이 패역하지 말고 네 입을 벌리고 내가 네게 주는 것을 먹으라 하시기로\n겔2:9 내가 보니 보라 한 손이 나를 향하여 펴지고 보라 그 안에 두루마리 책이 있더라\n겔2:10 그가 그것을 내 앞에 펴시니 그 안팎에 글이 있는데 그 위에 애가와 애곡과 재앙의 말이 기록되었더라' WHERE date = '2027-07-14';
UPDATE public.qt_plans SET text = E'겔3:1 또 그가 내게 이르시되 인자야 너는 발견한 것을 먹으라 너는 이 두루마리를 먹고 가서 이스라엘 족속에게 말하라 하시기로\n겔3:2 내가 입을 벌리니 그가 그 두루마리를 내게 먹이시며\n겔3:3 내게 이르시되 인자야 내가 네게 주는 이 두루마리를 네 배에 넣으며 네 창자에 채우라 하시기에 내가 먹으니 그것이 내 입에서 달기가 꿀 같더라\n겔3:4 그가 또 내게 이르시되 인자야 이스라엘 족속에게 가서 내 말로 그들에게 고하라\n겔3:5 너를 언어가 다르거나 말이 어려운 백성에게 보내는 것이 아니요 이스라엘 족속에게 보내는 것이라\n겔3:6 너를 언어가 다르거나 말이 어려워 네가 그들의 말을 알아 듣지 못할 나라들에게 보내는 것이 아니니라 내가 너를 그들에게 보냈다면 그들은 정녕 네 말을 들었으리라\n겔3:7 그러나 이스라엘 족속은 이마가 굳고 마음이 굳어 네 말을 듣고자 아니하리니 이는 내 말을 듣고자 아니함이니라\n겔3:8 보라 내가 그들의 얼굴을 마주보도록 네 얼굴을 굳게 하였고 그들의 이마를 마주보도록 네 이마를 굳게 하였으되\n겔3:9 네 이마를 화석보다 굳은 금강석 같이 하였으니 그들이 비록 반역하는 족속이라도 두려워하지 말며 그들의 얼굴을 무서워하지 말라 하시니라\n겔3:10 또 내게 이르시되 인자야 내가 네게 이를 모든 말을 너는 마음으로 받으며 귀로 듣고\n겔3:11 사로잡힌 네 민족에게로 가서 그들이 듣든지 아니 듣든지 그들에게 고하여 이르기를 주 여호와의 말씀이 이러하시다 하라\n겔3:12 때에 주의 영이 나를 들어올리시는데 내가 내 뒤에서 크게 울리는 소리를 들으니 찬송할지어다 여호와의 영광이 그의 처소로부터 나오는도다 하니\n겔3:13 이는 생물들의 날개가 서로 부딪치는 소리와 생물 곁의 바퀴 소리라 크게 울리는 소리더라\n겔3:14 주의 영이 나를 들어올려 데리고 가시는데 내가 근심하고 분한 마음으로 가니 여호와의 권능이 힘 있게 나를 감동시키시더라\n겔3:15 이에 내가 델아빕에 이르러 그 사로잡힌 백성 곧 그발 강 가에 거주하는 자들에게 나아가 그 중에서 두려워 떨며 칠 일을 지내니라\n겔3:16  칠 일 후에 여호와의 말씀이 내게 임하여 이르시되\n겔3:17 인자야 내가 너를 이스라엘 족속의 파수꾼으로 세웠으니 너는 내 입의 말을 듣고 나를 대신하여 그들을 깨우치라\n겔3:18 가령 내가 악인에게 말하기를 너는 꼭 죽으리라 할 때에 네가 깨우치지 아니하거나 말로 악인에게 일러서 그의 악한 길을 떠나 생명을 구원하게 하지 아니하면 그 악인은 그의 죄악 중에서 죽으려니와 내가 그의 피 값을 네 손에서 찾을 것이고\n겔3:19 네가 악인을 깨우치되 그가 그의 악한 마음과 악한 행위에서 돌이키지 아니하면 그는 그의 죄악 중에서 죽으려니와 너는 네 생명을 보존하리라\n겔3:20 또 의인이 그의 공의에서 돌이켜 악을 행할 때에는 이미 행한 그의 공의는 기억할 바 아니라 내가 그 앞에 거치는 것을 두면 그가 죽을지니 이는 네가 그를 깨우치지 않음이니라 그는 그의 죄 중에서 죽으려니와 그의 피 값은 내가 네 손에서 찾으리라\n겔3:21 그러나 네가 그 의인을 깨우쳐 범죄하지 아니하게 함으로 그가 범죄하지 아니하면 정녕 살리니 이는 깨우침을 받음이며 너도 네 영혼을 보존하리라\n겔3:22  여호와께서 권능으로 거기서 내게 임하시고 또 내게 이르시되 일어나 들로 나아가라 내가 거기서 너와 말하리라 하시기로\n겔3:23 내가 일어나 들로 나아가니 여호와의 영광이 거기에 머물렀는데 내가 전에 그발 강 가에서 보던 영광과 같은지라 내가 곧 엎드리니\n겔3:24 주의 영이 내게 임하사 나를 일으켜 내 발로 세우시고 내게 말씀하여 이르시되 너는 가서 네 집에 들어가 문을 닫으라\n겔3:25 너 인자야 보라 무리가 네 위에 줄을 놓아 너를 동여매리니 네가 그들 가운데에서 나오지 못할 것이라\n겔3:26 내가 네 혀를 네 입천장에 붙게 하여 네가 말 못하는 자가 되어 그들을 꾸짖는 자가 되지 못하게 하리니 그들은 패역한 족속임이니라\n겔3:27 그러나 내가 너와 말할 때에 네 입을 열리니 너는 그들에게 이르기를 주 여호와의 말씀이 이러하시다 하라 들을 자는 들을 것이요 듣기 싫은 자는 듣지 아니하리니 그들은 반역하는 족속임이니라' WHERE date = '2027-07-15';
UPDATE public.qt_plans SET text = E'겔4:1  너 인자야 토판을 가져다가 그것을 네 앞에 놓고 한 성읍 곧 예루살렘을 그 위에 그리고\n겔4:2 그 성읍을 에워싸되 그것을 향하여 사다리를 세우고 그것을 향하여 흙으로 언덕을 쌓고 그것을 향하여 진을 치고 그것을 향하여 공성퇴를 둘러 세우고\n겔4:3 또 철판을 가져다가 너와 성읍 사이에 두어 철벽을 삼고 성을 포위하는 것처럼 에워싸라 이것이 이스라엘 족속에게 징조가 되리라\n겔4:4 너는 또 왼쪽으로 누워 이스라엘 족속의 죄악을 짊어지되 네가 눕는 날수대로 그 죄악을 담당할지니라\n겔4:5 내가 그들의 범죄한 햇수대로 네게 날수를 정하였나니 곧 삼백구십 일이니라 너는 이렇게 이스라엘 족속의 죄악을 담당하고\n겔4:6 그 수가 차거든 너는 오른쪽으로 누워 유다 족속의 죄악을 담당하라 내가 네게 사십 일로 정하였나니 하루가 일 년이니라\n겔4:7 너는 또 네 얼굴을 에워싸인 예루살렘 쪽으로 향하고 팔을 걷어 올리고 예언하라\n겔4:8 내가 줄로 너를 동이리니 네가 에워싸는 날이 끝나기까지 몸을 이리 저리 돌리지 못하리라\n겔4:9 너는 밀과 보리와 콩과 팥과 조와 귀리를 가져다가 한 그릇에 담고 너를 위하여 떡을 만들어 네가 옆으로 눕는 날수 곧 삼백구십 일 동안 먹되\n겔4:10 너는 음식물을 달아서 하루 이십 세겔씩 때를 따라 먹고\n겔4:11 물도 육분의 일 힌씩 되어서 때를 따라 마시라\n겔4:12 너는 그것을 보리떡처럼 만들어 먹되 그들의 목전에서 인분 불을 피워 구울지니라\n겔4:13 또 여호와께서 이르시되 내가 여러 나라들로 쫓아내어 흩어 버릴 이스라엘 자손이 거기서 이같이 부정한 떡을 먹으리라 하시기로\n겔4:14 내가 말하되 아하 주 여호와여 나는 영혼을 더럽힌 일이 없었나이다 어려서부터 지금까지 스스로 죽은 것이나 짐승에게 찢긴 것을 먹지 아니하였고 가증한 고기를 입에 넣지 아니하였나이다\n겔4:15 여호와께서 내게 이르시되 보라 쇠똥으로 인분을 대신하기를 허락하노니 너는 그것으로 떡을 구울지니라\n겔4:16 또 내게 이르시되 인자야 내가 예루살렘에서 의뢰하는 양식을 끊으리니 백성이 근심 중에 떡을 달아 먹고 두려워 떨며 물을 되어 마시다가\n겔4:17 떡과 물이 부족하여 피차에 두려워 하여 떨며 그 죄악 중에서 쇠패하리라' WHERE date = '2027-07-16';
UPDATE public.qt_plans SET text = E'겔5:1  너 인자야 너는 날카로운 칼을 가져다가 삭도로 삼아 네 머리털과 수염을 깎아서 저울로 달아 나누어 두라\n겔5:2 그 성읍을 에워싸는 날이 차거든 너는 터럭 삼분의 일은 성읍 안에서 불사르고 삼분의 일은 성읍 사방에서 칼로 치고 또 삼분의 일은 바람에 흩으라 내가 그 뒤를 따라 칼을 빼리라\n겔5:3 너는 터럭 중에서 조금을 네 옷자락에 싸고\n겔5:4 또 그 가운데에서 얼마를 불에 던져 사르라 그 속에서 불이 이스라엘 온 족속에게로 나오리라\n겔5:5 주 여호와께서 이와 같이 이르시되 이것이 곧 예루살렘이라 내가 그를 이방인 가운데에 두어 나라들이 둘러 있게 하였거늘\n겔5:6 그가 내 규례를 거슬러서 이방인보다 악을 더 행하며 내 율례도 그리함이 그를 둘러 있는 나라들보다 더하니 이는 그들이 내 규례를 버리고 내 율례를 행하지 아니하였음이니라\n겔5:7 그러므로 나 주 여호와가 말하노라 너희 요란함이 너희를 둘러싸고 있는 이방인들보다 더하여 내 율례를 행하지 아니하며 내 규례를 지키지 아니하고 너희를 둘러 있는 이방인들의 규례대로도 행하지 아니하였느니라\n겔5:8 그러므로 나 주 여호와가 말하노라 나 곧 내가 너를 치며 이방인의 목전에서 너에게 벌을 내리되\n겔5:9 네 모든 가증한 일로 말미암아 내가 전무후무하게 네게 내릴지라\n겔5:10 그리한즉 네 가운데에서 아버지가 아들을 잡아먹고 아들이 그 아버지를 잡아먹으리라 내가 벌을 네게 내리고 너희 중에 남은 자를 다 사방에 흩으리라\n겔5:11 그러므로 나 주 여호와가 말하노라 내가 나의 삶을 두고 맹세하노니 네가 모든 미운 물건과 모든 가증한 일로 내 성소를 더럽혔은즉 나도 너를 아끼지 아니하며 긍휼을 베풀지 아니하고 미약하게 하리니\n겔5:12 너희 가운데에서 삼분의 일은 전염병으로 죽으며 기근으로 멸망할 것이요 삼분의 일은 너의 사방에서 칼에 엎드러질 것이며 삼분의 일은 내가 사방에 흩어 버리고 또 그 뒤를 따라 가며 칼을 빼리라\n겔5:13 이와 같이 내 노가 다한즉 그들을 향한 분이 풀려서 내 마음이 가라앉으리라 내 분이 그들에게 다한즉 나 여호와가 열심으로 말한 줄을 그들이 알리라\n겔5:14 내가 이르되 또 너를 황무하게 하고 너를 둘러싸고 있는 이방인들 중에서 모든 지나가는 자의 목전에 모욕 거리가 되게 하리니\n겔5:15 내 노와 분과 중한 책망으로 네게 벌을 내린즉 너를 둘러싸고 있는 이방인들에게 네가 수치와 조롱 거리가 되고 두려움과 경고가 되리라 나 여호와의 말이니라\n겔5:16 내가 멸망하게 하는 기근의 독한 화살을 너희에게 보내되 기근을 더하여 너희가 의뢰하는 양식을 끊을 것이라\n겔5:17 내가 기근과 사나운 짐승을 너희에게 보내 외롭게 하고 너희 가운데에 전염병과 살륙이 일어나게 하고 또 칼이 너희에게 임하게 하리라 나 여호와의 말이니라' WHERE date = '2027-07-17';
UPDATE public.qt_plans SET text = E'겔6:1  여호와의 말씀이 내게 임하여 이르시되\n겔6:2 인자야 너는 이스라엘 산을 향하여 그들에게 예언하여\n겔6:3 이르기를 이스라엘 산들아 주 여호와의 말씀을 들으라 주 여호와께서 산과 언덕과 시내와 골짜기를 향하여 이같이 말씀하시기를 나 곧 내가 칼이 너희에게 임하게 하여 너희 산당을 멸하리니\n겔6:4 너희 제단들이 황폐하고 분향제단들이 깨뜨려질 것이며 너희가 죽임을 당하여 너희 우상 앞에 엎드러지게 할 것이라\n겔6:5 이스라엘 자손의 시체를 그 우상 앞에 두며 너희 해골을 너희 제단 사방에 흩으리라\n겔6:6 내가 너희가 거주하는 모든 성읍이 사막이 되게 하며 산당을 황폐하게 하리니 이는 너희 제단이 깨어지고 황폐하며 너희 우상들이 깨어져 없어지며 너희 분향제단들이 찍히며 너희가 만든 것이 폐하여지며\n겔6:7 또 너희가 죽임을 당하여 엎드러지게 하여 내가 여호와인 줄을 너희가 알게 하려 함이라\n겔6:8 그러나 너희가 여러 나라에 흩어질 때에 내가 너희 중에서 칼을 피하여 이방인들 중에 살아 남은 자가 있게 할지라\n겔6:9 너희 중에서 살아 남은 자가 사로잡혀 이방인들 중에 있어서 나를 기억하되 그들이 음란한 마음으로 나를 떠나고 음란한 눈으로 우상을 섬겨 나를 근심하게 한 것을 기억하고 스스로 한탄하리니 이는 그 모든 가증한 일로 악을 행하였음이라\n겔6:10 그 때에야 그들이 나를 여호와인 줄 알리라 내가 이런 재앙을 그들에게 내리겠다 한 말이 헛되지 아니하니라\n겔6:11 주 여호와께서 이같이 이르시되 너는 손뼉을 치고 발을 구르며 말할지어다 오호라 이스라엘 족속이 모든 가증한 악을 행하므로 마침내 칼과 기근과 전염병에 망하되\n겔6:12 먼 데 있는 자는 전염병에 죽고 가까운 데 있는 자는 칼에 엎드러지고 남아 있어 에워싸인 자는 기근에 죽으리라 이같이 내 진노를 그들에게 이룬즉\n겔6:13 그 죽임 당한 시체들이 그 우상들 사이에, 제단 사방에, 각 높은 고개 위에, 모든 산 꼭대기에, 모든 푸른 나무 아래에, 무성한 상수리나무 아래 곧 그 우상에게 분향하던 곳에 있으리니 내가 여호와인 줄을 너희가 알리라\n겔6:14 내가 내 손을 그들의 위에 펴서 그가 사는 온 땅 곧 광야에서부터 디블라까지 황량하고 황폐하게 하리니 내가 여호와인 줄을 그들이 알리라' WHERE date = '2027-07-19';
UPDATE public.qt_plans SET text = E'겔7:1  또 여호와의 말씀이 내게 임하여 이르시되\n겔7:2 너 인자야 주 여호와께서 이스라엘 땅에 관하여 이같이 말씀하셨느니라 끝났도다 이 땅 사방의 일이 끝났도다\n겔7:3 이제는 네게 끝이 이르렀나니 내가 내 진노를 네게 나타내어 네 행위를 심판하고 네 모든 가증한 일을 보응하리라\n겔7:4 내가 너를 불쌍히 여기지 아니하며 긍휼히 여기지도 아니하고 네 행위대로 너를 벌하여 네 가증한 일이 너희 중에 나타나게 하리니 내가 여호와인 줄을 너희가 알리라\n겔7:5 주 여호와께서 이같이 이르시되 재앙이로다, 비상한 재앙이로다 볼지어다 그것이 왔도다\n겔7:6 끝이 왔도다, 끝이 왔도다 끝이 너에게 왔도다 볼지어다 그것이 왔도다\n겔7:7 이 땅 주민아 정한 재앙이 네게 임하도다 때가 이르렀고 날이 가까웠으니 요란한 날이요 산에서 즐거이 부르는 날이 아니로다\n겔7:8 이제 내가 속히 분을 네게 쏟고 내 진노를 네게 이루어서 네 행위대로 너를 심판하여 네 모든 가증한 일을 네게 보응하되\n겔7:9 내가 너를 불쌍히 여기지 아니하며 긍휼히 여기지도 아니하고 네 행위대로 너를 벌하여 너의 가증한 일이 너희 중에 나타나게 하리니 나 여호와가 때리는 이임을 네가 알리라\n겔7:10 볼지어다 그 날이로다 볼지어다 임박하도다 정한 재앙이 이르렀으니 몽둥이가 꽃이 피며 교만이 싹이 났도다\n겔7:11 포학이 일어나서 죄악의 몽둥이가 되었은즉 그들도, 그 무리도, 그 재물도 하나도 남지 아니하며 그 중의 아름다운 것도 없어지리로다\n겔7:12 때가 이르렀고 날이 가까웠으니 사는 자도 기뻐하지 말고 파는 자도 근심하지 말 것은 진노가 그 모든 무리에게 임함이로다\n겔7:13 파는 자가 살아 있다 할지라도 다시 돌아가서 그 판 것을 얻지 못하리니 이는 묵시가 그 모든 무리에게 돌아오지 아니하고, 사람이 그 죄악으로 말미암아 자기의 목숨을 유지할 수 없으리라 하였음이로다\n겔7:14  그들이 나팔을 불어 온갖 것을 준비하였을지라도 전쟁에 나갈 사람이 없나니 이는 내 진노가 그 모든 무리에게 이르렀음이라\n겔7:15 밖에는 칼이 있고 안에는 전염병과 기근이 있어서 밭에 있는 자는 칼에 죽을 것이요 성읍에 있는 자는 기근과 전염병에 망할 것이며\n겔7:16 도망하는 자는 산 위로 피하여 다 각기 자기 죄악 때문에 골짜기의 비둘기들처럼 슬피 울 것이며\n겔7:17 모든 손은 피곤하고 모든 무릎은 물과 같이 약할 것이라\n겔7:18 그들이 굵은 베로 허리를 묶을 것이요 두려움이 그들을 덮을 것이요 모든 얼굴에는 수치가 있고 모든 머리는 대머리가 될 것이며\n겔7:19 그들이 그 은을 거리에 던지며 그 금을 오물 같이 여기리니 이는 여호와 내가 진노를 내리는 날에 그들의 은과 금이 능히 그들을 건지지 못하며 능히 그 심령을 족하게 하거나 그 창자를 채우지 못하고 오직 죄악의 걸림돌이 됨이로다\n겔7:20 그들이 그 화려한 장식으로 말미암아 교만을 품었고 또 그것으로 가증한 우상과 미운 물건을 만들었은즉 내가 그것을 그들에게 오물이 되게 하여\n겔7:21 타국인의 손에 넘겨 노략하게 하며 세상 악인에게 넘겨 그들이 약탈하여 더럽히게 하고\n겔7:22 내가 또 내 얼굴을 그들에게서 돌이키리니 그들이 내 은밀한 처소를 더럽히고 포악한 자도 거기 들어와서 더럽히리라\n겔7:23 너는 쇠사슬을 만들라 이는 피 흘리는 죄가 그 땅에 가득하고 포악이 그 성읍에 찼음이라\n겔7:24 내가 극히 악한 이방인들을 데려와서 그들이 그 집들을 점령하게 하고 강한 자의 교만을 그치게 하리니 그들의 성소가 더럽힘을 당하리라\n겔7:25 패망이 이르리니 그들이 평강을 구하여도 없을 것이라\n겔7:26 환난에 환난이 더하고 소문에 소문이 더할 때에 그들이 선지자에게서 묵시를 구하나 헛될 것이며 제사장에게는 율법이 없어질 것이요 장로에게는 책략이 없어질 것이며\n겔7:27 왕은 애통하고 고관은 놀람을 옷 입듯 하며 주민의 손은 떨리리라 내가 그 행위대로 그들에게 갚고 그 죄악대로 그들을 심판하리니 내가 여호와인 줄을 그들이 알리라' WHERE date = '2027-07-20';
UPDATE public.qt_plans SET text = E'겔1:2 여호야긴 왕이 사로잡힌 지 오 년 그 달 초닷새라\n겔1:3 갈대아 땅 그발 강 가에서 여호와의 말씀이 부시의 아들 제사장 나 에스겔에게 특별히 임하고 여호와의 권능이 내 위에 있으니라\n겔1:4 내가 보니 북쪽에서부터 폭풍과 큰 구름이 오는데 그 속에서 불이 번쩍번쩍하여 빛이 그 사방에 비치며 그 불 가운데 단 쇠 같은 것이 나타나 보이고\n겔1:5 그 속에서 네 생물의 형상이 나타나는데 그들의 모양이 이러하니 그들에게 사람의 형상이 있더라\n겔1:6 그들에게 각각 네 얼굴과 네 날개가 있고\n겔1:7 그들의 다리는 곧은 다리요 그들의 발바닥은 송아지 발바닥 같고 광낸 구리 같이 빛나며\n겔1:8 그 사방 날개 밑에는 각각 사람의 손이 있더라 그 네 생물의 얼굴과 날개가 이러하니\n겔1:9 날개는 다 서로 연하였으며 갈 때에는 돌이키지 아니하고 일제히 앞으로 곧게 행하며\n겔1:10 그 얼굴들의 모양은 넷의 앞은 사람의 얼굴이요 넷의 오른쪽은 사자의 얼굴이요 넷의 왼쪽은 소의 얼굴이요 넷의 뒤는 독수리의 얼굴이니\n겔1:11 그 얼굴은 그러하며 그 날개는 들어 펴서 각기 둘씩 서로 연하였고 또 둘은 몸을 가렸으며\n겔1:12 영이 어떤 쪽으로 가면 그 생물들도 그대로 가되 돌이키지 아니하고 일제히 앞으로 곧게 행하며\n겔1:13 또 생물들의 모양은 타는 숯불과 횃불 모양 같은데 그 불이 그 생물 사이에서 오르락내리락 하며 그 불은 광채가 있고 그 가운데에서는 번개가 나며\n겔1:14 그 생물들은 번개 모양 같이 왕래하더라\n겔1:15 내가 그 생물들을 보니 그 생물들 곁에 있는 땅 위에는 바퀴가 있는데 그 네 얼굴을 따라 하나씩 있고\n겔1:16 그 바퀴의 모양과 그 구조는 황옥 같이 보이는데 그 넷은 똑같은 모양을 가지고 있으며 그들의 모양과 구조는 바퀴 안에 바퀴가 있는 것 같으며\n겔1:17 그들이 갈 때에는 사방으로 향한 대로 돌이키지 아니하고 가며\n겔1:18 그 둘레는 높고 무서우며 그 네 둘레로 돌아가면서 눈이 가득하며\n겔1:19 그 생물들이 갈 때에 바퀴들도 그 곁에서 가고 그 생물들이 땅에서 들릴 때에 바퀴들도 들려서\n겔1:20 영이 어떤 쪽으로 가면 생물들도 영이 가려 하는 곳으로 가고 바퀴들도 그 곁에서 들리니 이는 생물의 영이 그 바퀴들 가운데에 있음이니라\n겔1:21 그들이 가면 이들도 가고 그들이 서면 이들도 서고 그들이 땅에서 들릴 때에는 이들도 그 곁에서 들리니 이는 생물의 영이 그 바퀴들 가운데에 있음이더라\n겔1:22 그 생물의 머리 위에는 수정 같은 궁창의 형상이 있어 보기에 두려운데 그들의 머리 위에 펼쳐져 있고\n겔1:23 그 궁창 밑에 생물들의 날개가 서로 향하여 펴 있는데 이 생물은 두 날개로 몸을 가렸고 저 생물도 두 날개로 몸을 가렸더라\n겔1:24 생물들이 갈 때에 내가 그 날개 소리를 들으니 많은 물 소리와도 같으며 전능자의 음성과도 같으며 떠드는 소리 곧 군대의 소리와도 같더니 그 생물이 설 때에 그 날개를 내렸더라\n겔1:25 그 머리 위에 있는 궁창 위에서부터 음성이 나더라 그 생물이 설 때에 그 날개를 내렸더라\n겔1:26 그 머리 위에 있는 궁창 위에 보좌의 형상이 있는데 그 모양이 남보석 같고 그 보좌의 형상 위에 한 형상이 있어 사람의 모양 같더라\n겔1:27 내가 보니 그 허리 위의 모양은 단 쇠 같아서 그 속과 주위가 불 같고 내가 보니 그 허리 아래의 모양도 불 같아서 사방으로 광채가 나며\n겔1:28 그 사방 광채의 모양은 비 오는 날 구름에 있는 무지개 같으니 이는 여호와의 영광의 형상의 모양이라 내가 보고 엎드려 말씀하시는 이의 음성을 들으니라' WHERE date = '2027-07-21';
UPDATE public.qt_plans SET text = E'겔2:1  그가 내게 이르시되 인자야 네 발로 일어서라 내가 네게 말하리라 하시며\n겔2:2 그가 내게 말씀하실 때에 그 영이 내게 임하사 나를 일으켜 내 발로 세우시기로 내가 그 말씀하시는 자의 소리를 들으니\n겔2:3 내게 이르시되 인자야 내가 너를 이스라엘 자손 곧 패역한 백성, 나를 배반하는 자에게 보내노라 그들과 그 조상들이 내게 범죄하여 오늘까지 이르렀나니\n겔2:4 이 자손은 얼굴이 뻔뻔하고 마음이 굳은 자니라 내가 너를 그들에게 보내노니 너는 그들에게 이르기를 주 여호와의 말씀이 이러하시다 하라\n겔2:5 그들은 패역한 족속이라 그들이 듣든지 아니 듣든지 그들 가운데에 선지자가 있음을 알지니라\n겔2:6 인자야 너는 비록 가시와 찔레와 함께 있으며 전갈 가운데에 거주할지라도 그들을 두려워하지 말고 그들의 말을 두려워하지 말지어다 그들은 패역한 족속이라도 그 말을 두려워하지 말며 그 얼굴을 무서워하지 말지어다\n겔2:7 그들은 심히 패역한 자라 그들이 듣든지 아니 듣든지 너는 내 말로 고할지어다\n겔2:8 너 인자야 내가 네게 이르는 말을 듣고 그 패역한 족속 같이 패역하지 말고 네 입을 벌리고 내가 네게 주는 것을 먹으라 하시기로\n겔2:9 내가 보니 보라 한 손이 나를 향하여 펴지고 보라 그 안에 두루마리 책이 있더라\n겔2:10 그가 그것을 내 앞에 펴시니 그 안팎에 글이 있는데 그 위에 애가와 애곡과 재앙의 말이 기록되었더라' WHERE date = '2027-07-22';
UPDATE public.qt_plans SET text = E'겔3:1 또 그가 내게 이르시되 인자야 너는 발견한 것을 먹으라 너는 이 두루마리를 먹고 가서 이스라엘 족속에게 말하라 하시기로\n겔3:2 내가 입을 벌리니 그가 그 두루마리를 내게 먹이시며\n겔3:3 내게 이르시되 인자야 내가 네게 주는 이 두루마리를 네 배에 넣으며 네 창자에 채우라 하시기에 내가 먹으니 그것이 내 입에서 달기가 꿀 같더라\n겔3:4 그가 또 내게 이르시되 인자야 이스라엘 족속에게 가서 내 말로 그들에게 고하라\n겔3:5 너를 언어가 다르거나 말이 어려운 백성에게 보내는 것이 아니요 이스라엘 족속에게 보내는 것이라\n겔3:6 너를 언어가 다르거나 말이 어려워 네가 그들의 말을 알아 듣지 못할 나라들에게 보내는 것이 아니니라 내가 너를 그들에게 보냈다면 그들은 정녕 네 말을 들었으리라\n겔3:7 그러나 이스라엘 족속은 이마가 굳고 마음이 굳어 네 말을 듣고자 아니하리니 이는 내 말을 듣고자 아니함이니라\n겔3:8 보라 내가 그들의 얼굴을 마주보도록 네 얼굴을 굳게 하였고 그들의 이마를 마주보도록 네 이마를 굳게 하였으되\n겔3:9 네 이마를 화석보다 굳은 금강석 같이 하였으니 그들이 비록 반역하는 족속이라도 두려워하지 말며 그들의 얼굴을 무서워하지 말라 하시니라\n겔3:10 또 내게 이르시되 인자야 내가 네게 이를 모든 말을 너는 마음으로 받으며 귀로 듣고\n겔3:11 사로잡힌 네 민족에게로 가서 그들이 듣든지 아니 듣든지 그들에게 고하여 이르기를 주 여호와의 말씀이 이러하시다 하라\n겔3:12 때에 주의 영이 나를 들어올리시는데 내가 내 뒤에서 크게 울리는 소리를 들으니 찬송할지어다 여호와의 영광이 그의 처소로부터 나오는도다 하니\n겔3:13 이는 생물들의 날개가 서로 부딪치는 소리와 생물 곁의 바퀴 소리라 크게 울리는 소리더라\n겔3:14 주의 영이 나를 들어올려 데리고 가시는데 내가 근심하고 분한 마음으로 가니 여호와의 권능이 힘 있게 나를 감동시키시더라\n겔3:15 이에 내가 델아빕에 이르러 그 사로잡힌 백성 곧 그발 강 가에 거주하는 자들에게 나아가 그 중에서 두려워 떨며 칠 일을 지내니라\n겔3:16  칠 일 후에 여호와의 말씀이 내게 임하여 이르시되\n겔3:17 인자야 내가 너를 이스라엘 족속의 파수꾼으로 세웠으니 너는 내 입의 말을 듣고 나를 대신하여 그들을 깨우치라\n겔3:18 가령 내가 악인에게 말하기를 너는 꼭 죽으리라 할 때에 네가 깨우치지 아니하거나 말로 악인에게 일러서 그의 악한 길을 떠나 생명을 구원하게 하지 아니하면 그 악인은 그의 죄악 중에서 죽으려니와 내가 그의 피 값을 네 손에서 찾을 것이고\n겔3:19 네가 악인을 깨우치되 그가 그의 악한 마음과 악한 행위에서 돌이키지 아니하면 그는 그의 죄악 중에서 죽으려니와 너는 네 생명을 보존하리라\n겔3:20 또 의인이 그의 공의에서 돌이켜 악을 행할 때에는 이미 행한 그의 공의는 기억할 바 아니라 내가 그 앞에 거치는 것을 두면 그가 죽을지니 이는 네가 그를 깨우치지 않음이니라 그는 그의 죄 중에서 죽으려니와 그의 피 값은 내가 네 손에서 찾으리라\n겔3:21 그러나 네가 그 의인을 깨우쳐 범죄하지 아니하게 함으로 그가 범죄하지 아니하면 정녕 살리니 이는 깨우침을 받음이며 너도 네 영혼을 보존하리라\n겔3:22  여호와께서 권능으로 거기서 내게 임하시고 또 내게 이르시되 일어나 들로 나아가라 내가 거기서 너와 말하리라 하시기로\n겔3:23 내가 일어나 들로 나아가니 여호와의 영광이 거기에 머물렀는데 내가 전에 그발 강 가에서 보던 영광과 같은지라 내가 곧 엎드리니\n겔3:24 주의 영이 내게 임하사 나를 일으켜 내 발로 세우시고 내게 말씀하여 이르시되 너는 가서 네 집에 들어가 문을 닫으라\n겔3:25 너 인자야 보라 무리가 네 위에 줄을 놓아 너를 동여매리니 네가 그들 가운데에서 나오지 못할 것이라\n겔3:26 내가 네 혀를 네 입천장에 붙게 하여 네가 말 못하는 자가 되어 그들을 꾸짖는 자가 되지 못하게 하리니 그들은 패역한 족속임이니라\n겔3:27 그러나 내가 너와 말할 때에 네 입을 열리니 너는 그들에게 이르기를 주 여호와의 말씀이 이러하시다 하라 들을 자는 들을 것이요 듣기 싫은 자는 듣지 아니하리니 그들은 반역하는 족속임이니라' WHERE date = '2027-07-23';
UPDATE public.qt_plans SET text = E'겔4:1  너 인자야 토판을 가져다가 그것을 네 앞에 놓고 한 성읍 곧 예루살렘을 그 위에 그리고\n겔4:2 그 성읍을 에워싸되 그것을 향하여 사다리를 세우고 그것을 향하여 흙으로 언덕을 쌓고 그것을 향하여 진을 치고 그것을 향하여 공성퇴를 둘러 세우고\n겔4:3 또 철판을 가져다가 너와 성읍 사이에 두어 철벽을 삼고 성을 포위하는 것처럼 에워싸라 이것이 이스라엘 족속에게 징조가 되리라\n겔4:4 너는 또 왼쪽으로 누워 이스라엘 족속의 죄악을 짊어지되 네가 눕는 날수대로 그 죄악을 담당할지니라\n겔4:5 내가 그들의 범죄한 햇수대로 네게 날수를 정하였나니 곧 삼백구십 일이니라 너는 이렇게 이스라엘 족속의 죄악을 담당하고\n겔4:6 그 수가 차거든 너는 오른쪽으로 누워 유다 족속의 죄악을 담당하라 내가 네게 사십 일로 정하였나니 하루가 일 년이니라\n겔4:7 너는 또 네 얼굴을 에워싸인 예루살렘 쪽으로 향하고 팔을 걷어 올리고 예언하라\n겔4:8 내가 줄로 너를 동이리니 네가 에워싸는 날이 끝나기까지 몸을 이리 저리 돌리지 못하리라\n겔4:9 너는 밀과 보리와 콩과 팥과 조와 귀리를 가져다가 한 그릇에 담고 너를 위하여 떡을 만들어 네가 옆으로 눕는 날수 곧 삼백구십 일 동안 먹되\n겔4:10 너는 음식물을 달아서 하루 이십 세겔씩 때를 따라 먹고\n겔4:11 물도 육분의 일 힌씩 되어서 때를 따라 마시라\n겔4:12 너는 그것을 보리떡처럼 만들어 먹되 그들의 목전에서 인분 불을 피워 구울지니라\n겔4:13 또 여호와께서 이르시되 내가 여러 나라들로 쫓아내어 흩어 버릴 이스라엘 자손이 거기서 이같이 부정한 떡을 먹으리라 하시기로\n겔4:14 내가 말하되 아하 주 여호와여 나는 영혼을 더럽힌 일이 없었나이다 어려서부터 지금까지 스스로 죽은 것이나 짐승에게 찢긴 것을 먹지 아니하였고 가증한 고기를 입에 넣지 아니하였나이다\n겔4:15 여호와께서 내게 이르시되 보라 쇠똥으로 인분을 대신하기를 허락하노니 너는 그것으로 떡을 구울지니라\n겔4:16 또 내게 이르시되 인자야 내가 예루살렘에서 의뢰하는 양식을 끊으리니 백성이 근심 중에 떡을 달아 먹고 두려워 떨며 물을 되어 마시다가\n겔4:17 떡과 물이 부족하여 피차에 두려워 하여 떨며 그 죄악 중에서 쇠패하리라' WHERE date = '2027-07-24';
UPDATE public.qt_plans SET text = E'겔5:1  너 인자야 너는 날카로운 칼을 가져다가 삭도로 삼아 네 머리털과 수염을 깎아서 저울로 달아 나누어 두라\n겔5:2 그 성읍을 에워싸는 날이 차거든 너는 터럭 삼분의 일은 성읍 안에서 불사르고 삼분의 일은 성읍 사방에서 칼로 치고 또 삼분의 일은 바람에 흩으라 내가 그 뒤를 따라 칼을 빼리라\n겔5:3 너는 터럭 중에서 조금을 네 옷자락에 싸고\n겔5:4 또 그 가운데에서 얼마를 불에 던져 사르라 그 속에서 불이 이스라엘 온 족속에게로 나오리라\n겔5:5 주 여호와께서 이와 같이 이르시되 이것이 곧 예루살렘이라 내가 그를 이방인 가운데에 두어 나라들이 둘러 있게 하였거늘\n겔5:6 그가 내 규례를 거슬러서 이방인보다 악을 더 행하며 내 율례도 그리함이 그를 둘러 있는 나라들보다 더하니 이는 그들이 내 규례를 버리고 내 율례를 행하지 아니하였음이니라\n겔5:7 그러므로 나 주 여호와가 말하노라 너희 요란함이 너희를 둘러싸고 있는 이방인들보다 더하여 내 율례를 행하지 아니하며 내 규례를 지키지 아니하고 너희를 둘러 있는 이방인들의 규례대로도 행하지 아니하였느니라\n겔5:8 그러므로 나 주 여호와가 말하노라 나 곧 내가 너를 치며 이방인의 목전에서 너에게 벌을 내리되\n겔5:9 네 모든 가증한 일로 말미암아 내가 전무후무하게 네게 내릴지라\n겔5:10 그리한즉 네 가운데에서 아버지가 아들을 잡아먹고 아들이 그 아버지를 잡아먹으리라 내가 벌을 네게 내리고 너희 중에 남은 자를 다 사방에 흩으리라\n겔5:11 그러므로 나 주 여호와가 말하노라 내가 나의 삶을 두고 맹세하노니 네가 모든 미운 물건과 모든 가증한 일로 내 성소를 더럽혔은즉 나도 너를 아끼지 아니하며 긍휼을 베풀지 아니하고 미약하게 하리니\n겔5:12 너희 가운데에서 삼분의 일은 전염병으로 죽으며 기근으로 멸망할 것이요 삼분의 일은 너의 사방에서 칼에 엎드러질 것이며 삼분의 일은 내가 사방에 흩어 버리고 또 그 뒤를 따라 가며 칼을 빼리라\n겔5:13 이와 같이 내 노가 다한즉 그들을 향한 분이 풀려서 내 마음이 가라앉으리라 내 분이 그들에게 다한즉 나 여호와가 열심으로 말한 줄을 그들이 알리라\n겔5:14 내가 이르되 또 너를 황무하게 하고 너를 둘러싸고 있는 이방인들 중에서 모든 지나가는 자의 목전에 모욕 거리가 되게 하리니\n겔5:15 내 노와 분과 중한 책망으로 네게 벌을 내린즉 너를 둘러싸고 있는 이방인들에게 네가 수치와 조롱 거리가 되고 두려움과 경고가 되리라 나 여호와의 말이니라\n겔5:16 내가 멸망하게 하는 기근의 독한 화살을 너희에게 보내되 기근을 더하여 너희가 의뢰하는 양식을 끊을 것이라\n겔5:17 내가 기근과 사나운 짐승을 너희에게 보내 외롭게 하고 너희 가운데에 전염병과 살륙이 일어나게 하고 또 칼이 너희에게 임하게 하리라 나 여호와의 말이니라' WHERE date = '2027-07-26';
UPDATE public.qt_plans SET text = E'겔6:1  여호와의 말씀이 내게 임하여 이르시되\n겔6:2 인자야 너는 이스라엘 산을 향하여 그들에게 예언하여\n겔6:3 이르기를 이스라엘 산들아 주 여호와의 말씀을 들으라 주 여호와께서 산과 언덕과 시내와 골짜기를 향하여 이같이 말씀하시기를 나 곧 내가 칼이 너희에게 임하게 하여 너희 산당을 멸하리니\n겔6:4 너희 제단들이 황폐하고 분향제단들이 깨뜨려질 것이며 너희가 죽임을 당하여 너희 우상 앞에 엎드러지게 할 것이라\n겔6:5 이스라엘 자손의 시체를 그 우상 앞에 두며 너희 해골을 너희 제단 사방에 흩으리라\n겔6:6 내가 너희가 거주하는 모든 성읍이 사막이 되게 하며 산당을 황폐하게 하리니 이는 너희 제단이 깨어지고 황폐하며 너희 우상들이 깨어져 없어지며 너희 분향제단들이 찍히며 너희가 만든 것이 폐하여지며\n겔6:7 또 너희가 죽임을 당하여 엎드러지게 하여 내가 여호와인 줄을 너희가 알게 하려 함이라\n겔6:8 그러나 너희가 여러 나라에 흩어질 때에 내가 너희 중에서 칼을 피하여 이방인들 중에 살아 남은 자가 있게 할지라\n겔6:9 너희 중에서 살아 남은 자가 사로잡혀 이방인들 중에 있어서 나를 기억하되 그들이 음란한 마음으로 나를 떠나고 음란한 눈으로 우상을 섬겨 나를 근심하게 한 것을 기억하고 스스로 한탄하리니 이는 그 모든 가증한 일로 악을 행하였음이라\n겔6:10 그 때에야 그들이 나를 여호와인 줄 알리라 내가 이런 재앙을 그들에게 내리겠다 한 말이 헛되지 아니하니라\n겔6:11 주 여호와께서 이같이 이르시되 너는 손뼉을 치고 발을 구르며 말할지어다 오호라 이스라엘 족속이 모든 가증한 악을 행하므로 마침내 칼과 기근과 전염병에 망하되\n겔6:12 먼 데 있는 자는 전염병에 죽고 가까운 데 있는 자는 칼에 엎드러지고 남아 있어 에워싸인 자는 기근에 죽으리라 이같이 내 진노를 그들에게 이룬즉\n겔6:13 그 죽임 당한 시체들이 그 우상들 사이에, 제단 사방에, 각 높은 고개 위에, 모든 산 꼭대기에, 모든 푸른 나무 아래에, 무성한 상수리나무 아래 곧 그 우상에게 분향하던 곳에 있으리니 내가 여호와인 줄을 너희가 알리라\n겔6:14 내가 내 손을 그들의 위에 펴서 그가 사는 온 땅 곧 광야에서부터 디블라까지 황량하고 황폐하게 하리니 내가 여호와인 줄을 그들이 알리라' WHERE date = '2027-07-27';
UPDATE public.qt_plans SET text = E'겔7:1  또 여호와의 말씀이 내게 임하여 이르시되\n겔7:2 너 인자야 주 여호와께서 이스라엘 땅에 관하여 이같이 말씀하셨느니라 끝났도다 이 땅 사방의 일이 끝났도다\n겔7:3 이제는 네게 끝이 이르렀나니 내가 내 진노를 네게 나타내어 네 행위를 심판하고 네 모든 가증한 일을 보응하리라\n겔7:4 내가 너를 불쌍히 여기지 아니하며 긍휼히 여기지도 아니하고 네 행위대로 너를 벌하여 네 가증한 일이 너희 중에 나타나게 하리니 내가 여호와인 줄을 너희가 알리라\n겔7:5 주 여호와께서 이같이 이르시되 재앙이로다, 비상한 재앙이로다 볼지어다 그것이 왔도다\n겔7:6 끝이 왔도다, 끝이 왔도다 끝이 너에게 왔도다 볼지어다 그것이 왔도다\n겔7:7 이 땅 주민아 정한 재앙이 네게 임하도다 때가 이르렀고 날이 가까웠으니 요란한 날이요 산에서 즐거이 부르는 날이 아니로다\n겔7:8 이제 내가 속히 분을 네게 쏟고 내 진노를 네게 이루어서 네 행위대로 너를 심판하여 네 모든 가증한 일을 네게 보응하되\n겔7:9 내가 너를 불쌍히 여기지 아니하며 긍휼히 여기지도 아니하고 네 행위대로 너를 벌하여 너의 가증한 일이 너희 중에 나타나게 하리니 나 여호와가 때리는 이임을 네가 알리라\n겔7:10 볼지어다 그 날이로다 볼지어다 임박하도다 정한 재앙이 이르렀으니 몽둥이가 꽃이 피며 교만이 싹이 났도다\n겔7:11 포학이 일어나서 죄악의 몽둥이가 되었은즉 그들도, 그 무리도, 그 재물도 하나도 남지 아니하며 그 중의 아름다운 것도 없어지리로다\n겔7:12 때가 이르렀고 날이 가까웠으니 사는 자도 기뻐하지 말고 파는 자도 근심하지 말 것은 진노가 그 모든 무리에게 임함이로다\n겔7:13 파는 자가 살아 있다 할지라도 다시 돌아가서 그 판 것을 얻지 못하리니 이는 묵시가 그 모든 무리에게 돌아오지 아니하고, 사람이 그 죄악으로 말미암아 자기의 목숨을 유지할 수 없으리라 하였음이로다\n겔7:14  그들이 나팔을 불어 온갖 것을 준비하였을지라도 전쟁에 나갈 사람이 없나니 이는 내 진노가 그 모든 무리에게 이르렀음이라\n겔7:15 밖에는 칼이 있고 안에는 전염병과 기근이 있어서 밭에 있는 자는 칼에 죽을 것이요 성읍에 있는 자는 기근과 전염병에 망할 것이며\n겔7:16 도망하는 자는 산 위로 피하여 다 각기 자기 죄악 때문에 골짜기의 비둘기들처럼 슬피 울 것이며\n겔7:17 모든 손은 피곤하고 모든 무릎은 물과 같이 약할 것이라\n겔7:18 그들이 굵은 베로 허리를 묶을 것이요 두려움이 그들을 덮을 것이요 모든 얼굴에는 수치가 있고 모든 머리는 대머리가 될 것이며\n겔7:19 그들이 그 은을 거리에 던지며 그 금을 오물 같이 여기리니 이는 여호와 내가 진노를 내리는 날에 그들의 은과 금이 능히 그들을 건지지 못하며 능히 그 심령을 족하게 하거나 그 창자를 채우지 못하고 오직 죄악의 걸림돌이 됨이로다\n겔7:20 그들이 그 화려한 장식으로 말미암아 교만을 품었고 또 그것으로 가증한 우상과 미운 물건을 만들었은즉 내가 그것을 그들에게 오물이 되게 하여\n겔7:21 타국인의 손에 넘겨 노략하게 하며 세상 악인에게 넘겨 그들이 약탈하여 더럽히게 하고\n겔7:22 내가 또 내 얼굴을 그들에게서 돌이키리니 그들이 내 은밀한 처소를 더럽히고 포악한 자도 거기 들어와서 더럽히리라\n겔7:23 너는 쇠사슬을 만들라 이는 피 흘리는 죄가 그 땅에 가득하고 포악이 그 성읍에 찼음이라\n겔7:24 내가 극히 악한 이방인들을 데려와서 그들이 그 집들을 점령하게 하고 강한 자의 교만을 그치게 하리니 그들의 성소가 더럽힘을 당하리라\n겔7:25 패망이 이르리니 그들이 평강을 구하여도 없을 것이라\n겔7:26 환난에 환난이 더하고 소문에 소문이 더할 때에 그들이 선지자에게서 묵시를 구하나 헛될 것이며 제사장에게는 율법이 없어질 것이요 장로에게는 책략이 없어질 것이며\n겔7:27 왕은 애통하고 고관은 놀람을 옷 입듯 하며 주민의 손은 떨리리라 내가 그 행위대로 그들에게 갚고 그 죄악대로 그들을 심판하리니 내가 여호와인 줄을 그들이 알리라' WHERE date = '2027-07-28';
UPDATE public.qt_plans SET text = E'겔36:1  인자야 너는 이스라엘 산들에게 예언하여 이르기를 이스라엘 산들아 여호와의 말씀을 들으라\n겔36:2 주 여호와께서 이같이 말씀하시기를 원수들이 네게 대하여 말하기를 아하 옛적 높은 곳이 우리의 기업이 되었도다 하였느니라\n겔36:3 그러므로 너는 예언하여 이르기를 주 여호와께서 이같이 말씀하시기를 그들이 너희를 황폐하게 하고 너희 사방을 삼켜 너희가 남은 이방인의 기업이 되게 하여 사람의 말 거리와 백성의 비방 거리가 되게 하였도다\n겔36:4 그러므로 이스라엘 산들아 주 여호와의 말씀을 들을지어다 산들과 멧부리들과 시내들과 골짜기들과 황폐한 사막들과 사방에 남아 있는 이방인의 노략 거리와 조롱 거리가 된 성읍들에게 주 여호와께서 이같이 말씀하셨느니라\n겔36:5 주 여호와께서 이같이 말씀하시기를 내가 진실로 내 맹렬한 질투로 남아 있는 이방인과 에돔 온 땅을 쳐서 말하였노니 이는 그들이 심히 즐거워하는 마음과 멸시하는 심령으로 내 땅을 빼앗아 노략하여 자기 소유를 삼았음이라\n겔36:6 그러므로 너는 이스라엘 땅에 대하여 예언하되 그 산들과 멧부리들과 시내들과 골짜기들에 관하여 이르기를 주 여호와께서 이같이 말씀하시기를 내가 내 질투와 내 분노로 말하였나니 이는 너희가 이방의 수치를 당하였음이라\n겔36:7 그러므로 주 여호와께서 이같이 말씀하시기를 내가 맹세하였은즉 너희 사방에 있는 이방인이 자신들의 수치를 반드시 당하리라\n겔36:8 그러나 너희 이스라엘 산들아 너희는 가지를 내고 내 백성 이스라엘을 위하여 열매를 맺으리니 그들이 올 때가 가까이 이르렀음이라\n겔36:9 내가 돌이켜 너희와 함께 하리니 사람이 너희를 갈고 심을 것이며\n겔36:10 내가 또 사람을 너희 위에 많게 하리니 이들은 이스라엘 온 족속이라 그들을 성읍들에 거주하게 하며 빈 땅에 건축하게 하리라\n겔36:11 내가 너희 위에 사람과 짐승을 많게 하되 그들의 수가 많고 번성하게 할 것이라 너희 전 지위대로 사람이 거주하게 하여 너희를 처음보다 낫게 대우하리니 내가 여호와인 줄을 너희가 알리라\n겔36:12 내가 사람을 너희 위에 다니게 하리니 그들은 내 백성 이스라엘이라 그들은 너를 얻고 너는 그 기업이 되어 다시는 그들이 자식들을 잃어버리지 않게 하리라\n겔36:13 주 여호와께서 이같이 말씀하셨느니라 그들이 너희에게 이르기를 너는 사람을 삼키는 자요 네 나라 백성을 제거한 자라 하거니와\n겔36:14 네가 다시는 사람을 삼키지 아니하며 다시는 네 나라 백성을 제거하지 아니하리라 주 여호와의 말씀이니라\n겔36:15 내가 또 너를 여러 나라의 수치를 듣지 아니하게 하며 만민의 비방을 다시 받지 아니하게 하며 네 나라 백성을 다시 넘어뜨리지 아니하게 하리라 주 여호와의 말씀이니라 하셨다 하라\n겔36:16  여호와의 말씀이 또 내게 임하여 이르시되\n겔36:17 인자야 이스라엘 족속이 그들의 고국 땅에 거주할 때에 그들의 행위로 그 땅을 더럽혔나니 나 보기에 그 행위가 월경 중에 있는 여인의 부정함과 같았느니라\n겔36:18 그들이 땅 위에 피를 쏟았으며 그 우상들로 말미암아 자신들을 더럽혔으므로 내가 분노를 그들 위에 쏟아\n겔36:19 그들을 그 행위대로 심판하여 각국에 흩으며 여러 나라에 헤쳤더니\n겔36:20 그들이 이른바 그 여러 나라에서 내 거룩한 이름이 그들로 말미암아 더러워졌나니 곧 사람들이 그들을 가리켜 이르기를 이들은 여호와의 백성이라도 여호와의 땅에서 떠난 자라 하였음이라\n겔36:21 그러나 이스라엘 족속이 들어간 그 여러 나라에서 더럽힌 내 거룩한 이름을 내가 아꼈노라\n겔36:22 그러므로 너는 이스라엘 족속에게 이르기를 주 여호와께서 이같이 말씀하시기를 이스라엘 족속아 내가 이렇게 행함은 너희를 위함이 아니요 너희가 들어간 그 여러 나라에서 더럽힌 나의 거룩한 이름을 위함이라\n겔36:23 여러 나라 가운데에서 더럽혀진 이름 곧 너희가 그들 가운데에서 더럽힌 나의 큰 이름을 내가 거룩하게 할지라 내가 그들의 눈 앞에서 너희로 말미암아 나의 거룩함을 나타내리니 내가 여호와인 줄을 여러 나라 사람이 알리라 주 여호와의 말씀이니라\n겔36:24 내가 너희를 여러 나라 가운데에서 인도하여 내고 여러 민족 가운데에서 모아 데리고 고국 땅에 들어가서\n겔36:25 맑은 물을 너희에게 뿌려서 너희로 정결하게 하되 곧 너희 모든 더러운 것에서와 모든 우상 숭배에서 너희를 정결하게 할 것이며\n겔36:26 또 새 영을 너희 속에 두고 새 마음을 너희에게 주되 너희 육신에서 굳은 마음을 제거하고 부드러운 마음을 줄 것이며\n겔36:27 또 내 영을 너희 속에 두어 너희로 내 율례를 행하게 하리니 너희가 내 규례를 지켜 행할지라\n겔36:28 내가 너희 조상들에게 준 땅에서 너희가 거주하면서 내 백성이 되고 나는 너희 하나님이 되리라\n겔36:29 내가 너희를 모든 더러운 데에서 구원하고 곡식이 풍성하게 하여 기근이 너희에게 닥치지 아니하게 할 것이며\n겔36:30 또 나무의 열매와 밭의 소산을 풍성하게 하여 너희가 다시는 기근의 욕을 여러 나라에게 당하지 아니하게 하리니\n겔36:31 그 때에 너희가 너희 악한 길과 너희 좋지 못한 행위를 기억하고 너희 모든 죄악과 가증한 일로 말미암아 스스로 밉게 보리라\n겔36:32 주 여호와의 말씀이니라 내가 이렇게 행함은 너희를 위함이 아닌 줄을 너희가 알리라 이스라엘 족속아 너희 행위로 말미암아 부끄러워하고 한탄할지어다\n겔36:33 주 여호와께서 이같이 말씀하셨느니라 내가 너희를 모든 죄악에서 정결하게 하는 날에 성읍들에 사람이 거주하게 하며 황폐한 것이 건축되게 할 것인즉\n겔36:34 전에는 지나가는 자의 눈에 황폐하게 보이던 그 황폐한 땅이 장차 경작이 될지라\n겔36:35 사람이 이르기를 이 땅이 황폐하더니 이제는 에덴 동산 같이 되었고 황량하고 적막하고 무너진 성읍들에 성벽과 주민이 있다 하리니\n겔36:36 너희 사방에 남은 이방 사람이 나 여호와가 무너진 곳을 건축하며 황폐한 자리에 심은 줄을 알리라 나 여호와가 말하였으니 이루리라\n겔36:37 주 여호와께서 이같이 말씀하셨느니라 그래도 이스라엘 족속이 이같이 자기들에게 이루어 주기를 내게 구하여야 할지라 내가 그들의 수효를 양 떼 같이 많아지게 하되\n겔36:38 제사 드릴 양 떼 곧 예루살렘이 정한 절기의 양 무리 같이 황폐한 성읍을 사람의 떼로 채우리라 그리한즉 그들이 나를 여호와인 줄 알리라 하셨느니라' WHERE date = '2027-07-29';
UPDATE public.qt_plans SET text = E'겔37:1  여호와께서 권능으로 내게 임재하시고 그의 영으로 나를 데리고 가서 골짜기 가운데 두셨는데 거기 뼈가 가득하더라\n겔37:2 나를 그 뼈 사방으로 지나가게 하시기로 본즉 그 골짜기 지면에 뼈가 심히 많고 아주 말랐더라\n겔37:3 그가 내게 이르시되 인자야 이 뼈들이 능히 살 수 있겠느냐 하시기로 내가 대답하되 주 여호와여 주께서 아시나이다\n겔37:4 또 내게 이르시되 너는 이 모든 뼈에게 대언하여 이르기를 너희 마른 뼈들아 여호와의 말씀을 들을지어다\n겔37:5 주 여호와께서 이 뼈들에게 이같이 말씀하시기를 내가 생기를 너희에게 들어가게 하리니 너희가 살아나리라\n겔37:6 너희 위에 힘줄을 두고 살을 입히고 가죽으로 덮고 너희 속에 생기를 넣으리니 너희가 살아나리라 또 내가 여호와인 줄 너희가 알리라 하셨다 하라\n겔37:7 이에 내가 명령을 따라 대언하니 대언할 때에 소리가 나고 움직이며 이 뼈, 저 뼈가 들어 맞아 뼈들이 서로 연결되더라\n겔37:8 내가 또 보니 그 뼈에 힘줄이 생기고 살이 오르며 그 위에 가죽이 덮이나 그 속에 생기는 없더라\n겔37:9 또 내게 이르시되 인자야 너는 생기를 향하여 대언하라 생기에게 대언하여 이르기를 주 여호와께서 이같이 말씀하시기를 생기야 사방에서부터 와서 이 죽음을 당한 자에게 불어서 살아나게 하라 하셨다 하라\n겔37:10 이에 내가 그 명령대로 대언하였더니 생기가 그들에게 들어가매 그들이 곧 살아나서 일어나 서는데 극히 큰 군대더라\n겔37:11 또 내게 이르시되 인자야 이 뼈들은 이스라엘 온 족속이라 그들이 이르기를 우리의 뼈들이 말랐고 우리의 소망이 없어졌으니 우리는 다 멸절되었다 하느니라\n겔37:12 그러므로 너는 대언하여 그들에게 이르기를 주 여호와께서 이같이 말씀하시기를 내 백성들아 내가 너희 무덤을 열고 너희로 거기에서 나오게 하고 이스라엘 땅으로 들어가게 하리라\n겔37:13 내 백성들아 내가 너희 무덤을 열고 너희로 거기에서 나오게 한즉 너희는 내가 여호와인 줄을 알리라\n겔37:14 내가 또 내 영을 너희 속에 두어 너희가 살아나게 하고 내가 또 너희를 너희 고국 땅에 두리니 나 여호와가 이 일을 말하고 이룬 줄을 너희가 알리라 여호와의 말씀이니라\n겔37:15  여호와의 말씀이 또 내게 임하여 이르시되\n겔37:16 인자야 너는 막대기 하나를 가져다가 그 위에 유다와 그 짝 이스라엘 자손이라 쓰고 또 다른 막대기 하나를 가지고 그 위에 에브라임의 막대기 곧 요셉과 그 짝 이스라엘 온 족속이라 쓰고\n겔37:17 그 막대기들을 서로 합하여 하나가 되게 하라 네 손에서 둘이 하나가 되리라\n겔37:18 네 민족이 네게 말하여 이르기를 이것이 무슨 뜻인지 우리에게 말하지 아니하겠느냐 하거든\n겔37:19 너는 곧 이르기를 주 여호와께서 이같이 말씀하시기를 내가 에브라임의 손에 있는 바 요셉과 그 짝 이스라엘 지파들의 막대기를 가져다가 유다의 막대기에 붙여서 한 막대기가 되게 한즉 내 손에서 하나가 되리라 하셨다 하고\n겔37:20 너는 그 글 쓴 막대기들을 무리의 눈 앞에서 손에 잡고\n겔37:21 그들에게 이르기를 주 여호와께서 이같이 말씀하시기를 내가 이스라엘 자손을 잡혀 간 여러 나라에서 인도하며 그 사방에서 모아서 그 고국 땅으로 돌아가게 하고\n겔37:22 그 땅 이스라엘 모든 산에서 그들이 한 나라를 이루어서 한 임금이 모두 다스리게 하리니 그들이 다시는 두 민족이 되지 아니하며 두 나라로 나누이지 아니할지라\n겔37:23 그들이 그 우상들과 가증한 물건과 그 모든 죄악으로 더 이상 자신들을 더럽히지 아니하리라 내가 그들을 그 범죄한 모든 처소에서 구원하여 정결하게 한즉 그들은 내 백성이 되고 나는 그들의 하나님이 되리라\n겔37:24 내 종 다윗이 그들의 왕이 되리니 그들 모두에게 한 목자가 있을 것이라 그들이 내 규례를 준수하고 내 율례를 지켜 행하며\n겔37:25 내가 내 종 야곱에게 준 땅 곧 그의 조상들이 거주하던 땅에 그들이 거주하되 그들과 그들의 자자 손손이 영원히 거기에 거주할 것이요 내 종 다윗이 영원히 그들의 왕이 되리라\n겔37:26 내가 그들과 화평의 언약을 세워서 영원한 언약이 되게 하고 또 그들을 견고하고 번성하게 하며 내 성소를 그 가운데에 세워서 영원히 이르게 하리니\n겔37:27 내 처소가 그들 가운데에 있을 것이며 나는 그들의 하나님이 되고 그들은 내 백성이 되리라\n겔37:28 내 성소가 영원토록 그들 가운데에 있으리니 내가 이스라엘을 거룩하게 하는 여호와인 줄을 열국이 알리라 하셨다 하라' WHERE date = '2027-07-30';
UPDATE public.qt_plans SET text = E'겔38:1  여호와의 말씀이 내게 임하여 이르시되\n겔38:2 인자야 너는 마곡 땅에 있는 로스와 메섹과 두발 왕 곧 곡에게로 얼굴을 향하고 그에게 예언하여\n겔38:3 이르기를 주 여호와께서 이같이 말씀하시기를 로스와 메섹과 두발 왕 곡아 내가 너를 대적하여\n겔38:4 너를 돌이켜 갈고리로 네 아가리를 꿰고 너와 말과 기마병 곧 네 온 군대를 끌어내되 완전한 갑옷을 입고 큰 방패와 작은 방패를 가지며 칼을 잡은 큰 무리와\n겔38:5 그들과 함께 한 방패와 투구를 갖춘 바사와 구스와 붓과\n겔38:6 고멜과 그 모든 떼와 북쪽 끝의 도갈마 족속과 그 모든 떼 곧 많은 백성의 무리를 너와 함께 끌어내리라\n겔38:7 너는 스스로 예비하되 너와 네게 모인 무리들이 다 스스로 예비하고 너는 그들의 우두머리가 될지어다\n겔38:8 여러 날 후 곧 말년에 네가 명령을 받고 그 땅 곧 오래 황폐하였던 이스라엘 산에 이르리니 그 땅 백성은 칼을 벗어나서 여러 나라에서 모여 들어오며 이방에서 나와 다 평안히 거주하는 중이라\n겔38:9 네가 올라오되 너와 네 모든 떼와 너와 함께 한 많은 백성이 광풍 같이 이르고 구름 같이 땅을 덮으리라\n겔38:10 주 여호와께서 이같이 말씀하셨느니라 그 날에 네 마음에서 여러 가지 생각이 나서 악한 꾀를 내어\n겔38:11 말하기를 내가 평원의 고을들로 올라 가리라 성벽도 없고 문이나 빗장이 없어도 염려 없이 다 평안히 거주하는 백성에게 나아가서\n겔38:12 물건을 겁탈하며 노략하리라 하고 네 손을 들어서 황폐하였다가 지금 사람이 거주하는 땅과 여러 나라에서 모여서 짐승과 재물을 얻고 세상 중앙에 거주하는 백성을 치고자 할 때에\n겔38:13 스바와 드단과 다시스의 상인과 그 부자들이 네게 이르기를 네가 탈취하러 왔느냐 네가 네 무리를 모아 노략하고자 하느냐 은과 금을 빼앗으며 짐승과 재물을 빼앗으며 물건을 크게 약탈하여 가고자 하느냐 하리라\n겔38:14 인자야 너는 또 예언하여 곡에게 이르기를 주 여호와께서 이같이 말씀하시기를 내 백성 이스라엘이 평안히 거주하는 날에 네가 어찌 그것을 알지 못하겠느냐\n겔38:15 네가 네 고국 땅 북쪽 끝에서 많은 백성 곧 다 말을 탄 큰 무리와 능한 군대와 함께 오되\n겔38:16 구름이 땅을 덮음 같이 내 백성 이스라엘을 치러 오리라 곡아 끝 날에 내가 너를 이끌어다가 내 땅을 치게 하리니 이는 내가 너로 말미암아 이방 사람의 눈 앞에서 내 거룩함을 나타내어 그들이 다 나를 알게 하려 함이라\n겔38:17  주 여호와께서 이같이 말씀하셨느니라 내가 옛적에 내 종 이스라엘 선지자들을 통하여 말한 사람이 네가 아니냐 그들이 그 때에 여러 해 동안 예언하기를 내가 너를 이끌어다가 그들을 치게 하리라\n겔38:18 그 날에 곡이 이스라엘 땅을 치러 오면 내 노여움이 내 얼굴에 나타나리라 주 여호와의 말씀이니라\n겔38:19 내가 질투와 맹렬한 노여움으로 말하였거니와 그 날에 큰 지진이 이스라엘 땅에 일어나서\n겔38:20 바다의 고기들과 공중의 새들과 들의 짐승들과 땅에 기는 모든 벌레와 지면에 있는 모든 사람이 내 앞에서 떨 것이며 모든 산이 무너지며 절벽이 떨어지며 모든 성벽이 땅에 무너지리라\n겔38:21 주 여호와의 말씀이니라 내가 내 모든 산 중에서 그를 칠 칼을 부르리니 각 사람이 칼로 그 형제를 칠 것이며\n겔38:22 내가 또 전염병과 피로 그를 심판하며 쏟아지는 폭우와 큰 우박덩이와 불과 유황으로 그와 그 모든 무리와 그와 함께 있는 많은 백성에게 비를 내리듯 하리라\n겔38:23 이같이 내가 여러 나라의 눈에 내 위대함과 내 거룩함을 나타내어 나를 알게 하리니 내가 여호와인 줄을 그들이 알리라' WHERE date = '2027-07-31';
UPDATE public.qt_plans SET text = E'겔39:1  그러므로 인자야 너는 곡에게 예언하여 이르기를 주 여호와께서 이같이 말씀하시되 로스와 메섹과 두발 왕 곡아 내가 너를 대적하여\n겔39:2 너를 돌이켜서 이끌고 북쪽 끝에서부터 나와서 이스라엘 산 위에 이르러\n겔39:3 네 활을 쳐서 네 왼손에서 떨어뜨리고 네 화살을 네 오른손에서 떨어뜨리리니\n겔39:4 너와 네 모든 무리와 너와 함께 있는 백성이 다 이스라엘 산 위에 엎드러지리라 내가 너를 각종 사나운 새와 들짐승에게 넘겨 먹게 하리니\n겔39:5 네가 빈 들에 엎드러지리라 이는 내가 말하였음이니라 주 여호와의 말씀이니라\n겔39:6 내가 또 불을 마곡과 및 섬에 평안히 거주하는 자에게 내리리니 내가 여호와인 줄을 그들이 알리라\n겔39:7 내가 내 거룩한 이름을 내 백성 이스라엘 가운데에 알게 하여 다시는 내 거룩한 이름을 더럽히지 아니하게 하리니 내가 여호와 곧 이스라엘의 거룩한 자인 줄을 민족들이 알리라 하라\n겔39:8 주 여호와의 말씀이니라 볼지어다 그 날이 와서 이루어지리니 내가 말한 그 날이 이 날이라\n겔39:9 이스라엘 성읍들에 거주하는 자가 나가서 그들의 무기를 불태워 사르되 큰 방패와 작은 방패와 활과 화살과 몽둥이와 창을 가지고 일곱 해 동안 불태우리라\n겔39:10 이같이 그 무기로 불을 피울 것이므로 그들이 들에서 나무를 주워 오지 아니하며 숲에서 벌목하지 아니하겠고 전에 자기에게서 약탈하던 자의 것을 약탈하며 전에 자기에게서 늑탈하던 자의 것을 늑탈하리라 주 여호와의 말씀이니라\n겔39:11 그 날에 내가 곡을 위하여 이스라엘 땅 곧 바다 동쪽 사람이 통행하는 골짜기를 매장지로 주리니 통행하던 길이 막힐 것이라 사람이 거기에서 곡과 그 모든 무리를 매장하고 그 이름을 하몬곡의 골짜기라 일컬으리라\n겔39:12 이스라엘 족속이 일곱 달 동안에 그들을 매장하여 그 땅을 정결하게 할 것이라\n겔39:13 그 땅 모든 백성이 그들을 매장하고 그로 말미암아 이름을 얻으리니 이는 나의 영광이 나타나는 날이니라 주 여호와의 말씀이니라\n겔39:14 그들이 사람을 택하여 그 땅에 늘 순행하며 매장할 사람과 더불어 지면에 남아 있는 시체를 매장하여 그 땅을 정결하게 할 것이라 일곱 달 후에 그들이 살펴 보되\n겔39:15 지나가는 사람들이 그 땅으로 지나가다가 사람의 뼈를 보면 그 곁에 푯말을 세워 매장하는 사람에게 가서 하몬곡 골짜기에 매장하게 할 것이요\n겔39:16 성읍의 이름도 하모나라 하리라 그들이 이같이 그 땅을 정결하게 하리라\n겔39:17 주 여호와께서 이같이 말씀하셨느니라 너 인자야 너는 각종 새와 들의 각종 짐승에게 이르기를 너희는 모여 오라 내가 너희를 위한 잔치 곧 이스라엘 산 위에 예비한 큰 잔치로 너희는 사방에서 모여 살을 먹으며 피를 마실지어다\n겔39:18 너희가 용사의 살을 먹으며 세상 왕들의 피를 마시기를 바산의 살진 짐승 곧 숫양이나 어린 양이나 염소나 수송아지를 먹듯 할지라\n겔39:19 내가 너희를 위하여 예비한 잔치의 기름을 너희가 배불리 먹으며 그 피를 취하도록 마시되\n겔39:20 내 상에서 말과 기병과 용사와 모든 군사를 배부르게 먹일지니라 하라 주 여호와의 말씀이니라\n겔39:21  내가 내 영광을 여러 민족 가운데에 나타내어 모든 민족이 내가 행한 심판과 내가 그 위에 나타낸 권능을 보게 하리니\n겔39:22 그 날 이후에 이스라엘 족속은 내가 여호와 자기들의 하나님인 줄을 알겠고\n겔39:23 여러 민족은 이스라엘 족속이 그 죄악으로 말미암아 사로잡혀 갔던 줄을 알지라 그들이 내게 범죄하였으므로 내 얼굴을 그들에게 가리고 그들을 그 원수의 손에 넘겨 다 칼에 엎드러지게 하였으되\n겔39:24 내가 그들의 더러움과 그들의 범죄한 대로 행하여 그들에게 내 얼굴을 가리었었느니라\n겔39:25 그러므로 주 여호와께서 이같이 말씀하셨느니라 내가 이제 내 거룩한 이름을 위하여 열심을 내어 야곱의 사로잡힌 자를 돌아오게 하며 이스라엘 온 족속에게 사랑을 베풀지라\n겔39:26 그들이 그 땅에 평안히 거주하고 두렵게 할 자가 없게 될 때에 부끄러움을 품고 내게 범한 죄를 뉘우치리니\n겔39:27 내가 그들을 만민 중에서 돌아오게 하고 적국 중에서 모아 내어 많은 민족이 보는 데에서 그들로 말미암아 나의 거룩함을 나타낼 때라\n겔39:28 전에는 내가 그들이 사로잡혀 여러 나라에 이르게 하였거니와 후에는 내가 그들을 모아 고국 땅으로 돌아오게 하고 그 한 사람도 이방에 남기지 아니하리니 그들이 내가 여호와 자기들의 하나님인 줄을 알리라\n겔39:29 내가 다시는 내 얼굴을 그들에게 가리지 아니하리니 이는 내가 내 영을 이스라엘 족속에게 쏟았음이라 주 여호와의 말씀이니라' WHERE date = '2027-08-02';
UPDATE public.qt_plans SET text = E'겔42:1  그가 나를 데리고 밖으로 나가 북쪽 뜰로 가서 두 방에 이르니 그 두 방의 하나는 골방 앞 뜰을 향하였고 다른 하나는 북쪽 건물을 향하였는데\n겔42:2 그 방들의 자리의 길이는 백 척이요 너비는 쉰 척이며 그 문은 북쪽을 향하였고\n겔42:3 그 방 삼층에 회랑들이 있는데 한 방의 회랑은 스무 척 되는 안뜰과 마주 대하였고 다른 한 방의 회랑은 바깥뜰 박석 깔린 곳과 마주 대하였으며\n겔42:4 그 두 방 사이에 통한 길이 있어 너비는 열 척이요 길이는 백 척이며 그 문들은 북쪽을 향하였으며\n겔42:5 그 위층의 방은 가장 좁으니 이는 회랑들로 말미암아 아래층과 가운데 층보다 위층이 더 줄어짐이라\n겔42:6 그 방은 삼층인데도 뜰의 기둥 같은 기둥이 없으므로 그 위층이 아래층과 가운데 층보다 더욱 좁아짐이더라\n겔42:7 그 한 방의 바깥 담 곧 뜰의 담과 마주 대한 담의 길이는 쉰 척이니\n겔42:8 바깥뜰로 향한 방의 길이는 쉰 척이며 성전 앞을 향한 방은 백 척이며\n겔42:9 이 방들 아래에 동쪽에서 들어가는 통행구가 있으니 곧 바깥뜰에서 들어가는 통행구더라\n겔42:10 남쪽 골방 뜰 맞은쪽과 남쪽 건물 맞은쪽에도 방 둘이 있는데\n겔42:11 그 두 방 사이에 길이 있고 그 방들의 모양은 북쪽 방 같고 그 길이와 너비도 같으며 그 출입구와 문도 그와 같으며\n겔42:12 이 남쪽 방에 출입하는 문이 있는데 담 동쪽 길 어귀에 있더라\n겔42:13 그가 내게 이르되 좌우 골방 뜰 앞 곧 북쪽과 남쪽에 있는 방들은 거룩한 방이라 여호와를 가까이 하는 제사장들이 지성물을 거기에서 먹을 것이며 지성물 곧 소제와 속죄제와 속건제의 제물을 거기 둘 것이니 이는 거룩한 곳이라\n겔42:14 제사장의 의복은 거룩하므로 제사장이 성소에 들어갔다가 나올 때에 바로 바깥뜰로 가지 못하고 수종드는 그 의복을 그 방에 두고 다른 옷을 입고 백성의 뜰로 나갈 것이니라 하더라\n겔42:15  그가 안에 있는 성전 측량하기를 마친 후에 나를 데리고 동쪽을 향한 문의 길로 나가서 사방 담을 측량하는데\n겔42:16 그가 측량하는 장대 곧 그 장대로 동쪽을 측량하니 오백 척이요\n겔42:17 그 장대로 북쪽을 측량하니 오백 척이요\n겔42:18 그 장대로 남쪽을 측량하니 오백 척이요\n겔42:19 서쪽으로 돌이켜 그 장대로 측량하니 오백 척이라\n겔42:20 그가 이같이 그 사방을 측량하니 그 사방 담 안 마당의 길이가 오백 척이며 너비가 오백 척이라 그 담은 거룩한 것과 속된 것을 구별하는 것이더라' WHERE date = '2027-08-04';
UPDATE public.qt_plans SET text = E'겔43:1  그 후에 그가 나를 데리고 문에 이르니 곧 동쪽을 향한 문이라\n겔43:2 이스라엘 하나님의 영광이 동쪽에서부터 오는데 하나님의 음성이 많은 물 소리 같고 땅은 그 영광으로 말미암아 빛나니\n겔43:3 그 모양이 내가 본 환상 곧 전에 성읍을 멸하러 올 때에 보던 환상 같고 그발 강 가에서 보던 환상과도 같기로 내가 곧 얼굴을 땅에 대고 엎드렸더니\n겔43:4 여호와의 영광이 동문을 통하여 성전으로 들어가고\n겔43:5 영이 나를 들어 데리고 안뜰에 들어가시기로 내가 보니 여호와의 영광이 성전에 가득하더라\n겔43:6 성전에서 내게 하는 말을 내가 듣고 있을 때에 어떤 사람이 내 곁에 서 있더라\n겔43:7 그가 내게 이르시되 인자야 이는 내 보좌의 처소, 내 발을 두는 처소, 내가 이스라엘 족속 가운데에 영원히 있을 곳이라 이스라엘 족속 곧 그들과 그들의 왕들이 음행하며 그 죽은 왕들의 시체로 다시는 내 거룩한 이름을 더럽히지 아니하리라\n겔43:8 그들이 그 문지방을 내 문지방 곁에 두며 그 문설주를 내 문설주 곁에 두어서 그들과 나 사이에 겨우 한 담이 막히게 하였고 또 그 행하는 가증한 일로 내 거룩한 이름을 더럽혔으므로 내가 노하여 멸망시켰거니와\n겔43:9 이제는 그들이 그 음란과 그 왕들의 시체를 내게서 멀리 제거하여 버려야 할 것이라 그리하면 내가 그들 가운데에 영원히 살리라\n겔43:10 인자야 너는 이 성전을 이스라엘 족속에게 보여서 그들이 자기의 죄악을 부끄러워하고 그 형상을 측량하게 하라\n겔43:11 만일 그들이 자기들이 행한 모든 일을 부끄러워하거든 너는 이 성전의 제도와 구조와 그 출입하는 곳과 그 모든 형상을 보이며 또 그 모든 규례와 그 모든 법도와 그 모든 율례를 알게 하고 그 목전에 그것을 써서 그들로 그 모든 법도와 그 모든 규례를 지켜 행하게 하라\n겔43:12 성전의 법은 이러하니라 산 꼭대기 지점의 주위는 지극히 거룩하리라 성전의 법은 이러하니라\n겔43:13  제단의 크기는 이러하니라 한 자는 팔꿈치에서부터 손가락에 이르고 한 손바닥 넓이가 더한 것이라 제단 밑받침의 높이는 한 척이요 그 사방 가장자리의 너비는 한 척이며 그 가로 둘린 턱의 너비는 한 뼘이니 이는 제단 밑받침이요\n겔43:14 이 땅에 닿은 밑받침 면에서 아래층의 높이는 두 척이요 그 가장자리의 너비는 한 척이며 이 아래층 면에서 이 층의 높이는 네 척이요 그 가장자리의 너비는 한 척이며\n겔43:15 그 번제단 위층의 높이는 네 척이며 그 번제하는 바닥에서 솟은 뿔이 넷이며\n겔43:16 그 번제하는 바닥의 길이는 열두 척이요 너비도 열두 척이니 네모 반듯하고\n겔43:17 그 아래층의 길이는 열네 척이요 너비는 열네 척이니 네모 반듯하고 그 밑받침에 둘린 턱의 너비는 반 척이며 그 가장자리의 너비는 한 척이니라 그 층계는 동쪽을 향하게 할지니라\n겔43:18  그가 내게 이르시되 인자야 주 여호와께서 이같이 말씀하셨느니라 이 제단을 만드는 날에 그 위에 번제를 드리며 피를 뿌리는 규례는 이러하니라\n겔43:19 주 여호와의 말씀이니라 나를 가까이 하여 내게 수종드는 사독의 자손 레위 사람 제사장에게 너는 어린 수송아지 한 마리를 주어 속죄제물을 삼되\n겔43:20 네가 그 피를 가져다가 제단의 네 뿔과 아래층 네 모퉁이와 사방 가장자리에 발라 속죄하여 제단을 정결하게 하고\n겔43:21 그 속죄제물의 수송아지를 가져다가 성전의 정한 처소 곧 성소 밖에서 불사를지며\n겔43:22 다음 날에는 흠 없는 숫염소 한 마리를 속죄제물로 삼아 드려서 그 제단을 정결하게 하기를 수송아지로 정결하게 함과 같이 하고\n겔43:23 정결하게 하기를 마친 후에는 흠 없는 수송아지 한 마리와 떼 가운데에서 흠 없는 숫양 한 마리를 드리되\n겔43:24 나 여호와 앞에 받들어다가 제사장은 그 위에 소금을 쳐서 나 여호와께 번제로 드릴 것이며\n겔43:25 칠 일 동안은 매일 염소 한 마리를 갖추어 속죄제물을 삼고 또 어린 수송아지 한 마리와 떼 가운데에서 숫양 한 마리를 흠 없는 것으로 갖출 것이며\n겔43:26 이같이 칠 일 동안 제단을 위하여 속죄제를 드려 정결하게 하며 드릴 것이요\n겔43:27 이 모든 날이 찬 후 제팔일과 그 다음에는 제사장이 제단 위에서 너희 번제와 감사제를 드릴 것이라 그리하면 내가 너희를 즐겁게 받으리라 주 여호와의 말씀이니라' WHERE date = '2027-08-05';
UPDATE public.qt_plans SET text = E'겔44:1  그가 나를 데리고 성소의 동쪽을 향한 바깥 문에 돌아오시니 그 문이 닫혔더라\n겔44:2 여호와께서 내게 이르시되 이 문은 닫고 다시 열지 못할지니 아무도 그리로 들어오지 못할 것은 이스라엘 하나님 나 여호와가 그리로 들어왔음이라 그러므로 닫아 둘지니라\n겔44:3 왕은 왕인 까닭에 안 길로 이 문 현관으로 들어와서 거기에 앉아서 나 여호와 앞에서 음식을 먹고 그 길로 나갈 것이니라\n겔44:4  그가 또 나를 데리고 북문을 통하여 성전 앞에 이르시기로 내가 보니 여호와의 영광이 여호와의 성전에 가득한지라 내가 얼굴을 땅에 대고 엎드리니\n겔44:5 여호와께서 내게 이르시되 인자야 너는 전심으로 주목하여 내가 네게 말하는 바 여호와의 성전의 모든 규례와 모든 율례를 귀로 듣고 또 성전의 입구와 성소의 출구를 전심으로 주목하고\n겔44:6 너는 반역하는 자 곧 이스라엘 족속에게 이르기를 주 여호와께서 이같이 말씀하시기를 이스라엘 족속아 너희의 모든 가증한 일이 족하니라\n겔44:7 너희가 마음과 몸에 할례 받지 아니한 이방인을 데려오고 내 떡과 기름과 피를 드릴 때에 그들로 내 성소 안에 있게 하여 내 성전을 더럽히므로 너희의 모든 가증한 일 외에 그들이 내 언약을 위반하게 하는 것이 되었으며\n겔44:8 너희가 내 성물의 직분을 지키지 아니하고 내 성소에 사람을 두어 너희 직분을 대신 지키게 하였느니라\n겔44:9  주 여호와께서 이같이 말씀하셨느니라 이스라엘 족속 중에 있는 이방인 중에 마음과 몸에 할례를 받지 아니한 이방인은 내 성소에 들어오지 못하리라\n겔44:10 이스라엘 족속이 그릇 행하여 나를 떠날 때에 레위 사람도 그릇 행하여 그 우상을 따라 나를 멀리 떠났으니 그 죄악을 담당하리라\n겔44:11 그러나 그들이 내 성소에서 수종들어 성전 문을 맡을 것이며 성전에서 수종들어 백성의 번제의 희생물과 다른 희생물을 잡아 백성 앞에 서서 수종들게 되리라\n겔44:12 그들이 전에 백성을 위하여 그 우상 앞에서 수종들어 이스라엘 족속이 죄악에 걸려 넘어지게 하였으므로 내가 내 손을 들어 쳐서 그들이 그 죄악을 담당하였느니라 주 여호와의 말씀이니라\n겔44:13 그들이 내게 가까이 나아와 제사장의 직분을 행하지 못하며 또 내 성물 곧 지성물에 가까이 오지 못하리니 그들이 자기의 수치와 그 행한 바 가증한 일을 담당하리라\n겔44:14 그러나 내가 그들을 세워 성전을 지키게 하고 성전에 모든 수종드는 일과 그 가운데에서 행하는 모든 일을 맡기리라\n겔44:15  이스라엘 족속이 그릇 행하여 나를 떠날 때에 사독의 자손 레위 사람 제사장들은 내 성소의 직분을 지켰은즉 그들은 내게 가까이 나아와 수종을 들되 내 앞에 서서 기름과 피를 내게 드릴지니라 주 여호와의 말씀이니라\n겔44:16 그들이 내 성소에 들어오며 또 내 상에 가까이 나아와 내게 수종들어 내가 맡긴 직분을 지키되\n겔44:17 그들이 안뜰 문에 들어올 때에나 안뜰 문과 성전 안에서 수종들 때에는 양털 옷을 입지 말고 가는 베 옷을 입을 것이니\n겔44:18 가는 베 관을 머리에 쓰며 가는 베 바지를 입고 땀이 나게 하는 것으로 허리를 동이지 말 것이며\n겔44:19 그들이 바깥뜰 백성에게로 나갈 때에는 수종드는 옷을 벗어 거룩한 방에 두고 다른 옷을 입을지니 이는 그 옷으로 백성을 거룩하게 할까 함이라\n겔44:20 그들은 또 머리털을 밀지도 말며 머리털을 길게 자라게도 말고 그 머리털을 깎기만 할 것이며\n겔44:21 아무 제사장이든지 안뜰에 들어갈 때에는 포도주를 마시지 말 것이며\n겔44:22 과부나 이혼한 여인에게 장가 들지 말고 오직 이스라엘 족속의 처녀나 혹시 제사장의 과부에게 장가 들 것이며\n겔44:23 내 백성에게 거룩한 것과 속된 것의 구별을 가르치며 부정한 것과 정한 것을 분별하게 할 것이며\n겔44:24 송사하는 일을 재판하되 내 규례대로 재판할 것이며 내 모든 정한 절기에는 내 법도와 율례를 지킬 것이며 또 내 안식일을 거룩하게 하며\n겔44:25 시체를 가까이 하여 스스로 더럽히지 못할 것이로되 부모나 자녀나 형제나 시집 가지 아니한 자매를 위하여는 더럽힐 수 있으며\n겔44:26 이런 자는 스스로 정결하게 한 후에 칠 일을 더 지낼 것이요\n겔44:27 성소에서 수종들기 위해 안뜰과 성소에 들어갈 때에는 속죄제를 드릴지니라 주 여호와의 말씀이니라\n겔44:28 그들에게는 기업이 있으리니 내가 곧 그 기업이라 너희는 이스라엘 가운데에서 그들에게 산업을 주지 말라 내가 그 산업이 됨이라\n겔44:29 그들은 소제와 속죄제와 속건제의 제물을 먹을지니 이스라엘 중에서 구별하여 드리는 물건을 다 그들에게 돌리며\n겔44:30 또 각종 처음 익은 열매와 너희 모든 예물 중에 각종 거제 제물을 다 제사장에게 돌리고 너희가 또 첫 밀가루를 제사장에게 주어 그들에게 네 집에 복이 내리도록 하게 하라\n겔44:31 새나 가축이 저절로 죽은 것이나 찢겨서 죽은 것은 다 제사장이 먹지 말 것이니라' WHERE date = '2027-08-06';
UPDATE public.qt_plans SET text = E'겔45:1  너희는 제비 뽑아 땅을 나누어 기업으로 삼을 때에 한 구역을 거룩한 땅으로 삼아 여호와께 예물로 드릴지니 그 길이는 이만 오천 척이요 너비는 만 척이라 그 구역 안 전부가 거룩하리라\n겔45:2 그 중에서 성소에 속할 땅은 길이가 오백 척이요 너비가 오백 척이니 네모가 반듯하며 그 외에 사방 쉰 척으로 전원이 되게 하되\n겔45:3 이 측량한 가운데에서 길이는 이만 오천 척을 너비는 만 척을 측량하고 그 안에 성소를 둘지니 지극히 거룩한 곳이요\n겔45:4 그 곳은 성소에서 수종드는 제사장들 곧 하나님께 가까이 나아가서 수종드는 자들에게 주는 거룩한 땅이니 그들이 집을 지을 땅이며 성소를 위한 거룩한 곳이라\n겔45:5 또 길이는 이만 오천 척을 너비는 만 척을 측량하여 성전에서 수종드는 레위 사람에게 돌려 그들의 거주지를 삼아 마을 스물을 세우게 하고\n겔45:6 구별한 거룩한 구역 옆에 너비는 오천 척을 길이는 이만 오천 척을 측량하여 성읍의 기지로 삼아 이스라엘 온 족속에게 돌리고\n겔45:7 드린 거룩한 구역과 성읍의 기지 된 땅의 좌우편 곧 드린 거룩한 구역의 옆과 성읍의 기지 옆의 땅을 왕에게 돌리되 서쪽으로 향하여 서쪽 국경까지와 동쪽으로 향하여 동쪽 국경까지니 그 길이가 구역 하나와 서로 같을지니라\n겔45:8 이 땅을 왕에게 돌려 이스라엘 가운데에 기업으로 삼게 하면 나의 왕들이 다시는 내 백성을 압제하지 아니하리라 그 나머지 땅은 이스라엘 족속에게 그 지파대로 줄지니라\n겔45:9  주 여호와께서 이같이 말씀하셨느니라 이스라엘의 통치자들아 너희에게 만족하니라 너희는 포악과 겁탈을 제거하여 버리고 정의와 공의를 행하여 내 백성에게 속여 빼앗는 것을 그칠지니라 주 여호와의 말씀이니라\n겔45:10 너희는 공정한 저울과 공정한 에바와 공정한 밧을 쓸지니\n겔45:11 에바와 밧은 그 용량을 동일하게 하되 호멜의 용량을 따라 밧은 십분의 일 호멜을 담게 하고 에바도 십분의 일 호멜을 담게 할 것이며\n겔45:12 세겔은 이십 게라니 이십 세겔과 이십오 세겔과 십오 세겔로 너희 마네가 되게 하라\n겔45:13 너희가 마땅히 드릴 예물은 이러하니 밀 한 호멜에서는 육분의 일 에바를 드리고 보리 한 호멜에서도 육분의 일 에바를 드리며\n겔45:14 기름은 정한 규례대로 한 고르에서 십분의 일 밧을 드릴지니 기름의 밧으로 말하면 한 고르는 십 밧 곧 한 호멜이며 (십 밧은 한 호멜이라)\n겔45:15 또 이스라엘의 윤택한 초장의 가축 떼 이백 마리에서는 어린 양 한 마리를 드릴 것이라 백성을 속죄하기 위하여 이것들을 소제와 번제와 감사 제물로 삼을지니라 주 여호와의 말씀이니라\n겔45:16 이 땅 모든 백성은 이 예물을 이스라엘의 군주에게 드리고\n겔45:17 군주의 본분은 번제와 소제와 전제를 명절과 초하루와 안식일과 이스라엘 족속의 모든 정한 명절에 갖추는 것이니 이스라엘 족속을 속죄하기 위하여 이 속죄제와 소제와 번제와 감사 제물을 갖출지니라\n겔45:18  여호와께서 이같이 말씀하셨느니라 첫째 달 초하룻날에 흠 없는 수송아지 한 마리를 가져다가 성소를 정결하게 하되\n겔45:19 제사장이 그 속죄제 희생제물의 피를 가져다가 성전 문설주와 제단 아래층 네 모퉁이와 안뜰 문설주에 바를 것이요\n겔45:20 그 달 칠일에도 모든 과실범과 모르고 범죄한 자를 위하여 역시 그렇게 하여 성전을 속죄할지니라\n겔45:21 첫째 달 열나흗날에는 유월절을 칠 일 동안 명절로 지키며 누룩 없는 떡을 먹을 것이라\n겔45:22 그 날에 왕은 자기와 이 땅 모든 백성을 위하여 송아지 한 마리를 갖추어 속죄제를 드릴 것이요\n겔45:23 또 명절 칠 일 동안에는 그가 나 여호와를 위하여 번제를 준비하되 곧 이레 동안에 매일 흠 없는 수송아지 일곱 마리와 숫양 일곱 마리이며 또 매일 숫염소 한 마리를 갖추어 속죄제를 드릴 것이며\n겔45:24 또 소제를 갖추되 수송아지 한 마리에는 밀가루 한 에바요 숫양 한 마리에도 한 에바며 밀가루 한 에바에는 기름 한 힌 씩이며\n겔45:25 일곱째 달 열다섯째 날에 칠 일 동안 명절을 지켜 속죄제와 번제며 그 밀가루와 기름을 드릴지니라' WHERE date = '2027-08-07';
UPDATE public.qt_plans SET text = E'겔46:1  주 여호와께서 이같이 말씀하셨느니라 안뜰 동쪽을 향한 문은 일하는 엿새 동안에는 닫되 안식일에는 열며 초하루에도 열고\n겔46:2 군주는 바깥 문 현관을 통하여 들어와서 문 벽 곁에 서고 제사장은 그를 위하여 번제와 감사제를 드릴 것이요 군주는 문 통로에서 예배한 후에 밖으로 나가고 그 문은 저녁까지 닫지 말 것이며\n겔46:3 이 땅 백성도 안식일과 초하루에 이 문 입구에서 나 여호와 앞에 예배할 것이며\n겔46:4 안식일에 군주가 여호와께 드릴 번제는 흠 없는 어린 양 여섯 마리와 흠 없는 숫양 한 마리라\n겔46:5 그 소제는 숫양 하나에는 밀가루 한 에바요 모든 어린 양에는 그 힘대로 할 것이며 밀가루 한 에바에는 기름 한 힌 씩이니라\n겔46:6 초하루에는 흠 없는 수송아지 한 마리와 어린 양 여섯 마리와 숫양 한 마리를 드리되 모두 흠 없는 것으로 할 것이며\n겔46:7 또 소제를 준비하되 수송아지에는 밀가루 한 에바요 숫양에도 밀가루 한 에바며 모든 어린 양에는 그 힘대로 할 것이요 밀가루 한 에바에는 기름 한 힌씩이며\n겔46:8 군주가 올 때에는 이 문 현관을 통하여 들어오고 나갈 때에도 그리할지니라\n겔46:9 그러나 모든 정한 절기에 이 땅 백성이 나 여호와 앞에 나아올 때에는 북문으로 들어와서 경배하는 자는 남문으로 나가고 남문으로 들어오는 자는 북문으로 나갈지라 들어온 문으로 도로 나가지 말고 그 몸이 앞으로 향한 대로 나갈지며\n겔46:10 군주가 무리 가운데에 있어서 그들이 들어올 때에 들어오고 그들이 나갈 때에 나갈지니라\n겔46:11 명절과 성회 때에 그 소제는 수송아지 한 마리에 밀가루 한 에바요 숫양 한 마리에도 한 에바요 모든 어린 양에는 그 힘대로 할 것이며 밀가루 한 에바에는 기름 한 힌씩이며\n겔46:12 만일 군주가 자원하여 번제를 준비하거나 혹은 자원하여 감사제를 준비하여 나 여호와께 드릴 때에는 그를 위하여 동쪽을 향한 문을 열고 그가 번제와 감사제를 안식일에 드림 같이 드리고 밖으로 나갈지며 나간 후에 문을 닫을지니라\n겔46:13  아침마다 일년 되고 흠 없는 어린 양 한 마리를 번제를 갖추어 나 여호와께 드리고\n겔46:14 또 아침마다 그것과 함께 드릴 소제를 갖추되 곧 밀가루 육분의 일 에바와 기름 삼분의 일 힌을 섞을 것이니 이는 영원한 규례로 삼아 항상 나 여호와께 드릴 소제라\n겔46:15 이같이 아침마다 그 어린 양과 밀가루와 기름을 준비하여 항상 드리는 번제물로 삼을지니라\n겔46:16  주 여호와께서 이같이 말씀하셨느니라 군주가 만일 한 아들에게 선물을 준즉 그의 기업이 되어 그 자손에게 속하나니 이는 그 기업을 이어 받음이어니와\n겔46:17 군주가 만일 그 기업을 한 종에게 선물로 준즉 그 종에게 속하여 희년까지 이르고 그 후에는 군주에게로 돌아갈 것이니 군주의 기업은 그 아들이 이어 받을 것임이라\n겔46:18 군주는 백성의 기업을 빼앗아 그 산업에서 쫓아내지 못할지니 군주가 자기 아들에게 기업으로 줄 것은 자기 산업으로만 할 것임이라 백성이 각각 그 산업을 떠나 흩어지지 않게 할 것이니라\n겔46:19  그 후에 그가 나를 데리고 문 곁 통행구를 통하여 북쪽을 향한 제사장의 거룩한 방에 들어가시니 그 방 뒤 서쪽에 한 처소가 있더라\n겔46:20 그가 내게 이르시되 이는 제사장이 속건제와 속죄제 희생제물을 삶으며 소제 제물을 구울 처소니 그들이 이 성물을 가지고 바깥뜰에 나가면 백성을 거룩하게 할까 함이니라 하시고\n겔46:21 나를 데리고 바깥뜰로 나가서 나를 뜰 네 구석을 지나가게 하시는데 본즉 그 뜰 매 구석에 또 뜰이 있는데\n겔46:22 뜰의 네 구석 안에는 집이 있으니 길이는 마흔 척이요 너비는 서른 척이라 구석의 네 뜰이 같은 크기며\n겔46:23 그 작은 네 뜰 사방으로 돌아가며 부엌이 있고 그 사방 부엌에 삶는 기구가 설비되었는데\n겔46:24 그가 내게 이르시되 이는 삶는 부엌이니 성전에서 수종드는 자가 백성의 제물을 여기서 삶을 것이니라 하시더라' WHERE date = '2027-08-09';
UPDATE public.qt_plans SET text = E'단7:1  바벨론 벨사살 왕 원년에 다니엘이 그의 침상에서 꿈을 꾸며 머리 속으로 환상을 받고 그 꿈을 기록하며 그 일의 대략을 진술하니라\n단7:2 다니엘이 진술하여 이르되 내가 밤에 환상을 보았는데 하늘의 네 바람이 큰 바다로 몰려 불더니\n단7:3 큰 짐승 넷이 바다에서 나왔는데 그 모양이 각각 다르더라\n단7:4 첫째는 사자와 같은데 독수리의 날개가 있더니 내가 보는 중에 그 날개가 뽑혔고 또 땅에서 들려서 사람처럼 두 발로 서게 함을 받았으며 또 사람의 마음을 받았더라 또 보니\n단7:5 다른 짐승 곧 둘째는 곰과 같은데 그것이 몸 한쪽을 들었고 그 입의 잇사이에는 세 갈빗대가 물렸는데 그것에게 말하는 자들이 있어 이르기를 일어나서 많은 고기를 먹으라 하였더라\n단7:6 그 후에 내가 또 본즉 다른 짐승 곧 표범과 같은 것이 있는데 그 등에는 새의 날개 넷이 있고 그 짐승에게 또 머리 넷이 있으며 권세를 받았더라\n단7:7 내가 밤 환상 가운데에 그 다음에 본 넷째 짐승은 무섭고 놀라우며 또 매우 강하며 또 쇠로 된 큰 이가 있어서 먹고 부서뜨리고 그 나머지를 발로 밟았으며 이 짐승은 전의 모든 짐승과 다르고 또 열 뿔이 있더라\n단7:8 내가 그 뿔을 유심히 보는 중에 다른 작은 뿔이 그 사이에서 나더니 첫 번째 뿔 중의 셋이 그 앞에서 뿌리까지 뽑혔으며 이 작은 뿔에는 사람의 눈 같은 눈들이 있고 또 입이 있어 큰 말을 하였더라\n단7:9  내가 보니 왕좌가 놓이고 옛적부터 항상 계신 이가 좌정하셨는데 그의 옷은 희기가 눈 같고 그의 머리털은 깨끗한 양의 털 같고 그의 보좌는 불꽃이요 그의 바퀴는 타오르는 불이며\n단7:10 불이 강처럼 흘러 그의 앞에서 나오며 그를 섬기는 자는 천천이요 그 앞에서 모셔 선 자는 만만이며 심판을 베푸는데 책들이 펴 놓였더라\n단7:11 그 때에 내가 작은 뿔이 말하는 큰 목소리로 말미암아 주목하여 보는 사이에 짐승이 죽임을 당하고 그의 시체가 상한 바 되어 타오르는 불에 던져졌으며\n단7:12 그 남은 짐승들은 그의 권세를 빼앗겼으나 그 생명은 보존되어 정한 시기가 이르기를 기다리게 되었더라\n단7:13 내가 또 밤 환상 중에 보니 인자 같은 이가 하늘 구름을 타고 와서 옛적부터 항상 계신 이에게 나아가 그 앞으로 인도되매\n단7:14 그에게 권세와 영광과 나라를 주고 모든 백성과 나라들과 다른 언어를 말하는 모든 자들이 그를 섬기게 하였으니 그의 권세는 소멸되지 아니하는 영원한 권세요 그의 나라는 멸망하지 아니할 것이니라\n단7:15  나 다니엘이 중심에 근심하며 내 머리 속의 환상이 나를 번민하게 한지라\n단7:16 내가 그 곁에 모셔 선 자들 중 하나에게 나아가서 이 모든 일의 진상을 물으매 그가 내게 말하여 그 일의 해석을 알려 주며 이르되\n단7:17 그 네 큰 짐승은 세상에 일어날 네 왕이라\n단7:18 지극히 높으신 이의 성도들이 나라를 얻으리니 그 누림이 영원하고 영원하고 영원하리라\n단7:19 이에 내가 넷째 짐승에 관하여 확실히 알고자 하였으니 곧 그것은 모든 짐승과 달라서 심히 무섭더라 그 이는 쇠요 그 발톱은 놋이니 먹고 부서뜨리고 나머지는 발로 밟았으며\n단7:20 또 그것의 머리에는 열 뿔이 있고 그 외에 또 다른 뿔이 나오매 세 뿔이 그 앞에서 빠졌으며 그 뿔에는 눈도 있고 큰 말을 하는 입도 있고 그 모양이 그의 동류보다 커 보이더라\n단7:21 내가 본즉 이 뿔이 성도들과 더불어 싸워 그들에게 이겼더니\n단7:22 옛적부터 항상 계신 이가 와서 지극히 높으신 이의 성도들을 위하여 원한을 풀어 주셨고 때가 이르매 성도들이 나라를 얻었더라\n단7:23 모신 자가 이처럼 이르되 넷째 짐승은 곧 땅의 넷째 나라인데 이는 다른 나라들과는 달라서 온 천하를 삼키고 밟아 부서뜨릴 것이며\n단7:24 그 열 뿔은 그 나라에서 일어날 열 왕이요 그 후에 또 하나가 일어나리니 그는 먼저 있던 자들과 다르고 또 세 왕을 복종시킬 것이며\n단7:25 그가 장차 지극히 높으신 이를 말로 대적하며 또 지극히 높으신 이의 성도를 괴롭게 할 것이며 그가 또 때와 법을 고치고자 할 것이며 성도들은 그의 손에 붙인 바 되어 한 때와 두 때와 반 때를 지내리라\n단7:26 그러나 심판이 시작되면 그는 권세를 빼앗기고 완전히 멸망할 것이요\n단7:27 나라와 권세와 온 천하 나라들의 위세가 지극히 높으신 이의 거룩한 백성에게 붙인 바 되리니 그의 나라는 영원한 나라이라 모든 권세 있는 자들이 다 그를 섬기며 복종하리라\n단7:28 그 말이 이에 그친지라 나 다니엘은 중심에 번민하였으며 내 얼굴빛이 변하였으나 내가 이 일을 마음에 간직하였느니라' WHERE date = '2027-08-10';
UPDATE public.qt_plans SET text = E'단8:1  나 다니엘에게 처음에 나타난 환상 후 벨사살 왕 제삼년에 다시 한 환상이 나타나니라\n단8:2 내가 환상을 보았는데 내가 그것을 볼 때에 내 몸은 엘람 지방 수산 성에 있었고 내가 환상을 보기는 을래 강변에서이니라\n단8:3 내가 눈을 들어 본즉 강 가에 두 뿔 가진 숫양이 섰는데 그 두 뿔이 다 길었으며 그 중 한 뿔은 다른 뿔보다 길었고 그 긴 것은 나중에 난 것이더라\n단8:4 내가 본즉 그 숫양이 서쪽과 북쪽과 남쪽을 향하여 받으나 그것을 당할 짐승이 하나도 없고 그 손에서 구할 자가 없으므로 그것이 원하는 대로 행하고 강하여졌더라\n단8:5 내가 생각할 때에 한 숫염소가 서쪽에서부터 와서 온 지면에 두루 다니되 땅에 닿지 아니하며 그 염소의 두 눈 사이에는 현저한 뿔이 있더라\n단8:6 그것이 두 뿔 가진 숫양 곧 내가 본 바 강 가에 섰던 양에게로 나아가되 분노한 힘으로 그것에게로 달려가더니\n단8:7 내가 본즉 그것이 숫양에게로 가까이 나아가서는 더욱 성내어 그 숫양을 쳐서 그 두 뿔을 꺾으나 숫양에게는 그것을 대적할 힘이 없으므로 그것이 숫양을 땅에 엎드러뜨리고 짓밟았으나 숫양을 그 손에서 벗어나게 할 자가 없었더라\n단8:8 숫염소가 스스로 심히 강대하여 가더니 강성할 때에 그 큰 뿔이 꺾이고 그 대신에 현저한 뿔 넷이 하늘 사방을 향하여 났더라\n단8:9 그 중 한 뿔에서 또 작은 뿔 하나가 나서 남쪽과 동쪽과 또 영화로운 땅을 향하여 심히 커지더니\n단8:10 그것이 하늘 군대에 미칠 만큼 커져서 그 군대와 별들 중의 몇을 땅에 떨어뜨리고 그것들을 짓밟고\n단8:11 또 스스로 높아져서 군대의 주재를 대적하며 그에게 매일 드리는 제사를 없애 버렸고 그의 성소를 헐었으며\n단8:12 그의 악으로 말미암아 백성이 매일 드리는 제사가 넘긴 바 되었고 그것이 또 진리를 땅에 던지며 자의로 행하여 형통하였더라\n단8:13 내가 들은즉 한 거룩한 이가 말하더니 다른 거룩한 이가 그 말하는 이에게 묻되 환상에 나타난 바 매일 드리는 제사와 망하게 하는 죄악에 대한 일과 성소와 백성이 내준 바 되며 짓밟힐 일이 어느 때까지 이를꼬 하매\n단8:14 그가 내게 이르되 이천삼백 주야까지니 그 때에 성소가 정결하게 되리라 하였느니라\n단8:15  나 다니엘이 이 환상을 보고 그 뜻을 알고자 할 때에 사람 모양 같은 것이 내 앞에 섰고\n단8:16 내가 들은즉 을래 강 두 언덕 사이에서 사람의 목소리가 있어 외쳐 이르되 가브리엘아 이 환상을 이 사람에게 깨닫게 하라 하더니\n단8:17 그가 내가 선 곳으로 나왔는데 그가 나올 때에 내가 두려워서 얼굴을 땅에 대고 엎드리매 그가 내게 이르되 인자야 깨달아 알라 이 환상은 정한 때 끝에 관한 것이니라\n단8:18 그가 내게 말할 때에 내가 얼굴을 땅에 대고 엎드리어 깊이 잠들매 그가 나를 어루만져서 일으켜 세우며\n단8:19 이르되 진노하시는 때가 마친 후에 될 일을 내가 네게 알게 하리니 이 환상은 정한 때 끝에 관한 것임이라\n단8:20 네가 본 바 두 뿔 가진 숫양은 곧 메대와 바사 왕들이요\n단8:21 털이 많은 숫염소는 곧 헬라 왕이요 그의 두 눈 사이에 있는 큰 뿔은 곧 그 첫째 왕이요\n단8:22 이 뿔이 꺾이고 그 대신에 네 뿔이 났은즉 그 나라 가운데에서 네 나라가 일어나되 그의 권세만 못하리라\n단8:23 이 네 나라 마지막 때에 반역자들이 가득할 즈음에 한 왕이 일어나리니 그 얼굴은 뻔뻔하며 속임수에 능하며\n단8:24 그 권세가 강할 것이나 자기의 힘으로 말미암은 것이 아니며 그가 장차 놀랍게 파괴 행위를 하고 자의로 행하여 형통하며 강한 자들과 거룩한 백성을 멸하리라\n단8:25 그가 꾀를 베풀어 제 손으로 속임수를 행하고 마음에 스스로 큰 체하며 또 평화로운 때에 많은 무리를 멸하며 또 스스로 서서 만왕의 왕을 대적할 것이나 그가 사람의 손으로 말미암지 아니하고 깨지리라\n단8:26 이미 말한 바 주야에 대한 환상은 확실하니 너는 그 환상을 간직하라 이는 여러 날 후의 일임이라 하더라\n단8:27 이에 나 다니엘이 지쳐서 여러 날 앓다가 일어나서 왕의 일을 보았느니라 내가 그 환상으로 말미암아 놀랐고 그 뜻을 깨닫는 사람도 없었느니라' WHERE date = '2027-08-11';
UPDATE public.qt_plans SET text = E'스1:2 바사 왕 고레스는 말하노니 하늘의 하나님 여호와께서 세상 모든 나라를 내게 주셨고 나에게 명령하사 유다 예루살렘에 성전을 건축하라 하셨나니\n스1:3 이스라엘의 하나님은 참 신이시라 너희 중에 그의 백성 된 자는 다 유다 예루살렘으로 올라가서 이스라엘의 하나님 여호와의 성전을 건축하라 그는 예루살렘에 계신 하나님이시라\n스1:4 그 남아 있는 백성이 어느 곳에 머물러 살든지 그 곳 사람들이 마땅히 은과 금과 그 밖의 물건과 짐승으로 도와 주고 그 외에도 예루살렘에 세울 하나님의 성전을 위하여 예물을 기쁘게 드릴지니라 하였더라\n스1:5  이에 유다와 베냐민 족장들과 제사장들과 레위 사람들과 그 마음이 하나님께 감동을 받고 올라가서 예루살렘에 여호와의 성전을 건축하고자 하는 자가 다 일어나니\n스1:6 그 사면 사람들이 은 그릇과 금과 물품들과 짐승과 보물로 돕고 그 외에도 예물을 기쁘게 드렸더라\n스1:7 고레스 왕이 또 여호와의 성전 그릇을 꺼내니 옛적에 느부갓네살이 예루살렘에서 옮겨다가 자기 신들의 신당에 두었던 것이라\n스1:8 바사 왕 고레스가 창고지기 미드르닷에게 명령하여 그 그릇들을 꺼내어 세어서 유다 총독 세스바살에게 넘겨주니\n스1:9 그 수는 금 접시가 서른 개요 은 접시가 천 개요 칼이 스물아홉 개요\n스1:10 금 대접이 서른 개요 그보다 못한 은 대접이 사백열 개요 그밖의 그릇이 천 개이니\n스1:11 금, 은 그릇이 모두 오천사백 개라 사로잡힌 자를 바벨론에서 예루살렘으로 데리고 갈 때에 세스바살이 그 그릇들을 다 가지고 갔더라' WHERE date = '2027-08-12';
UPDATE public.qt_plans SET text = E'스2:1  옛적에 바벨론 왕 느부갓네살에게 사로잡혀 바벨론으로 갔던 자들의 자손들 중에서 놓임을 받고 예루살렘과 유다 도로 돌아와 각기 각자의 성읍으로 돌아간 자\n스2:2 곧 스룹바벨과 예수아와 느헤미야와 스라야와 르엘라야와 모르드개와 빌산과 미스발과 비그왜와 르훔과 바아나 등과 함께 나온 이스라엘 백성의 명수가 이러하니\n스2:3 바로스 자손이 이천백칠십이 명이요\n스2:4 스바댜 자손이 삼백칠십이 명이요\n스2:5 아라 자손이 칠백칠십오 명이요\n스2:6 바핫모압 자손 곧 예수아와 요압 자손이 이천팔백십이 명이요\n스2:7 엘람 자손이 천이백오십사 명이요\n스2:8 삿두 자손이 구백사십오 명이요\n스2:9 삭개 자손이 칠백육십 명이요\n스2:10 바니 자손이 육백사십이 명이요\n스2:11 브배 자손이 육백이십삼 명이요\n스2:12 아스갓 자손이 천이백이십이 명이요\n스2:13 아도니감 자손이 육백육십육 명이요\n스2:14 비그왜 자손이 이천오십육 명이요\n스2:15 아딘 자손이 사백오십사 명이요\n스2:16 아델 자손 곧 히스기야 자손이 구십팔 명이요\n스2:17 베새 자손이 삼백이십삼 명이요\n스2:18 요라 자손이 백십이 명이요\n스2:19 하숨 자손이 이백이십삼 명이요\n스2:20 깁발 자손이 구십오 명이요\n스2:21 베들레헴 사람이 백이십삼 명이요\n스2:22 느도바 사람이 오십육 명이요\n스2:23 아나돗 사람이 백이십팔 명이요\n스2:24 아스마? 자손이 사십이 명이요\n스2:25 기랴다림과 그비라와 브에롯 자손이 칠백사십삼 명이요\n스2:26 라마와 게바 자손이 육백이십일 명이요\n스2:27 믹마스 사람이 백이십이 명이요\n스2:28 벧엘과 아이 사람이 이백이십삼 명이요\n스2:29 느보 자손이 오십이 명이요\n스2:30 막비스 자손이 백오십육 명이요\n스2:31 다른 엘람 자손이 천이백오십사 명이요\n스2:32 하림 자손이 삼백이십 명이요\n스2:33 로드와 하딧과 오노 자손이 칠백이십오 명이요\n스2:34 여리고 자손이 삼백사십오 명이요\n스2:35 스나아 자손이 삼천육백삼십 명이었더라\n스2:36 제사장들은 예수아의 집 여다야 자손이 구백칠십삼 명이요\n스2:37 임멜 자손이 천오십이 명이요\n스2:38 바스훌 자손이 천이백사십칠 명이요\n스2:39 하림 자손이 천십칠 명이었더라\n스2:40 레위 사람은 호다위야 자손 곧 예수아와 갓미엘 자손이 칠십사 명이요\n스2:41 노래하는 자들은 아삽 자손이 백이십팔 명이요\n스2:42 문지기의 자손들은 살룸과 아델과 달문과 악굽과 하디다와 소배 자손이 모두 백삼십구 명이었더라\n스2:43 느디님 사람들은 시하 자손과 하수바 자손과 답바옷 자손과\n스2:44 게로스 자손과 시아하 자손과 바돈 자손과\n스2:45 르바나 자손과 하가바 자손과 악굽 자손과\n스2:46 하갑 자손과 사믈래 자손과 하난 자손과\n스2:47 깃델 자손과 가할 자손과 르아야 자손과\n스2:48 르신 자손과 느고다 자손과 갓삼 자손과\n스2:49 웃사 자손과 바세아 자손과 베새 자손과\n스2:50 아스나 자손과 므우님 자손과 느부심 자손과\n스2:51 박북 자손과 하그바 자손과 할훌 자손과\n스2:52 바슬룻 자손과 므히다 자손과 하르사 자손과\n스2:53 바르고스 자손과 시스라 자손과 데마 자손과\n스2:54 느시야 자손과 하디바 자손이었더라\n스2:55 솔로몬의 신하의 자손은 소대 자손과 하소베렛 자손과 브루다 자손과\n스2:56 야알라 자손과 다르곤 자손과 깃델 자손과\n스2:57 스바댜 자손과 하딜 자손과 보게렛하스바임 자손과 아미 자손이니\n스2:58 모든 느디님 사람과 솔로몬의 신하의 자손이 삼백구십이 명이었더라\n스2:59 델멜라와 델하르사와 그룹과 앗단과 임멜에서 올라온 자가 있으나 그들의 조상의 가문과 선조가 이스라엘에 속하였는지 밝힐 수 없었더라\n스2:60 그들은 들라야 자손과 도비야 자손과 느고다 자손이라 모두 육백오십이 명이요\n스2:61 제사장 중에는 하바야 자손과 학고스 자손과 바르실래 자손이니 바르실래는 길르앗 사람 바르실래의 딸 중의 한 사람을 아내로 삼고 바르실래의 이름을 따른 자라\n스2:62 이 사람들은 계보 중에서 자기 이름을 찾아도 얻지 못하므로 그들을 부정하게 여겨 제사장의 직분을 행하지 못하게 하고\n스2:63 방백이 그들에게 명령하여 우림과 둠밈을 가진 제사장이 일어나기 전에는 지성물을 먹지 말라 하였느니라\n스2:64 온 회중의 합계가 사만 이천삼백육십 명이요\n스2:65 그 외에 남종과 여종이 칠천삼백삼십칠 명이요 노래하는 남녀가 이백 명이요\n스2:66 말이 칠백삼십육이요 노새가 이백사십오요\n스2:67 낙타가 사백삼십오요 나귀가 육천칠백이십이었더라\n스2:68 어떤 족장들이 예루살렘에 있는 여호와의 성전 터에 이르러 하나님의 전을 그 곳에 다시 건축하려고 예물을 기쁘게 드리되\n스2:69 힘 자라는 대로 공사하는 금고에 들이니 금이 육만 천 다릭이요 은이 오천 마네요 제사장의 옷이 백 벌이었더라\n스2:70 이에 제사장들과 레위 사람들과 백성 몇과 노래하는 자들과 문지기들과 느디님 사람들이 각자의 성읍에 살았고 이스라엘 무리도 각자의 성읍에 살았더라' WHERE date = '2027-08-13';
UPDATE public.qt_plans SET text = E'슥1:2 여호와가 너희의 조상들에게 심히 진노하였느니라\n슥1:3 그러므로 너는 그들에게 말하기를 만군의 여호와께서 이처럼 이르시되 너희는 내게로 돌아오라 만군의 여호와의 말이니라 그리하면 내가 너희에게로 돌아가리라 만군의 여호와의 말이니라\n슥1:4 너희 조상들을 본받지 말라 옛적 선지자들이 그들에게 외쳐 이르되 만군의 여호와께서 이같이 말씀하시기를 너희가 악한 길, 악한 행위를 떠나서 돌아오라 하셨으나 그들이 듣지 아니하고 내게 귀를 기울이지 아니하였느니라 여호와의 말이니라\n슥1:5 너희 조상들이 어디 있느냐 또 선지자들이 영원히 살겠느냐\n슥1:6 내가 나의 종 선지자들에게 명령한 내 말과 내 법도들이 어찌 너희 조상들에게 임하지 아니하였느냐 그러므로 그들이 돌이켜 이르기를 만군의 여호와께서 우리 길대로, 우리 행위대로 우리에게 행하시려고 뜻하신 것을 우리에게 행하셨도다 하였느니라\n슥1:7  다리오 왕 제이년 열한째 달 곧 스밧월 이십사일에 잇도의 손자 베레갸의 아들 선지자 스가랴에게 여호와의 말씀이 임하니라\n슥1:8 내가 밤에 보니 사람들이 붉은 말을 타고 골짜기 속 화석류나무 사이에 섰고 그 뒤에는 붉은 말과 자줏빛 말과 백마가 있기로\n슥1:9 내가 말하되 내 주여 이들이 무엇이니이까 하니 내게 말하는 천사가 내게 이르되 이들이 무엇인지 내가 네게 보이리라 하니\n슥1:10 화석류나무 사이에 선 자가 대답하여 이르되 이는 여호와께서 땅에 두루 다니라고 보내신 자들이니라\n슥1:11 그들이 화석류나무 사이에 선 여호와의 천사에게 말하되 우리가 땅에 두루 다녀 보니 온 땅이 평안하고 조용하더이다 하더라\n슥1:12 여호와의 천사가 대답하여 이르되 만군의 여호와여 여호와께서 언제까지 예루살렘과 유다 성읍들을 불쌍히 여기지 아니하시려 하나이까 이를 노하신 지 칠십 년이 되었나이다 하매\n슥1:13 여호와께서 내게 말하는 천사에게 선한 말씀, 위로하는 말씀으로 대답하시더라\n슥1:14 내게 말하는 천사가 내게 이르되 너는 외쳐 이르기를 만군의 여호와의 말씀에 내가 예루살렘을 위하며 시온을 위하여 크게 질투하며\n슥1:15 안일한 여러 나라들 때문에 심히 진노하나니 나는 조금 노하였거늘 그들은 힘을 내어 고난을 더하였음이라\n슥1:16 그러므로 여호와가 이처럼 말하노라 내가 불쌍히 여기므로 예루살렘에 돌아왔은즉 내 집이 그 가운데에 건축되리니 예루살렘 위에 먹줄이 쳐지리라 만군의 여호와의 말이니라\n슥1:17 그가 다시 외쳐 이르기를 만군의 여호와의 말씀에 나의 성읍들이 넘치도록 다시 풍부할 것이라 여호와가 다시 시온을 위로하며 다시 예루살렘을 택하리라 하라 하니라\n슥1:18  내가 눈을 들어 본즉 네 개의 뿔이 보이기로\n슥1:19 이에 내게 말하는 천사에게 묻되 이들이 무엇이니이까 하니 내게 대답하되 이들은 유다와 이스라엘과 예루살렘을 흩뜨린 뿔이니라\n슥1:20 그 때에 여호와께서 대장장이 네 명을 내게 보이시기로\n슥1:21 내가 말하되 그들이 무엇하러 왔나이까 하니 대답하여 이르시되 그 뿔들이 유다를 흩뜨려서 사람들이 능히 머리를 들지 못하게 하니 이 대장장이들이 와서 그것들을 두렵게 하고 이전의 뿔들을 들어 유다 땅을 흩뜨린 여러 나라의 뿔들을 떨어뜨리려 하느니라 하시더라' WHERE date = '2027-08-14';
UPDATE public.qt_plans SET text = E'슥2:1  내가 또 눈을 들어 본즉 한 사람이 측량줄을 그의 손에 잡았기로\n슥2:2 네가 어디로 가느냐 물은즉 그가 내게 대답하되 예루살렘을 측량하여 그 너비와 길이를 보고자 하노라 하고 말할 때에\n슥2:3 내게 말하는 천사가 나가고 다른 천사가 나와서 그를 맞으며\n슥2:4 이르되 너는 달려가서 그 소년에게 말하여 이르기를 예루살렘은 그 가운데 사람과 가축이 많으므로 성곽 없는 성읍이 될 것이라 하라\n슥2:5 여호와의 말씀에 내가 불로 둘러싼 성곽이 되며 그 가운데에서 영광이 되리라\n슥2:6 오호라 너희는 북방 땅에서 도피할지어다 여호와의 말씀이니라 이는 내가 너희를 하늘 사방에 바람 같이 흩어지게 하였음이니라 여호와의 말씀이니라\n슥2:7 바벨론 성에 거주하는 시온아 이제 너는 피할지니라\n슥2:8 만군의 여호와께서 이같이 말씀하시되 영광을 위하여 나를 너희를 노략한 여러 나라로 보내셨나니 너희를 범하는 자는 그의 눈동자를 범하는 것이라\n슥2:9 내가 손을 그들 위에 움직인즉 그들이 자기를 섬기던 자들에게 노략거리가 되리라 하셨나니 너희가 만군의 여호와께서 나를 보내신 줄 알리라\n슥2:10 여호와의 말씀에 시온의 딸아 노래하고 기뻐하라 이는 내가 와서 네 가운데에 머물 것임이라\n슥2:11 그 날에 많은 나라가 여호와께 속하여 내 백성이 될 것이요 나는 네 가운데에 머물리라 네가 만군의 여호와께서 나를 네게 보내신 줄 알리라\n슥2:12 여호와께서 장차 유다를 거룩한 땅에서 자기 소유를 삼으시고 다시 예루살렘을 택하시리니\n슥2:13 모든 육체가 여호와 앞에서 잠잠할 것은 여호와께서 그의 거룩한 처소에서 일어나심이니라 하라 하더라' WHERE date = '2027-08-16';
UPDATE public.qt_plans SET text = E'슥3:1  대제사장 여호수아는 여호와의 천사 앞에 섰고 사탄은 그의 오른쪽에 서서 그를 대적하는 것을 여호와께서 내게 보이시니라\n슥3:2 여호와께서 사탄에게 이르시되 사탄아 여호와께서 너를 책망하노라 예루살렘을 택한 여호와께서 너를 책망하노라 이는 불에서 꺼낸 그슬린 나무가 아니냐 하실 때에\n슥3:3 여호수아가 더러운 옷을 입고 천사 앞에 서 있는지라\n슥3:4 여호와께서 자기 앞에 선 자들에게 명령하사 그 더러운 옷을 벗기라 하시고 또 여호수아에게 이르시되 내가 네 죄악을 제거하여 버렸으니 네게 아름다운 옷을 입히리라 하시기로\n슥3:5 내가 말하되 정결한 관을 그의 머리에 씌우소서 하매 곧 정결한 관을 그 머리에 씌우며 옷을 입히고 여호와의 천사는 곁에 섰더라\n슥3:6 여호와의 천사가 여호수아에게 증언하여 이르되\n슥3:7 만군의 여호와의 말씀에 네가 만일 내 도를 행하며 내 규례를 지키면 네가 내 집을 다스릴 것이요 내 뜰을 지킬 것이며 내가 또 너로 여기 섰는 자들 가운데에 왕래하게 하리라\n슥3:8 대제사장 여호수아야 너와 네 앞에 앉은 네 동료들은 내 말을 들을 것이니라 이들은 예표의 사람들이라 내가 내 종 싹을 나게 하리라\n슥3:9 만군의 여호와가 말하노라 내가 너 여호수아 앞에 세운 돌을 보라 한 돌에 일곱 눈이 있느니라 내가 거기에 새길 것을 새기며 이 땅의 죄악을 하루에 제거하리라\n슥3:10 만군의 여호와가 말하노라 그 날에 너희가 각각 포도나무와 무화과나무 아래로 서로 초대하리라 하셨느니라' WHERE date = '2027-08-17';
UPDATE public.qt_plans SET text = E'슥4:1  내게 말하던 천사가 다시 와서 나를 깨우니 마치 자는 사람이 잠에서 깨어난 것 같더라\n슥4:2 그가 내게 묻되 네가 무엇을 보느냐 내가 대답하되 내가 보니 순금 등잔대가 있는데 그 위에는 기름 그릇이 있고 또 그 기름 그릇 위에 일곱 등잔이 있으며 그 기름 그릇 위에 있는 등잔을 위해서 일곱 관이 있고\n슥4:3 그 등잔대 곁에 두 감람나무가 있는데 하나는 그 기름 그릇 오른쪽에 있고 하나는 그 왼쪽에 있나이다 하고\n슥4:4 내게 말하는 천사에게 물어 이르되 내 주여 이것들이 무엇이니이까 하니\n슥4:5 내게 말하는 천사가 대답하여 이르되 네가 이것들이 무엇인지 알지 못하느냐 하므로 내가 대답하되 내 주여 내가 알지 못하나이다 하니\n슥4:6 그가 내게 대답하여 이르되 여호와께서 스룹바벨에게 하신 말씀이 이러하니라 만군의 여호와께서 말씀하시되 이는 힘으로 되지 아니하며 능력으로 되지 아니하고 오직 나의 영으로 되느니라\n슥4:7 큰 산아 네가 무엇이냐 네가 스룹바벨 앞에서 평지가 되리라 그가 머릿돌을 내놓을 때에 무리가 외치기를 은총, 은총이 그에게 있을지어다 하리라 하셨고\n슥4:8 여호와의 말씀이 또 내게 임하여 이르시되\n슥4:9 스룹바벨의 손이 이 성전의 기초를 놓았은즉 그의 손이 또한 그 일을 마치리라 하셨나니 만군의 여호와께서 나를 너희에게 보내신 줄을 네가 알리라 하셨느니라\n슥4:10 작은 일의 날이라고 멸시하는 자가 누구냐 사람들이 스룹바벨의 손에 다림줄이 있음을 보고 기뻐하리라 이 일곱은 온 세상에 두루 다니는 여호와의 눈이라 하니라\n슥4:11 내가 그에게 물어 이르되 등잔대 좌우의 두 감람나무는 무슨 뜻이니이까 하고\n슥4:12 다시 그에게 물어 이르되 금 기름을 흘리는 두 금관 옆에 있는 이 감람나무 두 가지는 무슨 뜻이니이까 하니\n슥4:13 그가 내게 대답하여 이르되 네가 이것이 무엇인지 알지 못하느냐 하는지라 내가 대답하되 내 주여 알지 못하나이다 하니\n슥4:14 이르되 이는 기름 부음 받은 자 둘이니 온 세상의 주 앞에 서 있는 자니라 하더라' WHERE date = '2027-08-18';
UPDATE public.qt_plans SET text = E'슥5:1  내가 다시 눈을 들어 본즉 날아가는 두루마리가 있더라\n슥5:2 그가 내게 묻되 네가 무엇을 보느냐 하기로 내가 대답하되 날아가는 두루마리를 보나이다 그 길이가 이십 규빗이요 너비가 십 규빗이니이다\n슥5:3 그가 내게 이르되 이는 온 땅 위에 내리는 저주라 도둑질하는 자는 그 이쪽 글대로 끊어지고 맹세하는 자는 그 저쪽 글대로 끊어지리라 하니\n슥5:4 만군의 여호와께서 이르시되 내가 이것을 보냈나니 도둑의 집에도 들어가며 내 이름을 가리켜 망령되이 맹세하는 자의 집에도 들어가서 그의 집에 머무르며 그 집을 나무와 돌과 아울러 사르리라 하셨느니라 하니라\n슥5:5  내게 말하던 천사가 나아와서 내게 이르되 너는 눈을 들어 나오는 이것이 무엇인가 보라 하기로\n슥5:6 내가 묻되 이것이 무엇이니이까 하니 그가 이르되 나오는 이것이 에바이니라 하시고 또 이르되 온 땅에서 그들의 모양이 이러하니라\n슥5:7 이 에바 가운데에는 한 여인이 앉았느니라 하니 그 때에 둥근 납 한 조각이 들리더라\n슥5:8 그가 이르되 이는 악이라 하고 그 여인을 에바 속으로 던져 넣고 납 조각을 에바 아귀 위에 던져 덮더라\n슥5:9 내가 또 눈을 들어 본즉 두 여인이 나오는데 학의 날개 같은 날개가 있고 그 날개에 바람이 있더라 그들이 그 에바를 천지 사이에 들었기로\n슥5:10 내가 내게 말하는 천사에게 묻되 그들이 에바를 어디로 옮겨 가나이까 하니\n슥5:11 그가 내게 이르되 그들이 시날 땅으로 가서 그것을 위하여 집을 지으려 함이니라 준공되면 그것이 제 처소에 머물게 되리라 하더라' WHERE date = '2027-08-19';
UPDATE public.qt_plans SET text = E'슥6:1  내가 또 눈을 들어 본즉 네 병거가 두 산 사이에서 나오는데 그 산은 구리 산이더라\n슥6:2 첫째 병거는 붉은 말들이, 둘째 병거는 검은 말들이,\n슥6:3 셋째 병거는 흰 말들이, 넷째 병거는 어룽지고 건장한 말들이 메었는지라\n슥6:4 내가 내게 말하는 천사에게 물어 이르되 내 주여 이것들이 무엇이니이까 하니\n슥6:5 천사가 대답하여 이르되 이는 하늘의 네 바람인데 온 세상의 주 앞에 서 있다가 나가는 것이라 하더라\n슥6:6 검은 말은 북쪽 땅으로 나가고 흰 말은 그 뒤를 따르고 어룽진 말은 남쪽 땅으로 나가고\n슥6:7 건장한 말은 나가서 땅에 두루 다니고자 하니 그가 이르되 너희는 여기서 나가서 땅에 두루 다니라 하매 곧 땅에 두루 다니더라\n슥6:8 그가 내게 외쳐 말하여 이르되 북쪽으로 나간 자들이 북쪽에서 내 영을 쉬게 하였느니라 하더라\n슥6:9  여호와의 말씀이 내게 임하여 이르시되\n슥6:10 사로잡힌 자 가운데 바벨론에서부터 돌아온 헬대와 도비야와 여다야가 스바냐의 아들 요시아의 집에 들어갔나니 너는 이 날에 그 집에 들어가서 그들에게서 받되\n슥6:11 은과 금을 받아 면류관을 만들어 여호사닥의 아들 대제사장 여호수아의 머리에 씌우고\n슥6:12 말하여 이르기를 만군의 여호와께서 이같이 말씀하시되 보라 싹이라 이름하는 사람이 자기 곳에서 돋아나서 여호와의 전을 건축하리라\n슥6:13 그가 여호와의 전을 건축하고 영광도 얻고 그 자리에 앉아서 다스릴 것이요 또 제사장이 자기 자리에 있으리니 이 둘 사이에 평화의 의논이 있으리라 하셨다 하고\n슥6:14 그 면류관은 헬렘과 도비야와 여다야와 스바냐의 아들 헨을 기념하기 위하여 여호와의 전 안에 두라 하시니라\n슥6:15 먼 데 사람들이 와서 여호와의 전을 건축하리니 만군의 여호와께서 나를 너희에게 보내신 줄을 너희가 알리라 너희가 만일 너희의 하나님 여호와의 말씀을 들을진대 이같이 되리라' WHERE date = '2027-08-20';
UPDATE public.qt_plans SET text = E'에1:2 당시에 아하수에로 왕이 수산 궁에서 즉위하고\n에1:3 왕위에 있은 지 제삼년에 그의 모든 지방관과 신하들을 위하여 잔치를 베푸니 바사와 메대의 장수와 각 지방의 귀족과 지방관들이 다 왕 앞에 있는지라\n에1:4 왕이 여러 날 곧 백팔십 일 동안에 그의 영화로운 나라의 부함과 위엄의 혁혁함을 나타내니라\n에1:5 이 날이 지나매 왕이 또 도성 수산에 있는 귀천간의 백성을 위하여 왕궁 후원 뜰에서 칠 일 동안 잔치를 베풀새\n에1:6 백색, 녹색, 청색 휘장을 자색 가는 베 줄로 대리석 기둥 은고리에 매고 금과 은으로 만든 걸상을 화반석, 백석, 운모석, 흑석을 깐 땅에 진설하고\n에1:7 금 잔으로 마시게 하니 잔의 모양이 각기 다르고 왕이 풍부하였으므로 어주가 한이 없으며\n에1:8 마시는 것도 법도가 있어 사람으로 억지로 하지 않게 하니 이는 왕이 모든 궁내 관리에게 명령하여 각 사람이 마음대로 하게 함이더라\n에1:9 왕후 와스디도 아하수에로 왕궁에서 여인들을 위하여 잔치를 베푸니라\n에1:10 제칠일에 왕이 주흥이 일어나서 어전 내시 므후만과 비스다와 하르보나와 빅다와 아박다와 세달과 가르가스 일곱 사람을 명령하여\n에1:11 왕후 와스디를 청하여 왕후의 관을 정제하고 왕 앞으로 나아오게 하여 그의 아리따움을 뭇 백성과 지방관들에게 보이게 하라 하니 이는 왕후의 용모가 보기에 좋음이라\n에1:12 그러나 왕후 와스디는 내시가 전하는 왕명을 따르기를 싫어하니 왕이 진노하여 마음속이 불 붙는 듯하더라\n에1:13 왕이 사례를 아는 현자들에게 묻되 (왕이 규례와 법률을 아는 자에게 묻는 전례가 있는데\n에1:14 그 때에 왕에게 가까이 하여 왕의 기색을 살피며 나라 첫 자리에 앉은 자는 바사와 메대의 일곱 지방관 곧 가르스나와 세달과 아드마다와 다시스와 메레스와 마르스나와 므무간이라)\n에1:15 왕후 와스디가 내시가 전하는 아하수에로 왕의 명령을 따르지 아니하니 규례대로 하면 어떻게 처치할까\n에1:16 므무간이 왕과 지방관 앞에서 대답하여 이르되 왕후 와스디가 왕에게만 잘못했을 뿐 아니라 아하수에로 왕의 각 지방의 관리들과 뭇 백성에게도 잘못하였나이다\n에1:17 아하수에로 왕이 명령하여 왕후 와스디를 청하여도 오지 아니하였다 하는 왕후의 행위의 소문이 모든 여인들에게 전파되면 그들도 그들의 남편을 멸시할 것인즉\n에1:18 오늘이라도 바사와 메대의 귀부인들이 왕후의 행위를 듣고 왕의 모든 지방관들에게 그렇게 말하리니 멸시와 분노가 많이 일어나리이다\n에1:19 왕이 만일 좋게 여기실진대 와스디가 다시는 왕 앞에 오지 못하게 하는 조서를 내리되 바사와 메대의 법률에 기록하여 변개함이 없게 하고 그 왕후의 자리를 그보다 나은 사람에게 주소서\n에1:20 왕의 조서가 이 광대한 전국에 반포되면 귀천을 막론하고 모든 여인들이 그들의 남편을 존경하리이다 하니라\n에1:21 왕과 지방관들이 그 말을 옳게 여긴지라 왕이 므무간의 말대로 행하여\n에1:22 각 지방 각 백성의 문자와 언어로 모든 지방에 조서를 내려 이르기를 남편이 자기의 집을 주관하게 하고 자기 민족의 언어로 말하게 하라 하였더라' WHERE date = '2027-08-21';
UPDATE public.qt_plans SET text = E'에2:1  그 후에 아하수에로 왕의 노가 그치매 와스디와 그가 행한 일과 그에 대하여 내린 조서를 생각하거늘\n에2:2 왕의 측근 신하들이 아뢰되 왕은 왕을 위하여 아리따운 처녀들을 구하게 하시되\n에2:3 전국 각 지방에 관리를 명령하여 아리따운 처녀를 다 도성 수산으로 모아 후궁으로 들여 궁녀를 주관하는 내시 헤개의 손에 맡겨 그 몸을 정결하게 하는 물품을 주게 하시고\n에2:4 왕의 눈에 아름다운 처녀를 와스디 대신 왕후로 삼으소서 하니 왕이 그 말을 좋게 여겨 그대로 행하니라\n에2:5 도성 수산에 한 유다인이 있으니 이름은 모르드개라 그는 베냐민 자손이니 기스의 증손이요 시므이의 손자요 야일의 아들이라\n에2:6 전에 바벨론 왕 느부갓네살이 예루살렘에서 유다 왕 여고냐와 백성을 사로잡아 갈 때에 모르드개도 함께 사로잡혔더라\n에2:7 그의 삼촌의 딸 하닷사 곧 에스더는 부모가 없었으나 용모가 곱고 아리따운 처녀라 그의 부모가 죽은 후에 모르드개가 자기 딸 같이 양육하더라\n에2:8 왕의 조서와 명령이 반포되매 처녀들이 도성 수산에 많이 모여 헤개의 수하에 나아갈 때에 에스더도 왕궁으로 이끌려 가서 궁녀를 주관하는 헤개의 수하에 속하니\n에2:9 헤개가 이 처녀를 좋게 보고 은혜를 베풀어 몸을 정결하게 할 물품과 일용품을 곧 주며 또 왕궁에서 으레 주는 일곱 궁녀를 주고 에스더와 그 궁녀들을 후궁 아름다운 처소로 옮기더라\n에2:10 에스더가 자기의 민족과 종족을 말하지 아니하니 이는 모르드개가 명령하여 말하지 말라 하였음이라\n에2:11 모르드개가 날마다 후궁 뜰 앞으로 왕래하며 에스더의 안부와 어떻게 될지를 알고자 하였더라\n에2:12 처녀마다 차례대로 아하수에로 왕에게 나아가기 전에 여자에 대하여 정한 규례대로 열두 달 동안을 행하되 여섯 달은 몰약 기름을 쓰고 여섯 달은 향품과 여자에게 쓰는 다른 물품을 써서 몸을 정결하게 하는 기한을 마치며\n에2:13 처녀가 왕에게 나아갈 때에는 그가 구하는 것을 다 주어 후궁에서 왕궁으로 가지고 가게 하고\n에2:14 저녁이면 갔다가 아침에는 둘째 후궁으로 돌아와서 비빈을 주관하는 내시 사아스가스의 수하에 속하고 왕이 그를 기뻐하여 그의 이름을 부르지 아니하면 다시 왕에게 나아가지 못하더라\n에2:15 모르드개의 삼촌 아비하일의 딸 곧 모르드개가 자기의 딸 같이 양육하는 에스더가 차례대로 왕에게 나아갈 때에 궁녀를 주관하는 내시 헤개가 정한 것 외에는 다른 것을 구하지 아니하였으나 모든 보는 자에게 사랑을 받더라\n에2:16 아하수에로 왕의 제칠년 시월 곧 데벳월에 에스더가 왕궁에 인도되어 들어가서 왕 앞에 나가니\n에2:17 왕이 모든 여자보다 에스더를 더 사랑하므로 그가 모든 처녀보다 왕 앞에 더 은총을 얻은지라 왕이 그의 머리에 관을 씌우고 와스디를 대신하여 왕후로 삼은 후에\n에2:18 왕이 크게 잔치를 베푸니 이는 에스더를 위한 잔치라 모든 지방관과 신하들을 위하여 잔치를 베풀고 또 각 지방의 세금을 면제하고 왕의 이름으로 큰 상을 주니라\n에2:19  처녀들을 다시 모을 때에는 모르드개가 대궐 문에 앉았더라\n에2:20 에스더는 모르드개가 명령한 대로 그 종족과 민족을 말하지 아니하니 그가 모르드개의 명령을 양육 받을 때와 같이 따름이더라\n에2:21 모르드개가 대궐 문에 앉았을 때에 문을 지키던 왕의 내시 빅단과 데레스 두 사람이 원한을 품고 아하수에로 왕을 암살하려는 음모를 꾸미는 것을\n에2:22 모르드개가 알고 왕후 에스더에게 알리니 에스더가 모르드개의 이름으로 왕에게 아뢴지라\n에2:23 조사하여 실증을 얻었으므로 두 사람을 나무에 달고 그 일을 왕 앞에서 궁중 일기에 기록하니라' WHERE date = '2027-08-23';
UPDATE public.qt_plans SET text = E'에3:1  그 후에 아하수에로 왕이 아각 사람 함므다다의 아들 하만의 지위를 높이 올려 함께 있는 모든 대신 위에 두니\n에3:2 대궐 문에 있는 왕의 모든 신하들이 다 왕의 명령대로 하만에게 꿇어 절하되 모르드개는 꿇지도 아니하고 절하지도 아니하니\n에3:3 대궐 문에 있는 왕의 신하들이 모르드개에게 이르되 너는 어찌하여 왕의 명령을 거역하느냐 하고\n에3:4 날마다 권하되 모르드개가 듣지 아니하고 자기는 유다인임을 알렸더니 그들이 모르드개의 일이 어찌 되나 보고자 하여 하만에게 전하였더라\n에3:5 하만이 모르드개가 무릎을 꿇지도 아니하고 절하지도 아니함을 보고 매우 노하더니\n에3:6 그들이 모르드개의 민족을 하만에게 알리므로 하만이 모르드개만 죽이는 것이 부족하다고 생각하고 아하수에로의 온 나라에 있는 유다인 곧 모르드개의 민족을 다 멸하고자 하더라\n에3:7 아하수에로 왕 제십이년 첫째 달 곧 니산월에 무리가 하만 앞에서 날과 달에 대하여 부르 곧 제비를 뽑아 열두째 달 곧 아달월을 얻은지라\n에3:8 하만이 아하수에로 왕에게 아뢰되 한 민족이 왕의 나라 각 지방 백성 중에 흩어져 거하는데 그 법률이 만민의 것과 달라서 왕의 법률을 지키지 아니하오니 용납하는 것이 왕에게 무익하니이다\n에3:9 왕이 옳게 여기시거든 조서를 내려 그들을 진멸하소서 내가 은 일만 달란트를 왕의 일을 맡은 자의 손에 맡겨 왕의 금고에 드리리이다 하니\n에3:10 왕이 반지를 손에서 빼어 유다인의 대적 곧 아각 사람 함므다다의 아들 하만에게 주며\n에3:11 이르되 그 은을 네게 주고 그 백성도 그리하노니 너의 소견에 좋을 대로 행하라 하더라\n에3:12 첫째 달 십삼일에 왕의 서기관이 소집되어 하만의 명령을 따라 왕의 대신과 각 지방의 관리와 각 민족의 관원에게 아하수에로 왕의 이름으로 조서를 쓰되 곧 각 지방의 문자와 각 민족의 언어로 쓰고 왕의 반지로 인치니라\n에3:13 이에 그 조서를 역졸에게 맡겨 왕의 각 지방에 보내니 열두째 달 곧 아달월 십삼일 하루 동안에 모든 유다인을 젊은이 늙은이 어린이 여인들을 막론하고 죽이고 도륙하고 진멸하고 또 그 재산을 탈취하라 하였고\n에3:14 이 명령을 각 지방에 전하기 위하여 조서의 초본을 모든 민족에게 선포하여 그 날을 위하여 준비하게 하라 하였더라\n에3:15 역졸이 왕의 명령을 받들어 급히 나가매 그 조서가 도성 수산에도 반포되니 왕은 하만과 함께 앉아 마시되 수산 성은 어지럽더라' WHERE date = '2027-08-24';
UPDATE public.qt_plans SET text = E'에4:1  모르드개가 이 모든 일을 알고 자기의 옷을 찢고 굵은 베 옷을 입고 재를 뒤집어쓰고 성중에 나가서 대성 통곡하며\n에4:2 대궐 문 앞까지 이르렀으니 굵은 베 옷을 입은 자는 대궐 문에 들어가지 못함이라\n에4:3 왕의 명령과 조서가 각 지방에 이르매 유다인이 크게 애통하여 금식하며 울며 부르짖고 굵은 베 옷을 입고 재에 누운 자가 무수하더라\n에4:4 에스더의 시녀와 내시가 나아와 전하니 왕후가 매우 근심하여 입을 의복을 모르드개에게 보내어 그 굵은 베 옷을 벗기고자 하나 모르드개가 받지 아니하는지라\n에4:5 에스더가 왕의 어명으로 자기에게 가까이 있는 내시 하닥을 불러 명령하여 모르드개에게 가서 이것이 무슨 일이며 무엇 때문인가 알아보라 하매\n에4:6 하닥이 대궐 문 앞 성 중 광장에 있는 모르드개에게 이르니\n에4:7 모르드개가 자기가 당한 모든 일과 하만이 유다인을 멸하려고 왕의 금고에 바치기로 한 은의 정확한 액수를 하닥에게 말하고\n에4:8 또 유다인을 진멸하라고 수산 궁에서 내린 조서 초본을 하닥에게 주어 에스더에게 보여 알게 하고 또 그에게 부탁하여 왕에게 나아가서 그 앞에서 자기 민족을 위하여 간절히 구하라 하니\n에4:9 하닥이 돌아와 모르드개의 말을 에스더에게 알리매\n에4:10 에스더가 하닥에게 이르되 너는 모르드개에게 전하기를\n에4:11 왕의 신하들과 왕의 각 지방 백성이 다 알거니와 남녀를 막론하고 부름을 받지 아니하고 안뜰에 들어가서 왕에게 나가면 오직 죽이는 법이요 왕이 그 자에게 금 규를 내밀어야 살 것이라 이제 내가 부름을 입어 왕에게 나가지 못한 지가 이미 삼십 일이라 하라 하니라\n에4:12 그가 에스더의 말을 모르드개에게 전하매\n에4:13 모르드개가 그를 시켜 에스더에게 회답하되 너는 왕궁에 있으니 모든 유다인 중에 홀로 목숨을 건지리라 생각하지 말라\n에4:14 이 때에 네가 만일 잠잠하여 말이 없으면 유다인은 다른 데로 말미암아 놓임과 구원을 얻으려니와 너와 네 아버지 집은 멸망하리라 네가 왕후의 자리를 얻은 것이 이 때를 위함이 아닌지 누가 알겠느냐 하니\n에4:15 에스더가 모르드개에게 회답하여 이르되\n에4:16 당신은 가서 수산에 있는 유다인을 다 모으고 나를 위하여 금식하되 밤낮 삼 일을 먹지도 말고 마시지도 마소서 나도 나의 시녀와 더불어 이렇게 금식한 후에 규례를 어기고 왕에게 나아가리니 죽으면 죽으리이다 하니라\n에4:17 모르드개가 가서 에스더가 명령한 대로 다 행하니라' WHERE date = '2027-08-25';
UPDATE public.qt_plans SET text = E'에5:1  제삼일에 에스더가 왕후의 예복을 입고 왕궁 안 뜰 곧 어전 맞은편에 서니 왕이 어전에서 전 문을 대하여 왕좌에 앉았다가\n에5:2 왕후 에스더가 뜰에 선 것을 본즉 매우 사랑스러우므로 손에 잡았던 금 규를 그에게 내미니 에스더가 가까이 가서 금 규 끝을 만진지라\n에5:3 왕이 이르되 왕후 에스더여 그대의 소원이 무엇이며 요구가 무엇이냐 나라의 절반이라도 그대에게 주겠노라 하니\n에5:4 에스더가 이르되 오늘 내가 왕을 위하여 잔치를 베풀었사오니 왕이 좋게 여기시거든 하만과 함께 오소서 하니\n에5:5 왕이 이르되 에스더가 말한 대로 하도록 하만을 급히 부르라 하고 이에 왕이 하만과 함께 에스더가 베푼 잔치에 가니라\n에5:6 잔치의 술을 마실 때에 왕이 에스더에게 이르되 그대의 소청이 무엇이뇨 곧 허락하겠노라 그대의 요구가 무엇이뇨 나라의 절반이라 할지라도 시행하겠노라 하니\n에5:7 에스더가 대답하여 이르되 나의 소청, 나의 요구가 이러하니이다\n에5:8 내가 만일 왕의 목전에서 은혜를 입었고 왕이 내 소청을 허락하시며 내 요구를 시행하시기를 좋게 여기시면 내가 왕과 하만을 위하여 베푸는 잔치에 또 오소서 내일은 왕의 말씀대로 하리이다 하니라\n에5:9  그 날 하만이 마음이 기뻐 즐거이 나오더니 모르드개가 대궐 문에 있어 일어나지도 아니하고 몸을 움직이지도 아니하는 것을 보고 매우 노하나\n에5:10 참고 집에 돌아와서 사람을 보내어 그의 친구들과 그의 아내 세레스를 청하여\n에5:11 자기의 큰 영광과 자녀가 많은 것과 왕이 자기를 들어 왕의 모든 지방관이나 신하들보다 높인 것을 다 말하고\n에5:12 또 하만이 이르되 왕후 에스더가 그 베푼 잔치에 왕과 함께 오기를 허락 받은 자는 나밖에 없었고 내일도 왕과 함께 청함을 받았느니라\n에5:13 그러나 유다 사람 모르드개가 대궐 문에 앉은 것을 보는 동안에는 이 모든 일이 만족하지 아니하도다 하니\n에5:14 그의 아내 세레스와 모든 친구들이 이르되 높이가 오십 규빗 되는 나무를 세우고 내일 왕에게 모르드개를 그 나무에 매달기를 구하고 왕과 함께 즐거이 잔치에 가소서 하니 하만이 그 말을 좋게 여기고 명령하여 나무를 세우니라' WHERE date = '2027-08-26';
UPDATE public.qt_plans SET text = E'스7:1  이 일 후에 바사 왕 아닥사스다가 왕위에 있을 때에 에스라라 하는 자가 있으니라 그는 스라야의 아들이요 아사랴의 손자요 힐기야의 증손이요\n스7:2 살룸의 현손이요 사독의 오대 손이요 아히둡의 육대 손이요\n스7:3 아마랴의 칠대 손이요 아사랴의 팔대 손이요 므라욧의 구대 손이요\n스7:4 스라히야의 십대 손이요 웃시엘의 십일대 손이요 북기의 십이대 손이요\n스7:5 아비수아의 십삼대 손이요 비느하스의 십사대 손이요 엘르아살의 십오대 손이요 대제사장 아론의 십육대 손이라\n스7:6 이 에스라가 바벨론에서 올라왔으니 그는 이스라엘의 하나님 여호와께서 주신 모세의 율법에 익숙한 학자로서 그의 하나님 여호와의 도우심을 입음으로 왕에게 구하는 것은 다 받는 자이더니\n스7:7 아닥사스다 왕 제칠년에 이스라엘 자손과 제사장들과 레위 사람들과 노래하는 자들과 문지기들과 느디님 사람들 중에 몇 사람이 예루살렘으로 올라올 때에\n스7:8 이 에스라가 올라왔으니 왕의 제칠년 다섯째 달이라\n스7:9 첫째 달 초하루에 바벨론에서 길을 떠났고 하나님의 선한 손의 도우심을 입어 다섯째 달 초하루에 예루살렘에 이르니라\n스7:10 에스라가 여호와의 율법을 연구하여 준행하며 율례와 규례를 이스라엘에게 가르치기로 결심하였었더라\n스7:11  여호와의 계명의 말씀과 이스라엘에게 주신 율례 학자요 학자 겸 제사장인 에스라에게 아닥사스다 왕이 내린 조서의 초본은 아래와 같으니라\n스7:12 모든 왕의 왕 아닥사스다는 하늘의 하나님의 율법에 완전한 학자 겸 제사장 에스라에게\n스7:13 조서를 내리노니 우리 나라에 있는 이스라엘 백성과 그들 제사장들과 레위 사람들 중에 예루살렘으로 올라갈 뜻이 있는 자는 누구든지 너와 함께 갈지어다\n스7:14 너는 네 손에 있는 네 하나님의 율법을 따라 유다와 예루살렘의 형편을 살피기 위하여 왕과 일곱 자문관의 보냄을 받았으니\n스7:15 왕과 자문관들이 예루살렘에 거하시는 이스라엘 하나님께 성심으로 드리는 은금을 가져가고\n스7:16 또 네가 바벨론 온 도에서 얻을 모든 은금과 및 백성과 제사장들이 예루살렘에 있는 그들의 하나님의 성전을 위하여 기쁘게 드릴 예물을 가져다가\n스7:17 그들의 돈으로 수송아지와 숫양과 어린 양과 그 소제와 그 전제의 물품을 신속히 사서 예루살렘 네 하나님의 성전 제단 위에 드리고\n스7:18 그 나머지 은금은 너와 너의 형제가 좋게 여기는 일에 너희 하나님의 뜻을 따라 쓸지며\n스7:19 네 하나님의 성전에서 섬기는 일을 위하여 네게 준 그릇은 예루살렘 하나님 앞에 드리고\n스7:20 그 외에도 네 하나님의 성전에 쓰일 것이 있어서 네가 드리고자 하거든 무엇이든지 궁중창고에서 내다가 드릴지니라\n스7:21 나 곧 아닥사스다 왕이 유브라데 강 건너편 모든 창고지기에게 조서를 내려 이르기를 하늘의 하나님의 율법 학자 겸 제사장 에스라가 무릇 너희에게 구하는 것을 신속히 시행하되\n스7:22 은은 백 달란트까지, 밀은 백 고르까지, 포도주는 백 밧까지, 기름도 백 밧까지 하고 소금은 정량 없이 하라\n스7:23 무릇 하늘의 하나님의 전을 위하여 하늘의 하나님이 명령하신 것은 삼가 행하라 어찌하여 진노가 왕과 왕자의 나라에 임하게 하랴\n스7:24 내가 너희에게 이르노니 제사장들이나 레위 사람들이나 노래하는 자들이나 문지기들이나 느디님 사람들이나 혹 하나님의 성전에서 일하는 자들에게 조공과 관세와 통행세를 받는 것이 옳지 않으니라 하였노라\n스7:25 에스라여 너는 네 손에 있는 네 하나님의 지혜를 따라 네 하나님의 율법을 아는 자를 법관과 재판관을 삼아 강 건너편 모든 백성을 재판하게 하고 그 중 알지 못하는 자는 너희가 가르치라\n스7:26 무릇 네 하나님의 명령과 왕의 명령을 준행하지 아니하는 자는 속히 그 죄를 정하여 혹 죽이거나 귀양 보내거나 가산을 몰수하거나 옥에 가둘지니라 하였더라\n스7:27  우리 조상들의 하나님 여호와를 송축할지로다 그가 왕의 마음에 예루살렘 여호와의 성전을 아름답게 할 뜻을 두시고\n스7:28 또 나로 왕과 그의 보좌관들 앞과 왕의 권세 있는 모든 방백의 앞에서 은혜를 얻게 하셨도다 내 하나님 여호와의 손이 내 위에 있으므로 내가 힘을 얻어 이스라엘 중에 우두머리들을 모아 나와 함께 올라오게 하였노라' WHERE date = '2027-08-27';
UPDATE public.qt_plans SET text = E'스8:1  아닥사스다 왕이 왕위에 있을 때에 나와 함께 바벨론에서 올라온 족장들과 그들의 계보는 이러하니라\n스8:2 비느하스 자손 중에서는 게르솜이요 이다말 자손 중에서는 다니엘이요 다윗 자손 중에서는 핫두스요\n스8:3 스가냐 자손 곧 바로스 자손 중에서는 스가랴니 그와 함께 족보에 기록된 남자가 백오십 명이요\n스8:4 바핫모압 자손 중에서는 스라히야의 아들 엘여호에내니 그와 함께 있는 남자가 이백 명이요\n스8:5 스가냐 자손 중에서는 야하시엘의 아들이니 그와 함께 있는 남자가 삼백 명이요\n스8:6 아딘 자손 중에서는 요나단의 아들 에벳이니 그와 함께 있는 남자가 오십 명이요\n스8:7 엘람 자손 중에서는 아달리야의 아들 여사야니 그와 함께 있는 남자가 칠십 명이요\n스8:8 스바댜 자손 중에서는 미가엘의 아들 스바댜니 그와 함께 있는 남자가 팔십 명이요\n스8:9 요압 자손 중에서는 여히엘의 아들 오바댜니 그와 함께 있는 남자가 이백십팔 명이요\n스8:10 슬로밋 자손 중에서는 요시뱌의 아들이니 그와 함께 있는 남자가 백육십 명이요\n스8:11 베배 자손 중에서는 베배의 아들 스가랴니 그와 함께 있는 남자가 이십팔 명이요\n스8:12 아스갓 자손 중에서는 학가단의 아들 요하난이니 그와 함께 있는 남자가 백십 명이요\n스8:13 아도니감 자손 중에 나중된 자의 이름은 엘리벨렛과 여우엘과 스마야니 그와 함께 있는 남자가 육십 명이요\n스8:14 비그왜 자손 중에서는 우대와 사붓이니 그와 함께 있는 남자가 칠십 명이었느니라\n스8:15  내가 무리를 아하와로 흐르는 강 가에 모으고 거기서 삼 일 동안 장막에 머물며 백성과 제사장들을 살핀즉 그 중에 레위 자손이 한 사람도 없는지라\n스8:16 이에 모든 족장 곧 엘리에셀과 아리엘과 스마야와 엘라단과 야립과 엘라단과 나단과 스가랴와 므술람을 부르고 또 명철한 사람 요야립과 엘라단을 불러\n스8:17 가시뱌 지방으로 보내어 그 곳 족장 잇도에게 나아가게 하고 잇도와 그의 형제 곧 가시뱌 지방에 사는 느디님 사람들에게 할 말을 일러 주고 우리 하나님의 성전을 위하여 섬길 자를 데리고 오라 하였더니\n스8:18 우리 하나님의 선한 손의 도우심을 입고 그들이 이스라엘의 손자 레위의 아들 말리의 자손 중에서 한 명철한 사람을 데려오고 또 세레뱌와 그의 아들들과 형제 십팔 명과\n스8:19 하사뱌와 므라리 자손 중 여사야와 그의 형제와 그의 아들들 이십 명을 데려오고\n스8:20 다윗과 방백들이 레위 사람들을 섬기라고 준 느디님 사람 중 성전 일꾼은 이백이십 명이었는데 그들은 모두 지명 받은 이들이었더라\n스8:21  그 때에 내가 아하와 강 가에서 금식을 선포하고 우리 하나님 앞에서 스스로 겸비하여 우리와 우리 어린 아이와 모든 소유를 위하여 평탄한 길을 그에게 간구하였으니\n스8:22 이는 우리가 전에 왕에게 아뢰기를 우리 하나님의 손은 자기를 찾는 모든 자에게 선을 베푸시고 자기를 배반하는 모든 자에게는 권능과 진노를 내리신다 하였으므로 길에서 적군을 막고 우리를 도울 보병과 마병을 왕에게 구하기를 부끄러워 하였음이라\n스8:23 그러므로 우리가 이를 위하여 금식하며 우리 하나님께 간구하였더니 그의 응낙하심을 입었느니라\n스8:24  그 때에 내가 제사장의 우두머리들 중 열두 명 곧 세레뱌와 하사뱌와 그의 형제 열 명을 따로 세우고\n스8:25 그들에게 왕과 모사들과 방백들과 또 그 곳에 있는 이스라엘 무리가 우리 하나님의 성전을 위하여 드린 은과 금과 그릇들을 달아서 주었으니\n스8:26 내가 달아서 그들 손에 준 것은 은이 육백오십 달란트요 은 그릇이 백 달란트요 금이 백 달란트며\n스8:27 또 금잔이 스무 개라 그 무게는 천 다릭이요 또 아름답고 빛나 금 같이 보배로운 놋 그릇이 두 개라\n스8:28 내가 그들에게 이르되 너희는 여호와께 거룩한 자요 이 그릇들도 거룩하고 그 은과 금은 너희 조상들의 하나님 여호와께 즐거이 드린 예물이니\n스8:29 너희는 예루살렘 여호와의 성전 골방에 이르러 제사장들과 레위 사람의 우두머리들과 이스라엘의 족장들 앞에서 이 그릇을 달기까지 삼가 지키라\n스8:30 이에 제사장들과 레위 사람들이 은과 금과 그릇을 예루살렘 우리 하나님의 성전으로 가져가려 하여 그 무게대로 받으니라\n스8:31  첫째 달 십이 일에 우리가 아하와 강을 떠나 예루살렘으로 갈새 우리 하나님의 손이 우리를 도우사 대적과 길에 매복한 자의 손에서 건지신지라\n스8:32 이에 예루살렘에 이르러 거기서 삼 일 간 머물고\n스8:33 제사일에 우리 하나님의 성전에서 은과 금과 그릇을 달아서 제사장 우리아의 아들 므레못의 손에 넘기니 비느하스의 아들 엘르아살과 레위 사람 예수아의 아들 요사밧과 빈누이의 아들 노아댜가 함께 있어\n스8:34 모든 것을 다 세고 달아 보고 그 무게의 총량을 그 때에 기록하였느니라\n스8:35 사로잡혔던 자의 자손 곧 이방에서 돌아온 자들이 이스라엘의 하나님께 번제를 드렸는데 이스라엘 전체를 위한 수송아지가 열두 마리요 또 숫양이 아흔여섯 마리요 어린 양이 일흔일곱 마리요 또 속죄제의 숫염소가 열두 마리니 모두 여호와께 드린 번제물이라\n스8:36 무리가 또 왕의 조서를 왕의 총독들과 유브라데 강 건너편 총독들에게 넘겨 주매 그들이 백성과 하나님의 성전을 도왔느니라' WHERE date = '2027-08-28';
UPDATE public.qt_plans SET text = E'느1:아닥사스다 왕 제이십년 기슬르월에 내가 수산 궁에 있는데\n느1:2 내 형제들 가운데 하나인 하나니가 두어 사람과 함께 유다에서 내게 이르렀기로 내가 그 사로잡힘을 면하고 남아 있는 유다와 예루살렘 사람들의 형편을 물은즉\n느1:3 그들이 내게 이르되 사로잡힘을 면하고 남아 있는 자들이 그 지방 거기에서 큰 환난을 당하고 능욕을 받으며 예루살렘 성은 허물어지고 성문들은 불탔다 하는지라\n느1:4 내가 이 말을 듣고 앉아서 울고 수일 동안 슬퍼하며 하늘의 하나님 앞에 금식하며 기도하여\n느1:5 이르되 하늘의 하나님 여호와 크고 두려우신 하나님이여 주를 사랑하고 주의 계명을 지키는 자에게 언약을 지키시며 긍휼을 베푸시는 주여 간구하나이다\n느1:6 이제 종이 주의 종들인 이스라엘 자손을 위하여 주야로 기도하오며 우리 이스라엘 자손이 주께 범죄한 죄들을 자복하오니 주는 귀를 기울이시며 눈을 여시사 종의 기도를 들으시옵소서 나와 내 아버지의 집이 범죄하여\n느1:7 주를 향하여 크게 악을 행하여 주께서 주의 종 모세에게 명령하신 계명과 율례와 규례를 지키지 아니하였나이다\n느1:8 옛적에 주께서 주의 종 모세에게 명령하여 이르시되 만일 너희가 범죄하면 내가 너희를 여러 나라 가운데에 흩을 것이요\n느1:9 만일 내게로 돌아와 내 계명을 지켜 행하면 너희 쫓긴 자가 하늘 끝에 있을지라도 내가 거기서부터 그들을 모아 내 이름을 두려고 택한 곳에 돌아오게 하리라 하신 말씀을 이제 청하건대 기억하옵소서\n느1:10 이들은 주께서 일찍이 큰 권능과 강한 손으로 구속하신 주의 종들이요 주의 백성이니이다\n느1:11 주여 구하오니 귀를 기울이사 종의 기도와 주의 이름을 경외하기를 기뻐하는 종들의 기도를 들으시고 오늘 종이 형통하여 이 사람들 앞에서 은혜를 입게 하옵소서 하였나니 그 때에 내가 왕의 술 관원이 되었느니라' WHERE date = '2027-08-31';
UPDATE public.qt_plans SET text = E'느2:1  아닥사스다 왕 제이십년 니산월에 왕 앞에 포도주가 있기로 내가 그 포도주를 왕에게 드렸는데 이전에는 내가 왕 앞에서 수심이 없었더니\n느2:2 왕이 내게 이르시되 네가 병이 없거늘 어찌하여 얼굴에 수심이 있느냐 이는 필연 네 마음에 근심이 있음이로다 하더라 그 때에 내가 크게 두려워하여\n느2:3 왕께 대답하되 왕은 만세수를 하옵소서 내 조상들의 묘실이 있는 성읍이 이제까지 황폐하고 성문이 불탔사오니 내가 어찌 얼굴에 수심이 없사오리이까 하니\n느2:4 왕이 내게 이르시되 그러면 네가 무엇을 원하느냐 하시기로 내가 곧 하늘의 하나님께 묵도하고\n느2:5 왕에게 아뢰되 왕이 만일 좋게 여기시고 종이 왕의 목전에서 은혜를 얻었사오면 나를 유다 땅 나의 조상들의 묘실이 있는 성읍에 보내어 그 성을 건축하게 하옵소서 하였는데\n느2:6 그 때에 왕후도 왕 곁에 앉아 있었더라 왕이 내게 이르시되 네가 몇 날에 다녀올 길이며 어느 때에 돌아오겠느냐 하고 왕이 나를 보내기를 좋게 여기시기로 내가 기한을 정하고\n느2:7 내가 또 왕에게 아뢰되 왕이 만일 좋게 여기시거든 강 서쪽 총독들에게 내리시는 조서를 내게 주사 그들에게 나를 용납하여 유다에 들어가기까지 통과하게 하시고\n느2:8 또 왕의 삼림 감독 아삽에게 조서를 내리사 그가 성전에 속한 영문의 문과 성곽과 내가 들어갈 집을 위하여 들보로 쓸 재목을 내게 주게 하옵소서 하매 내 하나님의 선한 손이 나를 도우시므로 왕이 허락하고\n느2:9 군대 장관과 마병을 보내어 나와 함께 하게 하시기로 내가 강 서쪽에 있는 총독들에게 이르러 왕의 조서를 전하였더니\n느2:10 호론 사람 산발랏과 종이었던 암몬 사람 도비야가 이스라엘 자손을 흥왕하게 하려는 사람이 왔다 함을 듣고 심히 근심하더라\n느2:11 내가 예루살렘에 이르러 머무른 지 사흘 만에\n느2:12 내 하나님께서 예루살렘을 위해 무엇을 할 것인지 내 마음에 주신 것을 내가 아무에게도 말하지 아니하고 밤에 일어나 몇몇 사람과 함께 나갈새 내가 탄 짐승 외에는 다른 짐승이 없더라\n느2:13 그 밤에 골짜기 문으로 나가서 용정으로 분문에 이르는 동안에 보니 예루살렘 성벽이 다 무너졌고 성문은 불탔더라\n느2:14 앞으로 나아가 샘문과 왕의 못에 이르러서는 탄 짐승이 지나갈 곳이 없는지라\n느2:15 그 밤에 시내를 따라 올라가서 성벽을 살펴본 후에 돌아서 골짜기 문으로 들어와 돌아왔으나\n느2:16 방백들은 내가 어디 갔었으며 무엇을 하였는지 알지 못하였고 나도 그 일을 유다 사람들에게나 제사장들에게나 귀족들에게나 방백들에게나 그 외에 일하는 자들에게 알리지 아니하다가\n느2:17 후에 그들에게 이르기를 우리가 당한 곤경은 너희도 보고 있는 바라 예루살렘이 황폐하고 성문이 불탔으니 자, 예루살렘 성을 건축하여 다시 수치를 당하지 말자 하고\n느2:18 또 그들에게 하나님의 선한 손이 나를 도우신 일과 왕이 내게 이른 말씀을 전하였더니 그들의 말이 일어나 건축하자 하고 모두 힘을 내어 이 선한 일을 하려 하매\n느2:19 호론 사람 산발랏과 종이었던 암몬 사람 도비야와 아라비아 사람 게셈이 이 말을 듣고 우리를 업신여기고 우리를 비웃어 이르되 너희가 하는 일이 무엇이냐 너희가 왕을 배반하고자 하느냐 하기로\n느2:20 내가 그들에게 대답하여 이르되 하늘의 하나님이 우리를 형통하게 하시리니 그의 종들인 우리가 일어나 건축하려니와 오직 너희에게는 예루살렘에서 아무 기업도 없고 권리도 없고 기억되는 바도 없다 하였느니라' WHERE date = '2027-09-01';
UPDATE public.qt_plans SET text = E'느3:1  그 때에 대제사장 엘리아십이 그의 형제 제사장들과 함께 일어나 양문을 건축하여 성별하고 문짝을 달고 또 성벽을 건축하여 함메아 망대에서부터 하나넬 망대까지 성별하였고\n느3:2 그 다음은 여리고 사람들이 건축하였고 또 그 다음은 이므리의 아들 삭굴이 건축하였으며\n느3:3 어문은 하스나아의 자손들이 건축하여 그 들보를 얹고 문짝을 달고 자물쇠와 빗장을 갖추었고\n느3:4 그 다음은 학고스의 손자 우리아의 아들 므레못이 중수하였고 그 다음은 므세사벨의 손자 베레갸의 아들 므술람이 중수하였고 그 다음은 바아나의 아들 사독이 중수하였고\n느3:5 그 다음은 드고아 사람들이 중수하였으나 그 귀족들은 그들의 주인들의 공사를 분담하지 아니하였으며\n느3:6 옛 문은 바세아의 아들 요야다와 브소드야의 아들 므술람이 중수하여 그 들보를 얹고 문짝을 달고 자물쇠와 빗장을 갖추었고\n느3:7 그 다음은 기브온 사람 믈라댜와 메로놋 사람 야돈이 강 서쪽 총독의 관할에 속한 기브온 사람들 및 미스바 사람들과 더불어 중수하였고\n느3:8 그 다음은 금장색 할해야의 아들 웃시엘 등이 중수하였고 그 다음은 향품 장사 하나냐 등이 중수하되 그들이 예루살렘의 넓은 성벽까지 하였고\n느3:9 그 다음은 예루살렘 지방의 절반을 다스리는 후르의 아들 르바야가 중수하였고\n느3:10 그 다음은 하루맙의 아들 여다야가 자기 집과 마주 대한 곳을 중수하였고 그 다음은 하삽느야의 아들 핫두스가 중수하였고\n느3:11 하림의 아들 말기야와 바핫모압의 아들 핫숩이 한 부분과 화덕 망대를 중수하였고\n느3:12 그 다음은 예루살렘 지방 절반을 다스리는 할로헤스의 아들 살룸과 그의 딸들이 중수하였고\n느3:13 골짜기 문은 하눈과 사노아 주민이 중수하여 문을 세우며 문짝을 달고 자물쇠와 빗장을 갖추고 또 분문까지 성벽 천 규빗을 중수하였고\n느3:14 분문은 벧학게렘 지방을 다스리는 레갑의 아들 말기야가 중수하여 문을 세우며 문짝을 달고 자물쇠와 빗장을 갖추었고\n느3:15 샘문은 미스바 지방을 다스리는 골호세의 아들 살룬이 중수하여 문을 세우고 덮었으며 문짝을 달고 자물쇠와 빗장을 갖추고 또 왕의 동산 근처 셀라 못 가의 성벽을 중수하여 다윗 성에서 내려오는 층계까지 이르렀고\n느3:16 그 다음은 벧술 지방 절반을 다스리는 아스북의 아들 느헤미야가 중수하여 다윗의 묘실과 마주 대한 곳에 이르고 또 파서 만든 못을 지나 용사의 집까지 이르렀고\n느3:17 그 다음은 레위 사람 바니의 아들 르훔이 중수하였고 그 다음은 그일라 지방 절반을 다스리는 하사뱌가 그 지방을 대표하여 중수하였고\n느3:18 그 다음은 그들의 형제들 가운데 그일라 지방 절반을 다스리는 헤나닷의 아들 바왜가 중수하였고\n느3:19 그 다음은 미스바를 다스리는 예수아의 아들 에셀이 한 부분을 중수하여 성 굽이에 있는 군기고 맞은편까지 이르렀고\n느3:20 그 다음은 삽배의 아들 바룩이 한 부분을 힘써 중수하여 성 굽이에서부터 대제사장 엘리아십의 집 문에 이르렀고\n느3:21 그 다음은 학고스의 손자 우리야의 아들 므레못이 한 부분을 중수하여 엘리아십의 집 문에서부터 엘리아십의 집 모퉁이에 이르렀고\n느3:22 그 다음은 평지에 사는 제사장들이 중수하였고\n느3:23 그 다음은 베냐민과 핫숩이 자기 집 맞은편 부분을 중수하였고 그 다음은 아나냐의 손자 마아세야의 아들 아사랴가 자기 집에서 가까운 부분을 중수하였고\n느3:24 그 다음은 헤나닷의 아들 빈누이가 한 부분을 중수하되 아사랴의 집에서부터 성 굽이를 지나 성 모퉁이에 이르렀고\n느3:25 우새의 아들 발랄은 성 굽이 맞은편과 왕의 윗 궁에서 내민 망대 맞은편 곧 시위청에서 가까운 부분을 중수하였고 그 다음은 바로스의 아들 브다야가 중수하였고\n느3:26 (그 때에 느디님 사람은 오벨에 거주하여 동쪽 수문과 마주 대한 곳에서부터 내민 망대까지 이르렀느니라)\n느3:27 그 다음은 드고아 사람들이 한 부분을 중수하여 내민 큰 망대와 마주 대한 곳에서부터 오벨 성벽까지 이르렀느니라\n느3:28 마문 위로부터는 제사장들이 각각 자기 집과 마주 대한 부분을 중수하였고\n느3:29 그 다음은 임멜의 아들 사독이 자기 집과 마주 대한 부분을 중수하였고 그 다음은 동문지기 스가냐의 아들 스마야가 중수하였고\n느3:30 그 다음은 셀레먀의 아들 하나냐와 살랍의 여섯째 아들 하눈이 한 부분을 중수하였고 그 다음은 베레갸의 아들 므술람이 자기의 방과 마주 대한 부분을 중수하였고\n느3:31 그 다음은 금장색 말기야가 함밉갓 문과 마주 대한 부분을 중수하여 느디님 사람과 상인들의 집에서부터 성 모퉁이 성루에 이르렀고\n느3:32 성 모퉁이 성루에서 양문까지는 금장색과 상인들이 중수하였느니라' WHERE date = '2027-09-02';
UPDATE public.qt_plans SET text = E'느8:1 이스라엘 자손이 자기들의 성읍에 거주하였더니 일곱째 달에 이르러 모든 백성이 일제히 수문 앞 광장에 모여 학사 에스라에게 여호와께서 이스라엘에게 명령하신 모세의 율법책을 가져오기를 청하매\n느8:2 일곱째 달 초하루에 제사장 에스라가 율법책을 가지고 회중 앞 곧 남자나 여자나 알아들을 만한 모든 사람 앞에 이르러\n느8:3 수문 앞 광장에서 새벽부터 정오까지 남자나 여자나 알아들을 만한 모든 사람 앞에서 읽으매 뭇 백성이 그 율법책에 귀를 기울였는데\n느8:4 그 때에 학사 에스라가 특별히 지은 나무 강단에 서고 그의 곁 오른쪽에 선 자는 맛디댜와 스마와 아나야와 우리야와 힐기야와 마아세야요 그의 왼쪽에 선 자는 브다야와 미사엘과 말기야와 하숨과 하스밧다나와 스가랴와 므술람이라\n느8:5 에스라가 모든 백성 위에 서서 그들 목전에 책을 펴니 책을 펼 때에 모든 백성이 일어서니라\n느8:6 에스라가 위대하신 하나님 여호와를 송축하매 모든 백성이 손을 들고 아멘 아멘 하고 응답하고 몸을 굽혀 얼굴을 땅에 대고 여호와께 경배하니라\n느8:7 예수아와 바니와 세레뱌와 야민과 악굽과 사브대와 호디야와 마아세야와 그리다와 아사랴와 요사밧과 하난과 블라야와 레위 사람들은 백성이 제자리에 서 있는 동안 그들에게 율법을 깨닫게 하였는데\n느8:8 하나님의 율법책을 낭독하고 그 뜻을 해석하여 백성에게 그 낭독하는 것을 다 깨닫게 하니\n느8:9 백성이 율법의 말씀을 듣고 다 우는지라 총독 느헤미야와 제사장 겸 학사 에스라와 백성을 가르치는 레위 사람들이 모든 백성에게 이르기를 오늘은 너희 하나님 여호와의 성일이니 슬퍼하지 말며 울지 말라 하고\n느8:10 느헤미야가 또 그들에게 이르기를 너희는 가서 살진 것을 먹고 단 것을 마시되 준비하지 못한 자에게는 나누어 주라 이 날은 우리 주의 성일이니 근심하지 말라 여호와로 인하여 기뻐하는 것이 너희의 힘이니라 하고\n느8:11 레위 사람들도 모든 백성을 정숙하게 하여 이르기를 오늘은 성일이니 마땅히 조용하고 근심하지 말라 하니\n느8:12 모든 백성이 곧 가서 먹고 마시며 나누어 주고 크게 즐거워하니 이는 그들이 그 읽어 들려 준 말을 밝히 앎이라\n느8:13 그 이튿날 뭇 백성의 족장들과 제사장들과 레위 사람들이 율법의 말씀을 밝히 알고자 하여 학사 에스라에게 모여서\n느8:14 율법에 기록된 바를 본즉 여호와께서 모세를 통하여 명령하시기를 이스라엘 자손은 일곱째 달 절기에 초막에서 거할지니라 하였고\n느8:15 또 일렀으되 모든 성읍과 예루살렘에 공포하여 이르기를 너희는 산에 가서 감람나무 가지와 들감람나무 가지와 화석류나무 가지와 종려나무 가지와 기타 무성한 나무 가지를 가져다가 기록한 바를 따라 초막을 지으라 하라 한지라\n느8:16 백성이 이에 나가서 나뭇가지를 가져다가 혹은 지붕 위에, 혹은 뜰 안에, 혹은 하나님의 전 뜰에, 혹은 수문 광장에, 혹은 에브라임 문 광장에 초막을 짓되\n느8:17 사로잡혔다가 돌아온 회중이 다 초막을 짓고 그 안에서 거하니 눈의 아들 여호수아 때로부터 그 날까지 이스라엘 자손이 이같이 행한 일이 없었으므로 이에 크게 기뻐하며\n느8:18 에스라는 첫날부터 끝날까지 날마다 하나님의 율법책을 낭독하고 무리가 이레 동안 절기를 지키고 여덟째 날에 규례를 따라 성회를 열었느니라' WHERE date = '2027-09-03';
COMMIT;